import { PlayerData, ValidActiveBoostsTypes } from "../../../data/AllTypes/PlayerDataTypes.ts";

type StartBoostedActiveAction = {
  boostType: ValidActiveBoostsTypes;
  duration: number;
};

export function startBoostedActive(state: PlayerData, action: StartBoostedActiveAction): PlayerData {
  const { boostType, duration } = action;

  const coolDownDuration = 600 * 1000; // 10 minutes
  const boostDuration = duration * 1000;

  const activeBoosts = state.activeBoosts ?? {
    combat: { startTime: 0, endTime: 0, coolDown: 0 },
    skilling: { startTime: 0, endTime: 0, coolDown: 0 },
  };

  return {
    ...state,
    activeBoosts: {
      ...activeBoosts,
      [boostType]: {
        startTime: Date.now(),
        endTime: Date.now() + boostDuration,
        coolDown: Date.now() + boostDuration + coolDownDuration,
      },
    },
  };
}
