import { AutoCombatIds, PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";

export const updateAutoCombat = (
  state: PlayerData,
  action: { autoCombatId: AutoCombatIds; interval: number },
): PlayerData => {
  const { autoCombatId, interval } = action;

  if (!state.autoCombat || !state.autoCombat[autoCombatId]) {
    return state;
  }

  const updatedAutoCombat = {
    ...state.autoCombat,
    [autoCombatId]: {
      ...state.autoCombat[autoCombatId],
      interval,
    },
  };

  return {
    ...state,
    autoCombat: updatedAutoCombat,
  };
};
