import { PlayerData } from "../../data/AllTypes/PlayerDataTypes.ts";
import { GamePreview, StoredGameState } from "./AccountOverviewTypes.ts";
import pako from "pako";

// Helper function to validate if a string is Base64-encoded
export const isBase64 = (str: string): boolean => {
  try {
    // Try decoding the string using atob() to check if it's valid Base64
    atob(str);
    return true;
  } catch (e) {
    return false; // If decoding fails, it's not valid Base64
  }
};

export const decompressAndParseData = (compressedData: string): StoredGameState | null => {
  try {
    return decompressData(compressedData);
  } catch {
    try {
      const json = atob(compressedData);
      return JSON.parse(json);
    } catch (err) {
      console.warn("Failed to parse game data:", err);
      return null;
    }
  }
};

export const decompressData = (base64: string): any => {
  const binaryString = atob(base64);
  const bytes = Uint8Array.from(binaryString, (c) => c.charCodeAt(0));
  const decompressed = pako.inflate(bytes, { to: "string" });
  return JSON.parse(decompressed);
};

export const createDownloadLink = (compressedData: string, slotId: number) => {
  const blob = new Blob([compressedData], { type: "application/octet-stream" });
  const link = document.createElement("a");
  link.href = URL.createObjectURL(blob);
  const date = new Date().toISOString().replace(/:/g, "-");
  link.download = `rocky_idle_slot_${slotId}_date_${date}.txt`;
  link.click();
};
export const extractPreviewInfo = (parsedData: StoredGameState, slotId: number): GamePreview => {
  const state: PlayerData = parsedData?.state ?? {};

  const totalXP = state?.total?.xp ?? 0;
  const totalLevel = state?.total?.level ?? 1;
  const ingameTime = state?.inGameTime ?? 1;
  const name = state?.accountInfo?.inGameName ?? "Unknown";
  const accountType = state?.accountInfo?.accountType;
  const accountImgId = state?.accountInfo?.accountImgId;
  const lastSavedLocal = parsedData.lastSavedLocal;
  const lastSavedCloud = parsedData?.lastSavedCloud ? parsedData.lastSavedCloud : null;

  const currentProcess = state?.currentProcess ?? null;
  const collectionLogSlot = state?.collectionLogSlot ?? null;
  const currentAttackProcess = state?.currentAttackProcess ?? null;
  const accountId = state?.accountInfo?.accountId ?? null;

  return {
    slotId,
    inGameTime: ingameTime,
    totalXP,
    totalLevel,
    name,
    accountType,
    lastSavedLocal,
    lastSavedCloud,
    currentProcess,
    accountImgId,
    accountId,
    collectionLogSlot,
    currentAttackProcess,
  };
};

export type SaveMode = "local" | "cloud";

export const compressToBase64 = (
  gameState: PlayerData,
  mode: SaveMode = "local",
  lastSavedLocal?: number,
): string => {
  const now = Date.now();

  const wrapper: StoredGameState = {
    state: gameState,
    lastSavedLocal: lastSavedLocal ? lastSavedLocal : now,
    lastSavedCloud: mode === "cloud" ? now : undefined,
  };

  const json = JSON.stringify(wrapper);
  const compressed = pako.deflate(json);
  const base64 = btoa(String.fromCharCode(...compressed));
  return base64;
};

export const isInSync = (localData: GamePreview | undefined, cloudData: GamePreview | undefined): boolean => {
  if (!localData || !cloudData) return false;
  const sameGameId = isSameGameId(localData, cloudData);
  const sameIngameTime = localData?.inGameTime === cloudData?.inGameTime;
  const sameXp = localData?.totalXP === cloudData?.totalXP;
  if (sameIngameTime && sameXp && sameGameId) return true;
  return false;
};

export const isSameGameId = (
  localData: GamePreview | undefined,
  cloudData: GamePreview | undefined,
): boolean => {
  if (!localData || !cloudData) return false;
  return localData.accountId === cloudData.accountId;
};

