import { SkillIdNumberDictionary } from "../AllTypes/SkillsSpecificTypes.ts";
import { ItemDataByReference } from "../AllTypes/PlayerDataTypes.ts";
import { Difficulty } from "../AllTypes/DiaryTypes.ts";
import { DiaryIds } from "../AchievementDiaries/DiaryTypes.ts";
import { QuestIds } from "./QuestIds.ts";
import { PLACEHOLDER_IMG, PLACEHOLDER_NAME } from "../Constants.ts";
import ForestQuestData from "./forest";
import FieldQuestData from "./field";
import MarketQuestData from "./market";
import FortressQuestData from "./fortress";
import MineQuestData from "./mine";
import SeaQuestData from "./sea";
import TempleQuestData from "./temple";

export type Quest = {
  id: number;
  name?: string;
  description: string;
  questDuration: number;
  associatedDiary: DiaryIds;
  difficulty: Difficulty;
  questPoints: number;
  icon?: string;
  skillReq?: SkillIdNumberDictionary;
  itemsRequired?: ItemDataByReference[];
  itemsReward?: ItemDataByReference[];
  questReq?: QuestIds[];
  xpRewards?: SkillIdNumberDictionary;
  combatLevelRequired?: number;
  questPointsRequired?: number;
};
export type QuestFinal = Quest & {
  name: string;
  icon: string;
};

export function getQuestInfoById(questId: QuestIds | undefined): QuestFinal | null {
  if (!questId) return null;
  const res = QuestRegistry[questId];
  if (!res) return null;
  return {
    ...res,
    name: res.name || PLACEHOLDER_NAME,
    icon: res.icon || PLACEHOLDER_IMG,
  };
}

export type PartialQuestsType = Partial<Record<QuestIds, Quest>>;
export type AllQuestsType = Record<QuestIds, Quest>;
export const QuestRegistry: AllQuestsType = {
  ...ForestQuestData,
  ...SeaQuestData,
  ...MineQuestData,
  ...FortressQuestData,
  ...MarketQuestData,
  ...FieldQuestData,
  ...TempleQuestData,
} as AllQuestsType;
