import { ItemDataByReference, ItemType, XpLampItemType } from "../AllTypes/PlayerDataTypes.ts";
import { ImageMap } from "../ImageMap.ts";

import { SkillsId } from "../skillsData/SkillsEnum.ts";

export const DynamicItemsData: Record<number, XpLampItemType> = {};
export const DynamicItemIdStartValue = 1_000_000;
let nextDynamicItemId = DynamicItemIdStartValue;

export function createAntiqueLamp(
  amount: number,
  xp: number,
  minLevel: number,
  skillList: SkillsId[],
  probability?: number,
) {
  const id = nextDynamicItemId++; // 👈 generate a new ID
  const displayName = `Antique lamp(${xp}xp)(${minLevel}lv)`;

  const itemData: XpLampItemType = {
    id: id,
    name: displayName,
    img: ImageMap.xpLamp,
    amount: amount,
    type: ItemType.XP_LAMP,
    sellable: false,
    xp: xp,
    minLevel: minLevel,
    skillList: skillList,
    probability: probability,
  };

  DynamicItemsData[id] = itemData;

  return {
    id: id,
    amount: amount,
    probability: probability,
  } as ItemDataByReference;
}
