import { SlayerInfoType } from "../../AllTypes/PlayerDataTypes.ts";
import { AllSlayerMasters } from "../../Slayer/AllSlayerMasters.ts";
import { ValidSlayerMasterIds } from "../../AllTypes/SlayerTypes.ts";

export const calculateSlayerPointsFromSlayerMaster = (slayerInfo: SlayerInfoType) => {
  const slayerStreak = slayerInfo.slayerStreak + 1;

  const slayerMaster = slayerInfo.currentSlayerTask?.slayerMasterId;
  const slayerPoints = AllSlayerMasters[slayerMaster as ValidSlayerMasterIds].pointsReward;

  if (slayerStreak % 1000 === 0) {
    return slayerPoints.per1000;
  } else if (slayerStreak % 250 === 0) {
    return slayerPoints.per250;
  } else if (slayerStreak % 100 === 0) {
    return slayerPoints.per100;
  } else if (slayerStreak % 50 === 0) {
    return slayerPoints.per50;
  } else if (slayerStreak % 10 === 0) {
    return slayerPoints.per10;
  } else {
    return slayerPoints.base;
  }
};
