export const checkItemCostInInventory = (
  itemCost: ItemDataByReference[] | null | undefined,
  items: playerItemsType,
  currentLootMultiplier: number,
  excludeItems?: ItemIds[],
): boolean => {
  if (!itemCost) return true;
  const getTotalQuantityAcrossContainers = (itemId: number): number => {
    const allItems = getItemsFromAllContainers(items);
    return allItems.reduce((total, slot) => {
      if (slot && slot.id === itemId) {
        return total + slot.amount;
      }
      return total;
    }, 0);
  };
  for (const cost of itemCost) {
    if (excludeItems?.includes(cost.id)) {
      continue;
    }
    const requiredAmount = Math.floor(cost.amount * currentLootMultiplier);
    const totalOwned = getTotalQuantityAcrossContainers(cost.id);

    // If not enough, show toast and return false
    if (totalOwned < requiredAmount) {
      return false;
    }
  }
  // If we never failed, that means we have enough of everything
  return true;
};
export const checkDemoRestriction = (
  clueDiff: ContractDifficultyIds | undefined,
  e: React.MouseEvent | null | undefined,
  addToast: (toastComponent: React.ReactElement, timeout: number) => void,
): boolean => {
  if (isDemo) {
    const validContractsInDemo = [ContractDifficultyIds.EASY, ContractDifficultyIds.MEDIUM];
    if (clueDiff && !validContractsInDemo.includes(clueDiff)) {
      const message = "Can't be opened in Demo version!";
      if (e) {
        addToast(<ErrorToasterWithEvent message={message} mouseEvent={e} />, 2000);
      } else {
        addToast(<ErrorToaster message={message} />, 2000);
      }
      return false;
    }
  }
  return true;
};
export const isItemCostInInventoryNow = (
  itemCost: ItemDataByReference[] | null | undefined,
  currentLootMultiplier: number,
  addToast: (toastComponent: React.ReactElement, timeout: number) => void,
  e: React.MouseEvent | null | undefined,
): boolean => {
  if (!itemCost || itemCost.length === 0) return true;
  const hasEnoughItems = checkItemCostNow(itemCost, currentLootMultiplier);
  if (!hasEnoughItems) {
    const errorMessage = "Not enough items";
    if (e) {
      addToast(<ErrorToasterWithEvent message={errorMessage} mouseEvent={e} />, 1000);
    } else {
      addToast(<ErrorToaster message={errorMessage} />, 1000);
    }
  }
  return hasEnoughItems;
};

export const isItemCostInInventory = (
  itemCost: ItemDataByReference[] | null | undefined,
  items: playerItemsType,
  currentLootMultiplier: number,
  addToast: (toastComponent: React.ReactElement, timeout: number) => void,
  e: React.MouseEvent | null | undefined,
  excludeItems?: ItemIds[],
): boolean => {
  if (!itemCost || itemCost.length === 0) return true;
  const hasEnoughItems = checkItemCostInInventory(itemCost, items, currentLootMultiplier, excludeItems);
  // const hasEnoughItems = checkItemCostNow(itemCost, currentLootMultiplier);

  if (!hasEnoughItems) {
    const errorMessage = "Not enough items";

    if (e) {
      addToast(<ErrorToasterWithEvent message={errorMessage} mouseEvent={e} />, 1000);
    } else {
      addToast(<ErrorToaster message={errorMessage} />, 1000);
    }
  }

  return hasEnoughItems;
};

export const isItemCostInInventoryOrEquipped = (
  itemCost: ItemDataByReference[] | null | undefined,
  items: playerItemsType,
  addToast: (toastComponent: React.ReactElement, timeout: number) => void,
  e: React.MouseEvent,
  equippedItems: EquippedItemsSetType,
  slotToCheck: Slots, // Specific equipment slot to check
): boolean => {
  if (!itemCost || itemCost.length === 0) return true;

  //Todo this should use the existing checkItemCostInInventory function to avoid code duplication
  for (const costItem of itemCost) {
    // Check if the item is in the inventory
    const isInInventory = items.inventory.some((invItem) => invItem?.id === costItem.id);

    // Check if the item is equipped in the specific slot
    const isEquipped = equippedItems[slotToCheck]?.id === costItem.id;

    // If at least ONE item is found in inventory or equipped, return true immediately
    if (isInInventory || isEquipped) {
      return true;
    }
  }
  // If no valid item was found, show toast and return false
  addToast(
    <ErrorToasterWithEvent
      message={`You need at least one of these items in your inventory or equipped in ${slotToCheck}.`}
      mouseEvent={e}
    />,
    1000,
  );

  return false;
};

export function emptyInventorySpace(container?: InventoryItemsData): number {
  if (!container) return 0;
  return container.filter((slot) => slot === null).length;
}

export const isInventorySpaceNow = (
  itemGain: ItemDataByReference[] | null | undefined,
  addToast: (toastComponent: React.ReactElement, timeout: number) => void,
  e?: React.MouseEvent | null | DragEndEvent,
  alwaysDrops?: ItemDataByReference[] | null,
  dropRolls?: number,
  dropTableDrops?: DropTableDrops[] | null,
  ignoreContainer?: boolean,
): boolean => {
  const hasSpace = checkInventorySpaceNow(itemGain, alwaysDrops, dropRolls, dropTableDrops, ignoreContainer);

  if (!hasSpace) {
    if (e) addToast(<ErrorToasterWithEvent message="Not enough inventory space" mouseEvent={e} />, 1000);
    else addToast(<ErrorToaster message="Not enough inventory space" />, 1000);
  }
  return hasSpace;
};

export const isInventorySpace = (
  itemGain: ItemDataByReference[] | null | undefined,
  items: playerItemsType,
  addToast: (toastComponent: React.ReactElement, timeout: number) => void,
  e?: React.MouseEvent | null | DragEndEvent,
  alwaysDrops?: ItemDataByReference[] | null,
  dropRolls?: number,
  dropTableDrops?: DropTableDrops[] | null,
  ignoreContainer?: boolean,
): boolean => {
  const hasSpace = checkInventorySpace(
    itemGain,
    items,
    alwaysDrops,
    dropRolls,
    dropTableDrops,
    ignoreContainer,
  );
  // Handle insufficient space with a toast
  if (!hasSpace) {
    if (e) addToast(<ErrorToasterWithEvent message="Not enough inventory space" mouseEvent={e} />, 1000);
    else addToast(<ErrorToaster message="Not enough inventory space" />, 1000);
  }
  return hasSpace;
};

export const checkInventorySpace = (
  itemGain: ItemDataByReference[] | null | undefined,
  items: playerItemsType,
  alwaysDrops?: ItemDataByReference[] | null,
  dropRolls?: number,
  dropTableDrops?: DropTableDrops[] | null,
  ignoreContainer?: boolean,
): boolean => {
  if (!itemGain && !alwaysDrops) return true;
  let { allDropsWithProbability, alwaysDropsConcat } = mergeDrops(itemGain, alwaysDrops, dropTableDrops);

  //Here add a boolean to ignore containers if needed
  allDropsWithProbability = filterItemsAlreadyInInventoryAndContainers(
    allDropsWithProbability,
    items,
    ignoreContainer,
  );
  alwaysDropsConcat = filterItemsAlreadyInInventoryAndContainers(alwaysDropsConcat, items, ignoreContainer);

  //Remove the items from the entire drops that already exist inside the alwaysDropsList
  allDropsWithProbability = allDropsWithProbability.filter(
    (item) => !alwaysDropsConcat.some((alwaysDrop) => alwaysDrop.id === item.id),
  );

  const requiredInventorySlotsAlwaysDrops = calculateNeededInventorySlots(
    items,
    alwaysDropsConcat,
    ignoreContainer,
  );
  const requiredInventorySlotsDropsWithProbability = calculateNeededInventorySlots(
    items,
    allDropsWithProbability,
    ignoreContainer,
  );

  const requiredProbabilitySlots = Math.min(requiredInventorySlotsDropsWithProbability, dropRolls ?? 1);
  const totalRequiredSlots = requiredInventorySlotsAlwaysDrops + requiredProbabilitySlots;

  const emptySlots = emptyInventorySpace(items.inventory);

  return totalRequiredSlots <= emptySlots;
};

export const calculateNeededInventorySlots = (
  items: playerItemsType,
  itemsToAdd: ItemDataByReference[],
  ignoreContainer?: boolean,
): number => {
  const { inventory } = items;
  let inventorySlotsRequired = 0;
  if (ignoreContainer) return itemsToAdd.length;

  itemsToAdd.forEach((item) => {
    let itemNeedsInventorySpace = true;

    // Iterate over each container in the CONTAINERS_CONFIG
    for (const [containerId, containerConfig] of Object.entries(CONTAINERS_CONFIG)) {
      const isItemAllowed = containerConfig.allowedItems?.includes(item.id);
      const isContainerInInventory = hasExtraStorageInInventory(inventory, containerConfig.unlockItemId);
      if (isItemAllowed && isContainerInInventory) {
        const containerIdKey = containerId as unknown as StorageIds;
        const containerItems = items[containerIdKey];
        const availableSpace = calculateContainerSpace(containerItems, containerConfig);

        if (availableSpace > 0) {
          itemNeedsInventorySpace = false;
          break; // Stop checking other containers if one is found with space
        }
      }
    }

    // If the item doesn't fit in any container, it needs space in the inventory
    if (itemNeedsInventorySpace) {
      inventorySlotsRequired += 1;
    }
  });

  return inventorySlotsRequired;
};

export const calculateContainerSpace = (
  container: InventoryItemsData | undefined,
  config: { capacity: number; allowedItems: ItemIds[] | null },
): number => {
  if (!container || !config.allowedItems) return config.capacity;
  const usedSlots = container.filter((item) => item !== null).length;
  return config.capacity - usedSlots;
};

export const removeContainersFromInv = (playerItems: playerItemsType): playerItemsType => {
  return {
    inventory: playerItems.inventory,
    bank: playerItems.bank,
  };
};

export const filterItemsAlreadyInInventoryAndContainers = (
  items: ItemDataByReference[] | null | undefined,
  playerItems: playerItemsType,
  ignoreContainer: boolean | undefined,
): ItemDataByReference[] => {
  if (!items) return [];

  const allItemsInContainersPlusInventory = ignoreContainer
    ? playerItems.inventory
    : getItemsFromAllContainers(playerItems);
  const allContainerItems = allItemsInContainersPlusInventory.filter(
    (item): item is ItemDataByReference => item !== null,
  );
  const existingItemIds = new Set<number>(allContainerItems.map((item) => item.id));
  return items.filter((item) => !existingItemIds.has(item.id));
};

export const isLevelRequirementsMetWithToaster = (
  req: SkillIdNumberDictionary | null | undefined,
  skills: SkillsMapType,
  addToast: (toastComponent: React.ReactElement, timeout: number) => void,
  boostabelSkill: boolean,
  e?: React.MouseEvent,
): boolean => {
  if (!req || isLevelRequirementMet(skills, req, boostabelSkill)) return true;
  let errorToaster = <ErrorToaster message="You don't have the required level" />;
  if (e) {
    errorToaster = <ErrorToasterWithEvent message="You don't have the required level" mouseEvent={e} />;
  }
  addToast(errorToaster, 1000);
  return false;
};

export const isSpellError = (
  isMagic: boolean,
  currentSpell: SpellIds | null | undefined,
  addToast?: AddToastFunctionType,
): boolean => {
  const isSpellError = isMagic && !currentSpell;
  if (addToast && isSpellError) addToast(<ErrorToaster message="No spell selected." />, 1000);
  return isSpellError;
};

export const isQuestReqMeet = (completedQuestsProp: CompletedQuestsType, questReq: number[]): boolean => {
  return !(
    !questReq ||
    questReq.some((quest) => !allCompletedOrRewardPendingQuestsUtil(completedQuestsProp).includes(quest))
  );
};
export const isQuestCompletedWithToaster = (
  questReq: number[],
  completedQuestsProp: CompletedQuestsType,
  addToast: (toastComponent: React.ReactElement, timeout: number) => void,
  e: React.MouseEvent,
): boolean => {
  if (!areQuestsCompleted(completedQuestsProp, questReq)) {
    const errorToaster = (
      <ErrorToasterWithEvent message="You haven't completed the required quest" mouseEvent={e} />
    );
    addToast(errorToaster, 1000);
    return false;
  }
  return true;
};
export const areAllQuestsAndMiniquestsCompleted = (completedQuestsProp: CompletedQuestsType) => {
  if (!areQuestsCompleted(completedQuestsProp, ALL_QUEST_IDS)) return false;
  return true;
};

export const areAllDiariesCompletedWithToaster = (
  completedAchievementDiaryProp: CompletedAchievementDiary,
  addToast: (toastComponent: React.ReactElement, timeout: number) => void,
  e: React.MouseEvent,
): boolean => {
  if (!areAllDiariesCompleted(completedAchievementDiaryProp)) {
    addToast(<ErrorToasterWithEvent message="You need to have completed all diaries" mouseEvent={e} />, 1000);
    return false;
  }
  return true;
};
