export const isHitpointsAboveZero = (
  hitpoints: number,
  addToast: (toastComponent: React.ReactElement, timeout: number) => void,
  e: React.MouseEvent,
): boolean => {
  if (hitpoints <= 0) {
    addToast(<ErrorToasterWithEvent message="You are dead..." mouseEvent={e} />, 1000);
    return false;
  }
  return true;
};

export const stackedItems = (items: ItemDataByReference[] | null) => {
  if (!items || items.length === 0) return [];

  const map = new Map<number, { amount: number; probability?: number; source?: number }>();

  for (const item of items) {
    if (map.has(item.id)) {
      // Add amount but keep existing probability and source
      const existing = map.get(item.id)!;

      map.set(item.id, {
        ...existing,
        amount: existing.amount + item.amount,
      });
    } else {
      // First time seeing this id, store all values
      map.set(item.id, {
        amount: item.amount,
        ...(item.probability !== undefined && { probability: item.probability }),
        ...(item.source !== undefined && { source: item.source }),
      });
    }
  }

  return Array.from(map.entries()).map(([id, value]) => ({
    id,
    amount: value.amount,
    ...(value.probability !== undefined && { probability: value.probability }),
    ...(value.source !== undefined && { source: value.source }),
  }));
};
