import { ItemDataByReference } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { Slots, ValidEquipmentStats } from "../../../data/AllTypes/EquipmentTypes.ts";
import { ValidTotalBonuses } from "../../../data/AllTypes/AttackStyleAndWeaponTypes.ts";
import {
  getAndMergeItemData,
  getEquipmentInfo,
  getEquipmentStats,
} from "../../../data/ItemData/AllItemsData.ts";
import EquipmentLevelIcon from "../../LevelBoostsComponents/EquipmentLevelIcon.tsx";
import { getSlotInfo } from "../../util/equipmentBonusesUtil.tsx";
import { bonusCategories } from "../../../data/utilData/GearAndDmgCalculations/BonusCatagories.ts";
import { useGetCurrentEquippedItems, useGetLevelBoosts } from "../../../Context/usePlayerStore.ts";
import SkillReqEquitmentToolTip from "./SkillReqEquitmentToolTip.tsx";
import QuestReqEquipmentToolTip from "./QuestReqEquipmentToolTip.tsx";
import AmmoDescriptionToolTip from "./AmmoDescriptionToolTip.tsx";
import { shouldShowPercentage } from "./ToolTipEquipmentStatShowcase.tsx";
import ToolTipHeader from "./ToolTipHeader.tsx";
import AttackSpeedTooltip from "./AttackSpeedTooltip.tsx";

type ToolTipEquipmentProps = {
  item: ItemDataByReference;
};

const ToolTipEquipment = ({ item }: ToolTipEquipmentProps) => {
  const itemData = getAndMergeItemData(item);
  const levelBoosts = useGetLevelBoosts();
  const equippedItems = useGetCurrentEquippedItems();

  const combatPoints = levelBoosts.combatLevelBoostsPoints;
  const equipmentInfo = getEquipmentInfo(item);
  const equipmentStats = getEquipmentStats(item, combatPoints);
  if (!equipmentInfo || !equipmentStats) return null;
  const displayBonuses = (categories: { label: string; stat: ValidEquipmentStats }[]) =>
    categories.map(({ label, stat }, index) => {
      const value = equipmentStats[stat] || 0;
      const equippedItemRef = equippedItems[equipmentInfo.slot as Slots];
      const equippedItemStats = getEquipmentStats(equippedItemRef, combatPoints);
      const currentBonus = equippedItemStats?.[stat] || 0;

      return value !== 0 || currentBonus !== 0 ? (
        <div key={index} className="flex">
          <p>{label}:</p>
          {calculateDeltaBonus(stat as ValidEquipmentStats)}
        </div>
      ) : null;
    });

  const calculateDeltaBonus = (property: ValidEquipmentStats) => {
    if (!equipmentStats || !property) return null;
    const equippedItemRef = equippedItems[equipmentInfo.slot];
    const equippedItemStats = getEquipmentStats(equippedItemRef, levelBoosts.combatLevelBoostsPoints);
    const equippedItemStat = equippedItemStats || ({} as any);
    const currentStat: number = equippedItemStat[property] || 0;
    const totalProperty = "total" + property;
    const currentTotal: number = equippedItems.totalStats[totalProperty as ValidTotalBonuses] || 0;
    const currentStatOfProperty = equipmentStats[property] ? Number(equipmentStats[property]) : 0;
    const delta = currentTotal - currentStat + currentStatOfProperty;
    const shouldShowPercent = shouldShowPercentage(property);
    const currentStatOfPropertyRounded = shouldShowPercent
      ? currentStatOfProperty
      : Math.round(currentStatOfProperty);

    const deltaRounded =
      delta % 1 !== 0
        ? shouldShowPercent
          ? parseFloat(delta.toFixed(2))
          : parseFloat(delta.toFixed(0))
        : delta;
    return (
      <>
        <p className={deltaRounded > 0 ? "text-green-500 flex" : deltaRounded < 0 ? "text-red-500 flex" : ""}>
          {deltaRounded > 0 ? "+" : ""}
          {deltaRounded}
          {shouldShowPercent && "%"}
        </p>
        <p>
          /{currentStatOfPropertyRounded}
          {shouldShowPercent && "%"}
        </p>
      </>
    );
  };

  const level = getSlotInfo(equipmentInfo.slot, levelBoosts.combatLevelBoostsPoints);

  return (
    <div key={item?.id} className={`text-[11.5px] !z-[10000000]`}>
      <div className="absolute -right-[8px] -top-[8px]">
        {level && <EquipmentLevelIcon level={level} small />}
      </div>
      <ToolTipHeader itemData={itemData} />

      {Object.entries(bonusCategories).map(([categoryName, bonuses]) => {
        const shouldDisplay = bonuses.some(({ stat }) => (equipmentStats[stat] ?? 0) > 0);

        return shouldDisplay ? (
          <div key={categoryName}>
            <h2 className="text-orangeColorSecondary">{categoryName}:</h2>
            {displayBonuses(bonuses)}
          </div>
        ) : null;
      })}
      <AttackSpeedTooltip attackSpeed={equipmentInfo.weaponStats?.baseAttackSpeed} />
      {equipmentInfo.weaponStats?.twoHanded && <h2 className="text-blue-500 ">*Two Handed</h2>}
      {Object.entries(equipmentInfo.skillReq ?? {}).length > 0 && (
        <h2 className="text-red-500 ">Level Req:</h2>
      )}

      <SkillReqEquitmentToolTip skillsReq={equipmentInfo?.skillReq} />
      <QuestReqEquipmentToolTip questReq={equipmentInfo?.questReq} />
      <AmmoDescriptionToolTip ammunitionAllowed={equipmentInfo?.weaponStats?.ammunitionAllowed} />
    </div>
  );
};

export default ToolTipEquipment;
