import { ProcessCompletedAttributes } from "../../data/ProcessLevelData/ProcessLevelData.tsx";

type EquipmentLevelIconProps = {
  level: ProcessCompletedAttributes;
  small?: boolean;
};
const EquipmentLevelIcon = ({ level, small }: EquipmentLevelIconProps) => {
  return (
    <div
      className={` z-10 rounded-full p-1 grid container-shadow-small-no-hover place-content-center
      ${small ? "w-4 h-4" : "w-5 h-5"}
      `}
      style={{ backgroundColor: level?.color }}
    >
      <p className={`text-white text-drop-shadow ${small ? "text-[9px] " : "text-[12px]"}`}>
        {level?.equipmentMultiplier}x
      </p>
    </div>
  );
};

export default EquipmentLevelIcon;
