import { useCallback } from "react";
import { useGetSpecificUIVisibility, usePlayerStore } from "../Context/usePlayerStore.ts";

export const useUIVisibility = (key: string, defaultValue?: boolean) => {
  const isOpen = useGetSpecificUIVisibility(key, defaultValue ?? true);

  const setUIVisibility = usePlayerStore((s) => s.setUIVisibility);

  // ✅ Direct setter (NEW)
  const setVisibility = useCallback(
    (value: boolean) => {
      setUIVisibility(key, value);
    },
    [key, setUIVisibility],
  );

  // ✅ Toggle (unchanged behavior)
  const toggleVisibility = useCallback(() => {
    setUIVisibility(key, !isOpen);
  }, [key, isOpen, setUIVisibility]);

  // ✅ Return all three
  return [isOpen, toggleVisibility, setVisibility] as const;
};
