import { ItemDataByReference } from "../../data/AllTypes/PlayerDataTypes.ts";
import { AllDropTables, DropTableDrops } from "../../data/AllTypes/DropTables.ts";

export const mergeDrops = (
  itemGain: ItemDataByReference[] | null | undefined,
  alwaysDrops: ItemDataByReference[] | null | undefined,
  dropTableDrops: DropTableDrops[] | null | undefined,
): { allDropsWithProbability: ItemDataByReference[]; alwaysDropsConcat: ItemDataByReference[] } => {
  let alwaysDropsConcat: ItemDataByReference[] = [];

  const allItemsUndefined = itemGain?.every((item) => item.probability === undefined);
  if (allItemsUndefined && itemGain) {
    alwaysDropsConcat = [...itemGain];
  }
  if (alwaysDrops) {
    alwaysDropsConcat = [...alwaysDrops];
  }

  //Consist of all items and items from droptables if itemGain is not all undefined
  let allDropsWithProbability: ItemDataByReference[] = [];
  if (!allItemsUndefined && itemGain) {
    allDropsWithProbability = [...itemGain];
  }
  if (dropTableDrops) {
    dropTableDrops.forEach((tableDrop) => {
      const drops = AllDropTables[tableDrop.id].drops;
      allDropsWithProbability = [...allDropsWithProbability, ...drops];
    });
  }

  // Return the combined list of drops
  return { allDropsWithProbability, alwaysDropsConcat };
};
