const seedImages = {
  seed: ["seed1"],
};

type Seed = { amount: number; img: string };

function generateSeedData(seedTypeImages: string[]): Record<number, Seed> {
  return seedTypeImages.reduce(
    (acc, img, index) => {
      const amount = index + 1; // Assuming amounts are 1, 10, 100, etc.
      acc[amount] = { amount, img };
      return acc;
    },
    {} as Record<number, Seed>,
  );
}

export const seeds = generateSeedData(seedImages.seed);
