import coinImage1 from "../../../assets/items/coins/coins_1_icon.webp";
import coinImage2 from "../../../assets/items/coins/coins_1_icon.webp";
import coinImage3 from "../../../assets/items/coins/coins_1_icon.webp";
import coinImage4 from "../../../assets/items/coins/coins_1_icon.webp";
import coinImage5 from "../../../assets/items/coins/coins_5_icon.webp";
import coinImage25 from "../../../assets/items/coins/coins_25_icon.webp";
import coinImage100 from "../../../assets/items/coins/coins_100_icon.webp";
import coinImage250 from "../../../assets/items/coins/coins_250_icon.webp";
import coinImage1000 from "../../../assets/items/coins/coins_10000_icon.webp";
import coinImage10000 from "../../../assets/items/coins/coins_1000_icon.webp";

type Coin = {
  amount: number;
  img: string;
};

const coinsData: Coin[] = [
  { amount: 1, img: coinImage1 },
  { amount: 2, img: coinImage2 },
  { amount: 3, img: coinImage3 },
  { amount: 4, img: coinImage4 },
  { amount: 5, img: coinImage5 },
  { amount: 25, img: coinImage25 },
  { amount: 100, img: coinImage100 },
  { amount: 250, img: coinImage250 },
  { amount: 1000, img: coinImage1000 },
  { amount: 10000, img: coinImage10000 },
];

const coins: Record<number, Coin> = coinsData.reduce(
  (acc, coin) => {
    acc[coin.amount] = coin;
    return acc;
  },
  {} as Record<number, Coin>,
);

export default coins;
