import { countTotalDrops, countTotalSkillingPets } from "../Components/util/CombatUtils/MonsterDrops.tsx";
import { countTotalShopItems } from "../Components/util/CollectionLogUtils.tsx";

const getTotalCollectionLogs = () => {
  const totalItems = countTotalShopItems();
  const totalCollectionLogMonster = countTotalDrops();
  const totalSkillingPets = countTotalSkillingPets();

  const totalLogs = totalCollectionLogMonster + totalItems + totalSkillingPets;
  // const totalLogs = totalCollectionLogMonster + totalSkillingPets;

  return totalLogs;
};

export default getTotalCollectionLogs;
