import {
  ItemDataByReference,
  PetCategories,
  PetsType,
  PlayerData,
} from "../../../data/AllTypes/PlayerDataTypes.ts";
import { TOTAL_PETS } from "../../../data/ItemData/pets/AllPetItems.ts";

export function getPet(
  state: PlayerData,
  action: { type: PetCategories; pet: ItemDataByReference },
): PlayerData {
  const { type, pet } = action;
  if (!pet) return state;

  // Ensure pets object exists in state
  const updatedPets: PetsType = state.pets
    ? { ...state.pets, PetsMap: { ...state.pets.PetsMap } }
    : { PetsMap: { Combat: [], Skilling: [] }, total: 0, maxedTimestamp: null };

  // Find index of existing pet
  const petIndex = updatedPets.PetsMap[type].findIndex((p) => p.id === pet.id);

  if (petIndex !== -1) {
    // Create a new array with updated pet amount (Immutable update)
    updatedPets.PetsMap[type] = updatedPets.PetsMap[type].map((p, index) =>
      index === petIndex ? { ...p, amount: p.amount + pet.amount } : p,
    );
  } else {
    // Create a new array and add new pet
    updatedPets.PetsMap[type] = [...updatedPets.PetsMap[type], { ...pet }];
  }

  // Recalculate total pet count (ensuring a fresh object reference)
  updatedPets.total = Object.values(updatedPets.PetsMap).reduce((sum, category) => sum + category.length, 0);

  if (updatedPets.total >= TOTAL_PETS) {
    updatedPets.maxedTimestamp = new Date().getTime();
    updatedPets.total = TOTAL_PETS;
  }

  return {
    ...state,
    pets: { ...updatedPets },
  };
}
