import {
  CompletedQuestsType,
  currentQuestType,
  SkillsMapType,
  ValidQuestStatus,
} from "../../data/AllTypes/PlayerDataTypes.ts";
import { getQuestInfoById, QuestRegistry } from "../../data/Quest/AllQuests.ts";
import { SkillIdNumberDictionary } from "../../data/AllTypes/SkillsSpecificTypes.ts";
import { ALL_QUEST_IDS } from "../../data/Constants.ts";

import { SkillsId } from "../../data/skillsData/SkillsEnum.ts";
import { DiaryIds } from "../../data/AchievementDiaries/DiaryTypes.ts";
import { ImageMap } from "../../data/ImageMap.ts";
import { QuestIds } from "../../data/Quest/QuestIds.ts";
import ErrorToasterWithEvent from "../UtilityComponents/Toasts/ErrorToasterWithEvent.tsx";
import React from "react";

export const isSkillLevelRequirementMet = (
  skills: SkillsMapType,
  levelRequired: SkillIdNumberDictionary | null | undefined,
): boolean => {
  if (!levelRequired) return true;
  for (const [skillId, requiredLevel] of Object.entries(levelRequired)) {
    const skillIdTyped = Number(skillId) as SkillsId;
    const currentSkill = skills[skillIdTyped];
    if (!currentSkill || currentSkill.level < requiredLevel) return false;
  }
  return true;
};

export const isCombatLevelRequirementMet = (
  combatLevel: number,
  combatRequired: number | undefined,
): boolean => {
  if (combatRequired === undefined) return true;
  return combatLevel >= combatRequired;
};
export const isCombatLevelRequirementMetWithToaster = (
  combatLevel: number,
  combatRequired: number | undefined,
  addToast: (toastComponent: React.ReactElement, timeout: number) => void,
  e: React.MouseEvent,
): boolean => {
  if (combatRequired === undefined) return true;
  const isMet = combatLevel >= combatRequired;
  if (!isMet) {
    addToast(<ErrorToasterWithEvent message="Combat requrements not met." mouseEvent={e} />, 1000);
  }
  return isMet;
};

export const isQuestPointsEnough = (
  completedQuest: CompletedQuestsType,
  questPointsRequired: number | undefined,
) => {
  if (questPointsRequired === undefined) return true;
  const { totalCompletedQuestPoints } = calculateTotalQuestPoints(completedQuest);
  return totalCompletedQuestPoints >= questPointsRequired;
};

export const filterAndDisplayQuests = (
  skills: SkillsMapType,
  completedQuests: CompletedQuestsType,
  showCompleted: boolean,
  showIncompletable: boolean,
  selectedSkillId: SkillsId | null,
  difficulty: string,
  combatLevel: number,
) => {
  const allQuestIds = ALL_QUEST_IDS;
  const allCompletedQuests = allCompletedQuestsUtil(completedQuests);
  const allRewardPendingQuests = allRewardPendingQuestsUtil(completedQuests);

  // Function to filter quests based on conditions
  const filterQuests = (
    questId: number,
    completedQuests: number[],
    showIncompletable: boolean, // Add the showIncompletable flag
  ): boolean | null | number | undefined => {
    const questInfo = getQuestInfoById(questId);
    if (!questInfo) return false;
    const isSkillReq = !selectedSkillId || (questInfo.xpRewards && questInfo.xpRewards[selectedSkillId]);
    const isDifficulty = !difficulty || questInfo.difficulty === difficulty;
    const isQuestIncompletable = showIncompletable || !inCompletableQuests.includes(questInfo.id);
    const isQuestCompleted = showCompleted || (completedQuests && !completedQuests.includes(questInfo.id));
    return isQuestCompleted && isSkillReq && isDifficulty && isQuestIncompletable;
  };

  const inCompletableQuests = allQuestIds.filter((questId) => {
    const questInfo = getQuestInfoById(questId);
    if (!questInfo) return false;
    const showQuestRequirements =
      areQuestsCompleted(completedQuests, questInfo.questReq) &&
      isSkillLevelRequirementMet(skills, questInfo.skillReq) &&
      isCombatLevelRequirementMet(combatLevel, questInfo.combatLevelRequired) &&
      isQuestPointsEnough(completedQuests, questInfo.questPointsRequired);
    return !showQuestRequirements;
  });

  const rewardPending = allQuestIds.filter((questId) => {
    return (
      allRewardPendingQuests.includes(questId) && filterQuests(questId, allCompletedQuests, showIncompletable)
    );
  });

  const uniqueQuestsToDisplay = new Set<number>();

  allQuestIds.forEach((questId: number) => {
    if (!rewardPending.includes(questId)) {
      if (filterQuests(questId, allCompletedQuests, showIncompletable)) {
        uniqueQuestsToDisplay.add(questId);
      }
    }
  });

  // Sort unique quests based on duration
  const sortedUniqueQuests = Array.from(uniqueQuestsToDisplay).sort((a, b) => {
    const aAsID = Number(a) as QuestIds;
    const bAsID = Number(b) as QuestIds;
    const questA = QuestRegistry[aAsID];
    const questB = QuestRegistry[bAsID];
    if (!questA || !questB) return 0; // Handle undefined quests
    return questA.questDuration - questB.questDuration;
  });

  return [...rewardPending, ...sortedUniqueQuests];
};

export const calculateTotalQuestPoints = (completedQuestsProp: CompletedQuestsType) => {
  const completedQuestsArray = allCompletedOrRewardPendingQuestsUtil(completedQuestsProp);

  const totalQuestPoints = Object.values(QuestRegistry).reduce((total, quest) => {
    return total + (quest.questPoints || 0);
  }, 0);
  const completedQuestsData = completedQuestsArray.map((questId) => getQuestInfoById(questId));
  const totalCompletedQuestPoints = completedQuestsData.reduce((total, quest) => {
    return total + (quest?.questPoints || 0);
  }, 0);

  return {
    totalQuestPoints,
    totalCompletedQuestPoints,
  };
};

export const isLevelRequirementMet = (
  skills: SkillsMapType,
  req: SkillIdNumberDictionary,
  boostedLevelCheck?: boolean,
) => {
  function areSkillLevelsMet(skills: SkillsMapType, levelRequired: SkillIdNumberDictionary) {
    for (const skillId in levelRequired) {
      const skillTyped = Number(skillId) as SkillsId;
      const levelToCheck = boostedLevelCheck ? skills[skillTyped].boostedLevel : skills[skillTyped].level;
      if (skills[skillTyped] && levelToCheck < ((levelRequired && levelRequired[skillTyped]) ?? 0)) {
        return false;
      }
    }
    return true;
  }

  return areSkillLevelsMet(skills, req);
};

export const checkQuestCompletion = (
  currentQuestId: number | undefined,
  currentQuest: currentQuestType,
  onComplete: (questId: QuestIds) => void,
): void => {
  if (!currentQuestId) return;

  const now = Date.now();
  if (currentQuest && currentQuest.questFinishTime <= now) {
    const currentQuestData = getQuestInfoById(currentQuestId);
    if (!currentQuestData) return;

    onComplete(currentQuestId);
  }
};

export const countCompletedQuestsButNotTakenRewards = (completedQuests: CompletedQuestsType): number => {
  if (!completedQuests) return 0;
  return Object.keys(completedQuests).filter((quest) => isQuestRewardPending(completedQuests, Number(quest)))
    .length;
};

export const isQuestInProgress = (quests: CompletedQuestsType, questId: QuestIds): boolean => {
  if (!quests) return false;
  return quests[questId] === ValidQuestStatus.InProgress;
};
export const isQuestRewardPending = (quests: CompletedQuestsType | undefined, questId: QuestIds): boolean => {
  if (!quests) return false;
  return quests[questId] === ValidQuestStatus.CompletedRewardPending;
};

export const isQuestCompleted = (quests: CompletedQuestsType | undefined, questId: QuestIds): boolean => {
  if (!quests) return false;
  return quests[questId] === ValidQuestStatus.Completed;
};

export const isQuestCompletedOrRewardPending = (
  quests: CompletedQuestsType | undefined,
  questId: number,
): boolean => {
  if (!quests) return false;
  return isQuestCompleted(quests, questId) || isQuestRewardPending(quests, questId);
};

export const areQuestsCompleted = (
  completedQuestsProp: CompletedQuestsType,
  questReq: number[] | undefined,
) => {
  if (!questReq) return true;
  return questReq.every((questId) => isQuestCompletedOrRewardPending(completedQuestsProp, questId));
};

export const allCompletedOrRewardPendingQuestsUtil = (completedQuests: CompletedQuestsType) => {
  if (!completedQuests) return []; // Return an empty array if completedQuests is null or undefined
  const completedQuestsArray = Object.keys(completedQuests)
    .map(Number) // Convert string keys to numbers
    .filter((questId) => isQuestCompletedOrRewardPending(completedQuests, questId));
  return completedQuestsArray;
};

export const allCompletedQuestsUtil = (completedQuests: CompletedQuestsType) => {
  if (!completedQuests) return []; // Return an empty array if completedQuests is null or undefined
  const completedQuestsArray = Object.keys(completedQuests)
    .map(Number) // Convert string keys to numbers
    .filter((questId) => isQuestCompleted(completedQuests, questId));
  return completedQuestsArray;
};
export const allRewardPendingQuestsUtil = (completedQuests: CompletedQuestsType) => {
  if (!completedQuests) return []; // Return an empty array if completedQuests is null or undefined
  const completedQuestsArray = Object.keys(completedQuests)
    .map(Number) // Convert string keys to numbers
    .filter((questId) => isQuestRewardPending(completedQuests, questId));
  return completedQuestsArray;
};

export const QuestIconFromDiary = (diaryId: DiaryIds | undefined): string => {
  const QuestIconMap = {
    [DiaryIds.FOREST]: ImageMap.forestIconBig,
    [DiaryIds.MINE]: ImageMap.mineIconBig,
    [DiaryIds.SEA]: ImageMap.seaIconBig,
    [DiaryIds.FIELDS]: ImageMap.fieldsIconBig,
    [DiaryIds.TEMPLE]: ImageMap.templeIconBig,
    [DiaryIds.MARKET]: ImageMap.marketIconBig,
    [DiaryIds.FORTRESS]: ImageMap.fortressIconBig,
  };
  return diaryId ? QuestIconMap[diaryId] || ImageMap.logoIcon : ImageMap.logoIcon;
};
