import { AxiosError } from "axios";
import { useSharedToasts } from "./useSharedToasts";
import { useNavigate } from "react-router-dom";
import { useAuthStore } from "./useAuthToken.ts";
import { LOGIN_URL } from "../../data/Constants.ts";

export const useHandleApiError = () => {
  const { showError } = useSharedToasts();
  const navigate = useNavigate();
  const { clearAuth } = useAuthStore();

  const handleApiError = (error: unknown, fallbackMessage = "Something went wrong") => {
    if (!error) return;

    // Check if it’s an Axios error
    if ((error as AxiosError).isAxiosError) {
      const axiosError = error as AxiosError;

      // Server returned a response
      if (axiosError.response) {
        const status = axiosError.response.status;
        const dataMessage = (axiosError.response.data as any)?.message;

        switch (status) {
          case 401:
            showError(dataMessage || "Unauthorized: Please log in");
            //Clear the auth state like tokens and userId
            clearAuth();
            navigate(LOGIN_URL);
            break;
          case 403:
            showError(dataMessage || "Forbidden: You don’t have permission");
            clearAuth();
            navigate(LOGIN_URL);
            break;
          case 500:
            showError(dataMessage || "Internal server error. Try again later");
            break;
          default:
            showError(dataMessage || fallbackMessage);
            break;
        }
      } else if (axiosError.request) {
        // Request was made but no response
        showError("No response from server. Check your connection.");
      } else {
        // Something else happened
        showError(axiosError.message || fallbackMessage);
      }
    } else if (error instanceof Error) {
      // Non-Axios Error
      showError(error.message || fallbackMessage);
    } else {
      showError(fallbackMessage);
    }
  };

  return { handleApiError };
};
