import { Slots } from "../../data/AllTypes/EquipmentTypes.ts";
import {
  EquipmentBonusMap,
  ProcessCompletedAttributes,
} from "../../data/ProcessLevelData/ProcessLevelData.tsx";
import { calculateHighestUpgradeForSlotUpTo } from "../../data/ProcessLevelData/CaulateMileStonePointsCombat.ts";

export const getSlotMultiplier = (slot: Slots, combatPoints: number): number => {
  const slotUpgradeNumber = calculateHighestUpgradeForSlotUpTo(combatPoints, slot);
  const multiplier =
    slotUpgradeNumber > 0 ? EquipmentBonusMap[slotUpgradeNumber - 1]?.equipmentMultiplier : 1; // Safely accessing with optional chaining
  return multiplier ? multiplier : 1;
};

export const getSlotInfo = (slot: Slots, combatPoints: number): ProcessCompletedAttributes => {
  const slotUpgradeNumber = calculateHighestUpgradeForSlotUpTo(combatPoints, slot);

  return EquipmentBonusMap[slotUpgradeNumber - 1];
};
