import { processesCompletedType } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { ResourceIds } from "../../../data/skillsData/ResourceIds.ts";
import { getResourceInfo } from "../../../data/skillsData/skillsChooser.ts";

export const getProcessCompleted = (
  processesCompleted: processesCompletedType | null,
  processId: ResourceIds | null | undefined,
) => {
  if (!processId) return 0;
  const processIdToLevelUp = getProcessNameToLevelUp(processId);
  const currentProcessCompleted =
    processesCompleted && processesCompleted[processIdToLevelUp] ? processesCompleted[processIdToLevelUp] : 0;
  return currentProcessCompleted ?? 0;
};

export const getProcessNameToLevelUp = (processId: ResourceIds) => {
  const processInfo = getResourceInfo(processId);
  if (!processInfo) return processId;
  // const processName = processInfo.name;
  // const isHighAlching = processName?.includes("High alch");
  // const isLowAlching = processName?.includes("Low alch");
  //make the ids for the high alch if needed
  // if (isHighAlching) return "High alch";
  // if (isLowAlching) return "Low alch";
  return processId;
};
