import { MouseEvent, useEffect, useMemo } from "react";
import { autoUpdate, flip, offset, shift, useFloating } from "@floating-ui/react";
import { DragEndEvent } from "@dnd-kit/core";

type EventType = MouseEvent | DragEndEvent;

type FloatingToastProps = {
  mouseEvent?: EventType;
  children: React.ReactNode;
};

export default function FloatingToast({ mouseEvent, children }: FloatingToastProps) {
  const virtualRef = useMemo(() => {
    if (!mouseEvent) return null;

    let x = 0;
    let y = 0;

    if ("clientX" in mouseEvent && "clientY" in mouseEvent) {
      x = mouseEvent.clientX;
      y = mouseEvent.clientY;
    } else if ("delta" in mouseEvent) {
      x = mouseEvent.delta.x;
      y = mouseEvent.delta.y;
    }

    return {
      getBoundingClientRect() {
        return { x, y, top: y, left: x, right: x, bottom: y, width: 0, height: 0 };
      },
    };
  }, [mouseEvent]);

  const { refs, floatingStyles } = useFloating({
    placement: "top",
    middleware: [offset(12), flip(), shift({ padding: 8 })],
    whileElementsMounted: autoUpdate,
  });

  useEffect(() => {
    if (virtualRef) {
      refs.setReference(virtualRef);
    }
  }, [virtualRef, refs]); // refs is stable, virtualRef now memoized

  if (!virtualRef) return null;

  return (
    <div ref={refs.setFloating} style={{ ...floatingStyles, zIndex: 1000, pointerEvents: "none" }}>
      <div className="animateSlideUpToasterSlow flex gap-2">{children}</div>
    </div>
  );
}
