import "./App.css";
import "./CSS/Animations.css";
import "./CSS/AnimationWeapon.css";
import "./CSS/AnimationToasters.css";
import "./CSS/AnimtionItemShine.css";
import "./CSS/ScrollAnimation.css";
import ToastManagerContext from "./Context/ToastManagerContext.tsx";
import { HashRouter as Router, Route, Routes } from "react-router-dom";
import { AuthProvider } from "./Providers/AuthProvider.tsx";
import SetupProtectedRoute from "./Providers/SetupProtectedRoute.tsx";
import { ModalProvider } from "./Context/ModalContext.tsx";

import { lazy, Suspense } from "react";
import LoadingComponent from "./Components/UtilityComponents/LoadingComponent.tsx";
import SteamLoginCallback from "./SteamLoginCallback.tsx";
import { LinkAccountPage } from "./Pages/LinkAccountPage.tsx";
import { Initializers } from "./Layout/Initializers.tsx";

export function lazyRetry<T extends React.ComponentType<any>>(importFn: () => Promise<{ default: T }>) {
  return lazy(() =>
    importFn().catch((err) => {
      console.warn("Lazy chunk failed to load, reloading app", err);
      window.location.reload();
      throw err;
    }),
  );
}

const MainPage = lazyRetry(() => import("./Pages/MainPage/MainPage"));
const SkillDisplayPage = lazyRetry(() => import("./Pages/SkillDisplayPage"));
const CollectionLog = lazyRetry(() => import("./Pages/CollectionLog"));
const Achievements = lazyRetry(() => import("./Pages/Achievements"));
const Shops = lazyRetry(() => import("./Pages/Shops"));
const NotFoundPage = lazyRetry(() => import("./Pages/NotFoundPage"));
const LogInPage = lazyRetry(() => import("./Pages/LogInPage"));
const Monsters = lazyRetry(() => import("./Components/Combat/MonstersPage/Monsters"));
const LevelBoosts = lazyRetry(() => import("./Pages/LevelBoosts"));
const QuestPage = lazyRetry(() => import("./Pages/QuestPage"));
const AccountOverview = lazyRetry(() => import("./Components/AccountOverview/AccountOverview"));
const PrivacyPolicyPage = lazyRetry(() => import("./Pages/PrivacyPolicyPage"));
const Chests = lazyRetry(() => import("./Pages/Chests"));
const LandingPage = lazyRetry(() => import("./Pages/LandingPage/LandingPage"));
const LayoutPage = lazyRetry(() => import("./Layout/LayoutPage"));
const Items = lazyRetry(() => import("./Pages/Items"));

// const inDev = import.meta.env.VITE_APP_MODE === "development";

function ProtectedRoutes() {
  return (
    <AuthProvider>
      <ModalProvider>
        {/*<UpdateNotifier />*/}
        {/*{inDev && <TestingInterface />}*/}
        <Suspense fallback={<LoadingComponent />}>
          <Routes>
            <Route path="/landing" element={<LandingPage />} />
            <Route path="accountOverview" element={<AccountOverview />} />
            <Route path="/privacy-policy" element={<PrivacyPolicyPage />} />
            <Route path="/link-account" element={<LinkAccountPage />} />
            <Route path="/login/steam" element={<SteamLoginCallback />} />
            <Route path="/login" element={<LogInPage />} />

            <Route element={<SetupProtectedRoute />}>
              <Route path="/" element={<LayoutPage />}>
                <Route index element={<MainPage />} />
                <Route path="combat" element={<Monsters />} />
                <Route path="skills/:skillId" element={<SkillDisplayPage />} />
                <Route path="Quests" element={<QuestPage />} />
                <Route path="CollectionLog" element={<CollectionLog />} />
                <Route path="Achievements" element={<Achievements />} />
                <Route path="Items" element={<Items />} />
                <Route path="Items/:itemId" element={<Items />} />
                <Route path="Shops" element={<Shops />} />
                <Route path="Boosts" element={<LevelBoosts />} />
                <Route path="Chests" element={<Chests />} />
              </Route>
              <Route path="*" element={<NotFoundPage />} />
            </Route>
          </Routes>
        </Suspense>
      </ModalProvider>
    </AuthProvider>
  );
}

function App() {
  return (
    // <ProfilerWrapper id="EntireApp" benchmarkDuration={5000}>
    <Router>
      <ToastManagerContext>
        <Initializers />
        <Routes>
          <Route path="/*" element={<ProtectedRoutes />} />
        </Routes>
      </ToastManagerContext>
    </Router>
    // </ProfilerWrapper>
  );
}

export default App;
