import { ItemDataByReference, PotionItemType } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { calcBoost } from "../../util/PotionUtils/PotionUtils.tsx";
import { getAndMergeItemData } from "../../../data/ItemData/AllItemsData.ts";
import { useGetPlayerSkills } from "../../../Context/usePlayerStore.ts";

import { SkillsId } from "../../../data/skillsData/SkillsEnum.ts";
import { getSkillNameFromId } from "../../util/SkillsUtil/SkillUtil.tsx";
import ToolTipHeader from "./ToolTipHeader.tsx";

type ToolTipPotionProps = {
  item: ItemDataByReference;
};

const ToolTipPotions = ({ item }: ToolTipPotionProps) => {
  const itemData = getAndMergeItemData(item) as PotionItemType;
  const skills = useGetPlayerSkills();
  const boostObject = calcBoost(skills, itemData);
  // Create an array of skill names sorted by the total level change, in descending order
  const sortedSkills = boostObject
    ? Object.keys(boostObject).sort((a, b) => {
        const aKey = Number(a) as SkillsId;
        const bKey = Number(b) as SkillsId;
        const deltaLevelA = skills[aKey].boostedLevel - skills[aKey].level;
        const totalLevelChangeA = (boostObject[aKey] ?? 0) - deltaLevelA;

        const deltaLevelB = skills[bKey].boostedLevel - skills[bKey].level;
        const totalLevelChangeB = (boostObject[bKey] ?? 0) - deltaLevelB;

        return totalLevelChangeB - totalLevelChangeA; // Sort in descending order
      })
    : [];

  const maxSkillsToShow = 5;
  const sortedSkillLength = sortedSkills.length;
  const skillsToShow = sortedSkillLength > maxSkillsToShow ? maxSkillsToShow - 1 : sortedSkillLength;
  const splicedSkills = sortedSkills.slice(0, skillsToShow);

  return (
    <div>
      <ToolTipHeader itemData={itemData} />
      {splicedSkills.map((key) => {
        const skillId = Number(key) as SkillsId;
        const skillName = getSkillNameFromId(skillId);

        if (!boostObject) return null;
        const boostedLevel = skills[skillId].boostedLevel;
        const baseLevel = skills[skillId].level;

        const deltaBoostVsBaseLevel = boostedLevel - baseLevel;
        const boostedLevelObject = boostObject[skillId] ?? 0;

        let totalLevelChange = boostedLevelObject - deltaBoostVsBaseLevel;
        if (!itemData.overFlow && boostedLevel + totalLevelChange > baseLevel) {
          totalLevelChange = Math.abs(boostedLevel + totalLevelChange - (baseLevel + totalLevelChange));
        }
        totalLevelChange = Math.min(totalLevelChange, boostedLevelObject);

        if (!itemData.overFlow) {
          totalLevelChange = Math.min(baseLevel - boostedLevel, totalLevelChange);
        }
        // Ensure that we never have a negativ totalLevelChange
        if (boostedLevel + totalLevelChange < baseLevel) totalLevelChange = Math.max(totalLevelChange, 0);

        return (
          <div className="flex gap-[2px]" key={key}>
            <p>{skillName}: </p>
            <div className="flex">
              {totalLevelChange === 0 && <p className=" ">+{totalLevelChange}</p>}
              {totalLevelChange > 0 && <p className="text-green-500">+{totalLevelChange}</p>}
              {totalLevelChange < 0 && <p className="text-red-500 ">{totalLevelChange}</p>}
              <span>/{boostedLevelObject}</span>
            </div>
          </div>
        );
      })}
      {sortedSkillLength > 5 && <p>+{sortedSkillLength - (maxSkillsToShow - 1)} More</p>}
    </div>
  );
};

export default ToolTipPotions;
