import { ItemDataByReference, PlayerData, PotionItemType } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { getItemDataFromId } from "../../../data/ItemData/AllItemsData.ts";
import { ItemIds } from "../../../data/ItemData/AllItemsIds.ts";

type ChangeCurrentPotionAction = {
  potion: ItemDataByReference;
};

export function changeCurrentPotions(state: PlayerData, action: ChangeCurrentPotionAction): PlayerData {
  const now = Date.now();
  const potionData = getItemDataFromId(action.potion.id) as PotionItemType;
  const duration = potionData?.duration ?? 0;
  const id = action.potion.id as ItemIds;
  const computedValue = now + duration * 1000;

  const updatedPotions = { ...(state.currentPotions || {}) } as Partial<Record<ItemIds, number>>;
  updatedPotions[id] = computedValue;

  return {
    ...state,
    currentPotions: updatedPotions,
  };
}
