import { ItemIds } from "../../../data/ItemData/AllItemsIds.ts";
import { getItemDataFromId } from "../../../data/ItemData/AllItemsData.ts";

type AmmoDescriptionToolTipProps = {
  ammunitionAllowed: ItemIds[] | null | undefined;
};
const AmmoDescriptionToolTip = ({ ammunitionAllowed }: AmmoDescriptionToolTipProps) => {
  const lastAmmoId = ammunitionAllowed ? ammunitionAllowed.slice(-1)[0] : null;
  const lastAmmoName = lastAmmoId && getItemDataFromId(lastAmmoId)?.name;
  return <div>{ammunitionAllowed && <div>Up to: {lastAmmoName}</div>}</div>;
};

export default AmmoDescriptionToolTip;
