import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { StanceIds } from "../../../data/ItemData/AllWeaponStances.ts";
import { SpellIds } from "../../../data/utilData/AllMagicSpells.ts";

type ChangeCombatStyleAction = {
  setIndex: number;
  stanceId?: StanceIds;
  spellId?: SpellIds;
};

export function changeCombatStyle(state: PlayerData, action: ChangeCombatStyleAction): PlayerData {
  const { setIndex, stanceId, spellId } = action;
  const prevSet = state.equippedItems.sets[setIndex];
  return {
    ...state,
    equippedItems: {
      ...state.equippedItems,
      sets: {
        ...state.equippedItems.sets,
        [setIndex]: {
          ...prevSet,
          currentWeaponStyle: stanceId ?? prevSet.currentWeaponStyle,
          currentSpell: spellId ?? prevSet.currentSpell,
        },
      },
    },
  };
}
