import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";

type UpdateAttackTimestampAction = {
  attackStartTimestamp: number;
  attackDuration: number;
};

export function updateAttackTimestamp(state: PlayerData, action: UpdateAttackTimestampAction): PlayerData {
  const { attackStartTimestamp, attackDuration } = action;

  if (!state.currentAttackProcess) {
    console.warn("No current attack process to update");
    return state;
  }

  return {
    ...state,
    currentAttackProcess: {
      ...state.currentAttackProcess,
      attackStartTimestamp,
      attackDuration,
    },
  };
}
