import {
  LongTermProcesses,
  RunSlotRequirementsType,
  RunsSlotsPlayerInfo,
} from "../AllTypes/PlayerDataTypes.ts";

import { SkillsId } from "../skillsData/SkillsEnum.ts";
import { QuestIds } from "../Quest/QuestIds.ts";

export const getStaticSlotData = (runId: RunIds, index: number) => {
  switch (runId) {
    case RunIds.HerbRuns:
      return herbRunSlots[index];
    case RunIds.TreeRuns:
      return treeRunSlots[index];
    default:
      return null;
  }
};

export const getRunDataFromId = (runId: RunIds): RunConfigValue | null => {
  return RunConfig[runId] || null;
};

export const getSlotDataFromState = (
  runId: RunIds,
  index: number,
  currentLongTermProcesses: LongTermProcesses | null,
): RunsSlotsPlayerInfo | null => {
  if (!currentLongTermProcesses) return null;
  const runSlots = currentLongTermProcesses[runId];
  if (!runSlots) return null;
  return runSlots[index];
};

export enum RunIds {
  HerbRuns = 1001,
  TreeRuns = 1003,
  ThievingRuns = 1004,
}
export const skillFromRunMap: Record<RunIds, SkillsId> = {
  [RunIds.HerbRuns]: SkillsId.Farming,
  [RunIds.TreeRuns]: SkillsId.Farming,
  [RunIds.ThievingRuns]: SkillsId.Thieving,
};

export type RunConfigValue = {
  name: string;
  id: RunIds;
  slots: StaticSlotType;
};
export type StaticSlotType = Record<number, Partial<RunSlotRequirementsType>>;

