import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { v4 as uuidv4 } from "uuid";

type setPlayerDataAction = {
  playerData: PlayerData;
};
export function setPlayerData(state: PlayerData, action: setPlayerDataAction): PlayerData {
  const { playerData } = action;
  const initialized = playerData.isInitialized;
  if (!initialized) {
    console.log("in here not setting the player data with state", playerData.total);
    return state;
  }
  // Ensure accountId exists
  if (!playerData.accountInfo?.accountId) {
    console.warn("Player data missing accountId — generating one...");
    return {
      ...playerData,
      accountInfo: {
        ...playerData.accountInfo,
        accountId: uuidv4(),
      },
    };
  }

  return playerData;
}
