import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { ResourceIds } from "../../../data/skillsData/ResourceIds.ts";

type changeProcessesCompletedAction = {
  resourceId: ResourceIds;
  amount: number;
};

export const changeProcessesCompleted = (
  state: PlayerData,
  action: changeProcessesCompletedAction,
): PlayerData => {
  const { resourceId, amount } = action;
  const currentProcessesCompleted = state.processesCompleted || {};

  // Correctly updating the processesCompleted with the new amount
  const updatedProcessesCompleted = {
    ...currentProcessesCompleted,
    [resourceId]: (currentProcessesCompleted[resourceId] || 0) + Math.floor(amount),
  };

  // Return new state object with the updated processesCompleted
  return {
    ...state,
    processesCompleted: updatedProcessesCompleted,
  };
};
