import {
  chestInfo,
  chestOpenedType,
  ItemDataByReference,
  PlayerData,
} from "../../../data/AllTypes/PlayerDataTypes.ts";
import { ChestIds } from "../../../data/Chests/AllChests.ts";

function updateDrops(
  existingDrops: ItemDataByReference[],
  dropsReceived: ItemDataByReference[],
): ItemDataByReference[] {
  // Create a Map for fast lookup of existing drops
  const dropsMap = new Map<number, ItemDataByReference>();

  // Add existing drops to the map
  existingDrops.forEach((drop) => {
    dropsMap.set(drop.id, { ...drop });
  });

  // Process each received drop
  dropsReceived.forEach((drop) => {
    if (dropsMap.has(drop.id)) {
      // If drop exists, increase the amount
      dropsMap.get(drop.id)!.amount += drop.amount;
    } else {
      // If drop is new, add it to the map
      dropsMap.set(drop.id, { ...drop });
    }
  });

  // Convert the map back to an array and return the updated drop list
  return Array.from(dropsMap.values());
}

export function updateChestDrop(
  state: PlayerData,
  action: {
    chestId: ChestIds;
    dropsReceived: ItemDataByReference[];
    amount: number;
  },
): PlayerData {
  const { amount, chestId, dropsReceived } = action;
  if (!state.chestsOpened) {
    state.chestsOpened = {} as chestOpenedType; // Initialize if null
  }

  const existingChest = (state.chestsOpened && state.chestsOpened[chestId]) || {
    chestCount: 0,
    drops: [],
  };

  // Update chest count and handle drops
  const updatedChest: chestInfo = {
    chestCount: existingChest.chestCount + amount,
    drops: updateDrops(existingChest.drops, dropsReceived),
  };

  // Return the new state with the updated chest information, ensuring immutability
  return {
    ...state,
    chestsOpened: {
      ...state.chestsOpened,
      [chestId]: updatedChest,
    },
  };
}
