import React from "react";
import IconComponent from "../../Components/AccountOverview/IconComponent.tsx";
import IconRotateWrapper from "./IconRotateWrapper.tsx";
import { IconName } from "../../icons.ts";

type SupportButtonProps = {
  iconName: IconName;
  labelTop: string;
  labelBottom: string;
  bgColor?: string;
  small?: boolean;
  link?: string; // optional external URL
  onClick?: () => void; // optional internal handler
  rotate?: boolean; // if you want rotating icon (like the controller)
  clasName?: string;
  noText?: boolean;
};

const SupportButton: React.FC<SupportButtonProps> = ({
  iconName,
  labelTop,
  labelBottom,
  bgColor = "bg-emerald-600",
  small = false,
  link,
  onClick,
  clasName,
  noText,
}) => {
  const iconSize = small ? 24 : 48;
  const textTopSize = small ? "text-xs" : "text-sm";
  const textBottomSize = small ? "text-md" : "text-2xl";
  const padding = small ? "px-1.5 py-1 rounded-md" : "px-3 p-1.5 rounded-lg";

  const content = (
    <>
      <IconRotateWrapper>
        <IconComponent iconName={iconName} size={iconSize} />
      </IconRotateWrapper>
      {!noText && (
        <div>
          <div className={`tracking-tight leading-none ${textTopSize}`}>{labelTop}</div>
          <div className={`tracking-widest leading-none font-semibold ${textBottomSize}`}>{labelBottom}</div>
        </div>
      )}
    </>
  );

  // If there's a link, render <a>, otherwise <div> with onClick
  const isDisabled = !link && !onClick;
  const Wrapper = link
    ? (props: any) => <a href={link} target="_blank" rel="noopener noreferrer" {...props} />
    : (props: any) => <div {...props} onClick={onClick} />;

  return (
    <Wrapper
      className={`${bgColor} group flex gap-2 w-fit items-center text-start ${
        isDisabled ? "cursor-not-allowed opacity-60" : "cursor-pointer hover:shadow-lg"
      } shadow-black mx-auto ${padding} transition duration-200 text-white ${clasName}`}
    >
      {content}
    </Wrapper>
  );
};

export default SupportButton;
