import { MonsterType } from "../../../data/AllTypes/MonsterTypes.ts";
import { AllMonsters, AllMonstersFiltered } from "../../../data/MonsterData/AllMonsters.ts";
import { AllDropTables, DropTable, DropTableIds } from "../../../data/AllTypes/DropTables.ts";
import {
  DropTableDropsType,
  ItemDataByReference,
  PetsMapType,
} from "../../../data/AllTypes/PlayerDataTypes.ts";
import { MonsterIdDictionary } from "../../../data/AllTypes/AttackStyleAndWeaponTypes.ts";
import { allSkillingPetIds } from "../../../data/AllTypes/AllPetItemNames.ts";
import { DiaryIds } from "../../../data/AchievementDiaries/DiaryTypes.ts";
import { getMonsterInfo } from "../../../data/MonsterData/MonsterInfoUtil.ts";

const countAllDrops = (monsters: MonsterType[]): number => {
  return monsters.reduce((total, monster) => total + (monster.drops ? monster.drops.length : 0), 0);
};

export const countTotalDrops = (): number => {
  const monsters = Object.values(AllMonsters);
  const dropTables = Object.values(AllDropTables);

  let totalDrops = countAllDrops(monsters);

  for (const dropTable of dropTables) {
    totalDrops += dropTable.drops.length;
  }

  return totalDrops;
};

const countDrops = (monsters: MonsterType[], monsterKilledInfo: MonsterIdDictionary | null) => {
  let collectedDropCount = 0;
  let totalDropCount = 0;

  for (const monster of monsters) {
    const monsterStats = monsterKilledInfo && monsterKilledInfo[monster.id];
    totalDropCount += monster.drops.length;
    if (monsterStats && monsterStats.drops && monsterStats.drops.length > 0) {
      monsterStats.drops.forEach((collectedDrop: ItemDataByReference) => {
        const inDrops = monster.drops.some((drop) => drop.id === collectedDrop.id);
        if (inDrops) {
          collectedDropCount++;
        }
      });
    }
  }

  return { collectedDropCount, totalDropCount };
};

export function getMonstersIdsByDiaryId(diaryId: DiaryIds) {
  return AllMonstersFiltered.filter((monsterId) => {
    const monsterInfo = getMonsterInfo(monsterId);
    return monsterInfo?.diaryId === diaryId;
  });
}
export function getMonstersDropsByDiaryId(diaryId: DiaryIds, monsterKillStats: MonsterIdDictionary | null) {
  const monsters = Object.values(AllMonsters).filter((monster) => monster.diaryId === Number(diaryId));
  return countDrops(monsters, monsterKillStats);
}
export const getMonsterForest = (monsterKillStats: MonsterIdDictionary | null) => {
  return getMonstersDropsByDiaryId(DiaryIds.FOREST, monsterKillStats);
};
export const getMonstersMine = (monsterKillStats: MonsterIdDictionary | null) => {
  return getMonstersDropsByDiaryId(DiaryIds.MINE, monsterKillStats);
};
export const getMonsterSea = (monsterKillStats: MonsterIdDictionary | null) => {
  return getMonstersDropsByDiaryId(DiaryIds.SEA, monsterKillStats);
};
export const getMonsterFields = (monsterKillStats: MonsterIdDictionary | null) => {
  return getMonstersDropsByDiaryId(DiaryIds.FIELDS, monsterKillStats);
};
export const getMonsterTemple = (monsterKillStats: MonsterIdDictionary | null) => {
  return getMonstersDropsByDiaryId(DiaryIds.TEMPLE, monsterKillStats);
};

export const getMonsterMarket = (monsterKillStats: MonsterIdDictionary | null) => {
  return getMonstersDropsByDiaryId(DiaryIds.MARKET, monsterKillStats);
};

export const getDropTableDrops = (
  _monsterKillStats: MonsterIdDictionary | null,
  dropTableDrops: DropTableDropsType,
) => {
  let collectedDropCount = 0;
  let totalDropCount = 0;

  for (const id in AllDropTables) {
    const dropTable: DropTable = AllDropTables[id as unknown as DropTableIds];
    totalDropCount += dropTable.drops.length;
    const dropTableDropsUtil = dropTableDrops && dropTableDrops[id as unknown as DropTableIds];
    if (dropTableDropsUtil && dropTableDropsUtil.length > 0) {
      dropTableDropsUtil.forEach((collectedDrop) => {
        const inDrops = dropTable.drops.some((drop) => drop.id === collectedDrop.id);
        if (inDrops) {
          collectedDropCount++;
        }
      });
    }
  }

  return { collectedDropCount, totalDropCount };
};

export const countTotalSkillingPets = (): number => {
  return allSkillingPetIds.length;
};

export const countOwnedSkillingPets = (petsMap: PetsMapType | undefined): number => {
  if (!petsMap) return 0;
  const skillingPets = petsMap.Skilling;
  return skillingPets.length;
};
