import { PlayerData, ValidQuestStatus } from "../../../data/AllTypes/PlayerDataTypes.ts";

type StopQuestAction = {
  questId?: number;
};

export function stopQuest(state: PlayerData, action: StopQuestAction) {
  const { questId } = action;

  return {
    ...state,
    currentQuest: null,
    completedQuests: questId
      ? {
          ...state.completedQuests,
          // [questId]: { status: ValidQuestStatus.NotStarted },
          [questId]: ValidQuestStatus.NotStarted,
        }
      : state.completedQuests,
  };
}
