import { ToolIds } from "../../../data/skillsData/Tools.ts";
import { ToolsMap } from "../../../data/skillsData/skillsChooser.ts";

export const getUnownedTools = (
  ownedToolIds: ToolIds[] | null | undefined,
  allToolInfo: ToolsMap | null | undefined,
): ToolIds[] => {
  const ownedSet = new Set(ownedToolIds ?? []);
  const allToolIds = allToolInfo
    ? (Object.keys(allToolInfo).map((id) => Number(id) as ToolIds) as ToolIds[])
    : null;
  if (!allToolInfo || !allToolIds) return [];
  return allToolIds.filter((id) => !ownedSet.has(id));
};
