import { useMutation } from "@tanstack/react-query";
import { PlayerData } from "../../data/AllTypes/PlayerDataTypes.ts";
import axiosInstance from "../../api/axiosInstance.ts";

export type LoginResponse = {
  accessToken: string;
  refreshToken: string;
  userId: string;
  updatedAt?: Date;
  state?: PlayerData;
};

export const useLoginUser = () => {
  return useMutation<LoginResponse, Error, { token: string }>({
    mutationFn: async ({ token }) => {
      if (!token) return Promise.reject(new Error("Missing credential"));
      const response = await axiosInstance.post("/api/login", {
        token,
      });
      return response.data;
    },
  });
};

export const useLoginSteamAuto = () => {
  return useMutation<LoginResponse, Error, { ticket: string; appId: number }>({
    mutationFn: async ({ ticket, appId }) => {
      const response = await axiosInstance.post("/api/login/steam", {
        ticket,
        appId,
      });
      return response.data;
    },
  });
};
