import { SlayerCategoriesIds } from "../../data/MonsterData/MonsterTypes.ts";
import { SkillsId } from "../../data/skillsData/SkillsEnum.ts";
import { CURRENT_UNLOCK, MONSTER, TAB } from "../../data/Constants.ts";
import { SlayerBuyIds } from "../../data/Slayer/SlayerBuys.ts";
import { MonsterIds } from "../../data/MonsterData/MonsterIds.ts";

export function createSlayerMonsterUrl(monsterId: SlayerCategoriesIds | null | undefined) {
  const baseUrl = `/combat?${TAB}=All&page=1`;
  return monsterId ? `${baseUrl}&slayerMonster=${monsterId}` : baseUrl;
}

export function createSearchMonsterUrl(search: string) {
  return `/combat?${TAB}=All&page=1&search=${search}`;
}

export function createSlayerBuyUrl(upgradeId: SlayerBuyIds) {
  return `/skills/${SkillsId.Slayer}?${TAB}=Buy&${CURRENT_UNLOCK}=${upgradeId}`;
}

export function createSlayerOfflineUrl(monsterId: MonsterIds) {
  return `/skills/${SkillsId.Slayer}?${TAB}=Offline&${MONSTER}=${monsterId}`;
}
