import { useUIVisibility } from "../../../hooks/useUIVisibility.tsx";
import { SHOW_CLASSIC_NUMBER_DISPLAY } from "../../../data/Constants.ts";

interface ItemAmountDisplayProps {
  amount: number;
  black?: boolean;
  className?: string;
}

function ItemAmountDisplay({ amount, black, className }: ItemAmountDisplayProps) {
  const [showClassicNumberDisplay] = useUIVisibility(SHOW_CLASSIC_NUMBER_DISPLAY, false);
  const { value, color } = showClassicNumberDisplay ? getClassicDisplay(amount) : getPreciseDisplay(amount);
  const finalColor = black ? "text-black" : color;

  return <p className={`${finalColor} ${className}`}>{value}</p>;
}

export default ItemAmountDisplay;

const getClassicDisplay = (amount: number) => {
  if (amount >= 10_000_000_000)
    return { value: Math.floor(amount / 1_000_000_000) + "B", color: "text-purple-500" };
  if (amount >= 10_000_000) return { value: Math.floor(amount / 1_000_000) + "M", color: "text-green-500" };
  if (amount >= 100_000) return { value: Math.floor(amount / 1_000) + "K", color: "text-orangeColor" };
  return { value: Math.floor(amount), color: "text-yellowColor" };
};
const getPreciseDisplay = (amount: number) => {
  const K = 1_000,
    M = 1_000_000,
    B = 1_000_000_000;
  if (amount >= B) {
    const roundedDown = Math.floor((amount / B) * 100) / 100;
    const val = amount < 10 * B ? roundedDown.toFixed(1).replace(/\.?0+$/, "") : Math.floor(amount / B);
    return { value: val + "B", color: "text-purple-500" };
  }
  if (amount >= M) {
    const roundedDown = Math.floor((amount / M) * 10) / 10;
    const val = amount < 10 * M ? roundedDown.toFixed(1).replace(/\.0$/, "") : Math.floor(amount / M);
    return { value: val + "M", color: "text-green-500" };
  }
  if (amount >= 10 * K) return { value: Math.floor(amount / K) + "K", color: "text-orangeColor" };

  return { value: Math.floor(amount), color: "text-yellowColor" };
};
