type Arrow = { amount: number; img: string };

export function generateArrowData(arrowTypeImages: string[]): Record<number, Arrow> {
  return arrowTypeImages.reduce(
    (acc, img, index) => {
      const amount = index + 1;
      acc[amount] = { amount, img };
      return acc;
    },
    {} as Record<number, Arrow>,
  );
}
