import { PlayerData, ValidRunStatusTypes } from "../../data/AllTypes/PlayerDataTypes.ts";
import { RunIds } from "../../data/Runs/AllRunsData.ts";
import { simulateRolls } from "../../Components/util/ProcessUtil.tsx";
import { getResourceInfo } from "../../data/skillsData/skillsChooser.ts";

type CompleteRunSlotAction = {
  runId: RunIds;
  slot: number;
};

export function runCompletedWithRewardPending(state: PlayerData, action: CompleteRunSlotAction): PlayerData {
  const { runId, slot } = action;

  const currentRuns = { ...state.currentLongTermProcesses };
  const runSlots = currentRuns?.[runId];

  const resourceId = runSlots?.[slot]?.resourceId;
  const resourceInfo = resourceId ? getResourceInfo(resourceId) : null;
  const itemGainAlways = resourceInfo?.itemGainAlways;
  const itemGainWithProbability = resourceInfo?.itemGainWithProbability;

  //Todo fix, since the properbility is cahgned based on loot multipler so it will change the rolled stuff
  const flattenedItems = itemGainWithProbability && simulateRolls(itemGainWithProbability, 1);
  const allItems = itemGainAlways ? [...itemGainAlways, ...(flattenedItems ?? [])] : flattenedItems;

  if (runSlots?.[slot]) {
    const updatedRun = {
      ...runSlots,
      [slot]: {
        ...runSlots[slot],
        status: ValidRunStatusTypes.CompletedRewardPending,
        baseCalculatedLootNoPet: allItems,
      },
    };

    return {
      ...state,
      currentLongTermProcesses: {
        ...currentRuns,
        [runId]: updatedRun,
      },
    };
  } else {
    console.error(`Invalid runId or slot index: ${runId}, slot: ${slot}`);
    return state;
  }
}
