import { calculateTotalBonuses } from "../../Components/Reducer/playerCalculations.ts";
import { PlayerData } from "../../data/AllTypes/PlayerDataTypes.ts";

export function recalculateBonuses(state: PlayerData): PlayerData {
  // Recalculate bonuses for all sets
  const updatedSets = Object.fromEntries(
    Object.entries(state.equippedItems.sets).map(([setIndex, equippedSet]) => {
      const totalBonuses = calculateTotalBonuses(equippedSet, state.levelBoosts.combatLevelBoostsPoints);
      return [
        setIndex,
        {
          ...equippedSet,
          totalStats: totalBonuses || equippedSet.totalStats, // Update totalStats for each set
        },
      ];
    }),
  );

  return {
    ...state,
    equippedItems: {
      ...state.equippedItems,
      sets: updatedSets, // Replace sets with recalculated values
    },
  };
}
