import { placeItemInContainer } from "../../../Components/util/ExtraStorageUtils/ExtraStorageUtils.tsx";
import {
  AutoCombatIds,
  AutoCombatValues,
  ItemDataByReference,
  PlayerData,
} from "../../../data/AllTypes/PlayerDataTypes.ts";
import { AUTO_COMBAT_CONFIG } from "../../../Components/util/AutoCombatUtils/AutoCombatUtils.ts";

export function getAutoCombatItem(
  state: PlayerData,
  action: { item: ItemDataByReference; autoCombatId: AutoCombatIds },
): PlayerData {
  const { item, autoCombatId } = action;
  if (!item) return state;

  const config = AUTO_COMBAT_CONFIG[autoCombatId];
  if (!config) return state;

  const existing = state.autoCombat?.[autoCombatId];
  const currentItems = [...(existing?.items?.length ? existing.items : [null])];
  const roundedAmount = Math.round(item.amount);

  if (roundedAmount > 0 && config.allowedItems.includes(item.id)) {
    const updatedItems = placeItemInContainer(currentItems, item, roundedAmount);

    const updatedAutoCombatEntry: AutoCombatValues = {
      items: updatedItems,
      interval: existing?.interval ?? 0,
      cooldownTimestamp: existing?.cooldownTimestamp ?? 0,
    };

    return {
      ...state,
      autoCombat: {
        ...state.autoCombat,
        [autoCombatId]: updatedAutoCombatEntry,
      },
    };
  }

  return state; // No update needed
}
