import ItemAmountDisplay from "../../util/Formatter/ItemAmountDisplay.tsx";
import { ItemDataByReference } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { getAndMergeItemData } from "../../../data/ItemData/AllItemsData.ts";
import ImgGetImageSourceWithSkeletonLoading from "./ImgGetImageSourceWithSkeletonLoading.tsx";
import { memo } from "react";
import { calculateItemProbability } from "../../util/ProcessUtil.tsx";
import TooltipWrapper from "../ToolTip/TooltipWrapper.tsx";
import TooltipWithAmountProb from "../ToolTip/TooltipContentWithAmountProb.tsx";
import ItemDbLinkButton from "./ItemDbLinkButton.tsx";

type ItemGainDisplayProps = {
  itemsGain: ItemDataByReference[] | null | undefined;
  currentLootMultiplier?: number;
  shouldShowOverlay?: boolean;
  probabilityMultiplier?: number;
  big?: boolean;
  className?: string;
  showHelpLink?: boolean;
};

const ItemsGainDisplay = memo(
  ({
    itemsGain,
    currentLootMultiplier = 1,
    big,
    shouldShowOverlay,
    className,
    probabilityMultiplier,
    showHelpLink,
  }: ItemGainDisplayProps) => {
    if (!itemsGain) return null;

    return (
      <div
        className={`flex flex-wrap absolute bottom-0 right-0 justify-end gap-[1px] ${
          shouldShowOverlay && "brightness-50"
        }
        ${className} 
      `}
      >
        {itemsGain.map((item, index) => {
          const itemData = getAndMergeItemData(item);
          const probability = calculateItemProbability(item, probabilityMultiplier ?? 1);
          const { name, amount } = itemData;
          const displayAmount = amount * currentLootMultiplier;

          return (
            <div
              key={index}
              className={`flex gap-1 bottom-0 h-[25px] flex-wrap place-items-center right-0 text-sm !text-black group/itemRef
              `}
              style={{ right: `${index * 18}px` }}
            >
              <TooltipWrapper
                placement={"top"}
                className={"relative"}
                content={<TooltipWithAmountProb amount={amount} probability={probability} itemName={name} />}
              >
                {showHelpLink && <ItemDbLinkButton itemId={item.id} />}

                <div className=" relative flex  justify-center h-full items-center">
                  {displayAmount >= 2 && (
                    <div className="absolute z-20 -left-[1px] -top-1.5 text-[9px]">
                      <ItemAmountDisplay amount={displayAmount} />
                    </div>
                  )}
                  <ImgGetImageSourceWithSkeletonLoading
                    item={item}
                    amount={displayAmount}
                    containerClassName={`relative min-w-[20px] flex justify-center items-center ${
                      !big && "max-w-[26px] h-[26.5px]"
                    }`}
                    skeletonClassName={`w-[26px] h-[26.5px] self-center place-self-center `}
                    imageClassName={`h-auto max-h-full max-w-full self-center w-auto aspect-auto object-contain ${
                      big && "!max-w-4 !max-h-7 h-auto w-auto"
                    }`}
                    style={{ zIndex: `${13 - index}` }}
                  />
                </div>
              </TooltipWrapper>
            </div>
          );
        })}
      </div>
    );
  },
);

export default ItemsGainDisplay;
