import { numberFormatter } from "../../util/Formatter/NumberFormatter2Decimal.tsx";
import { getItemInfoFromId } from "../../../data/ItemData/AllItemsData.ts";
import { formatProbability } from "../../CollectionLog/CombatCollectionLog/PetUtils.tsx";
import { ItemIds } from "../../../data/ItemData/AllItemsIds.ts";

type TooltipContentWithAmountProbProps = {
  itemId?: ItemIds;
  itemName?: string;
  probability?: number | null;
  dropRolls?: number;
  amount?: number;
  className?: string;
};
const TooltipContentWithAmountProb = ({
  itemId,
  itemName,
  probability,
  className,
  amount,
  dropRolls,
}: TooltipContentWithAmountProbProps) => {
  const itemInfo = getItemInfoFromId(itemId);
  const name = itemInfo?.name || itemName;

  const renderProbability = probability && probability !== 1 && (
    <>
      {dropRolls && dropRolls > 1 && <div>{dropRolls}x</div>}
      {formatProbability(probability)}
    </>
  );

  return (
    <div
      className={` capitalize pointer-events-none hover:will-change-contents w-fit whitespace-nowrap leading-none flex flex-col items-center
       ${className}`}
    >
      <div>
        {name}
        {amount !== undefined && amount && amount > 1 && "(" + numberFormatter(Math.floor(amount)) + ")"}
      </div>
      <div className="flex gap-1">{renderProbability}</div>
    </div>
  );
};

export default TooltipContentWithAmountProb;
