import { ImageMap } from "../../../data/ImageMap.ts";
import { useNavigation } from "../../../hooks/Navigation/useNavigation.tsx";
import { ItemIds } from "../../../data/ItemData/AllItemsIds.ts";

type ItemDbLinkButtonProps = {
  itemId: ItemIds;
};
const ItemDbLinkButton = ({ itemId }: ItemDbLinkButtonProps) => {
  const { goToItemDb } = useNavigation();

  return (
    <button
      onClick={(e) => {
        e.stopPropagation();
        goToItemDb(itemId);
      }}
      className="absolute overlay-button -top-1 -right-1 z-20 opacity-0 p-[1px] group-hover/itemRef:opacity-100
                        text-white rounded-full red-redirect-small
                        flex items-center justify-center
                       duration-200 cursor-pointer"
    >
      <img src={ImageMap.hiddenContent} alt="" className={"w-3 h-3 object-contain"} />
    </button>
  );
};

export default ItemDbLinkButton;
