import { DISCORD_LINK } from "../../data/Constants.ts";
import SupportButton from "./SupportButton.tsx";

type JoinDiscordProps = {
  small?: boolean;
  clasName?: string;
  noText?: boolean;
};

const JoinDiscord = ({ small, clasName, noText }: JoinDiscordProps) => {
  return (
    <SupportButton
      iconName="PiDiscordLogoFill"
      labelTop="JOIN US ON"
      labelBottom="DISCORD"
      small={small}
      clasName={clasName}
      bgColor="bg-[#5D6FEB]"
      link={DISCORD_LINK}
      noText={noText}
    />
  );
};

export default JoinDiscord;
