import { ItemIds } from "../../../data/ItemData/AllItemsIds.ts";
import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";

type RemoveItemFromLockedListAction = {
  itemId: ItemIds;
};

export function removeItemFromLockedList(
  state: PlayerData,
  action: RemoveItemFromLockedListAction,
): PlayerData {
  const { itemId } = action;
  const currentLocked = state.lockedInventoryItems || [];
  if (!currentLocked.includes(itemId)) {
    // Not present
    return state;
  }
  return {
    ...state,
    lockedInventoryItems: currentLocked.filter((id) => id !== itemId),
  };
}
