import { ResourceIds } from "../../data/skillsData/ResourceIds.ts";

import skillChooser from "../../data/skillsData/skillsChooser.ts";
import { SkillsId } from "../../data/skillsData/SkillsEnum.ts";

export function getSkillAndTabFromResourceId(
  resourceId: ResourceIds,
): { skillId: SkillsId; tabName: string } | null {
  const numericResourceId = Number(resourceId);

  for (const skillId in skillChooser) {
    const skillIdTyped = Number(skillId) as SkillsId;
    const entry = skillChooser[skillIdTyped];
    if (!entry?.tabs) continue;
    for (const tab of entry.tabs) {
      if (tab.resources && tab.resources.includes(numericResourceId)) {
        return {
          skillId: skillIdTyped,
          tabName: tab.name,
        };
      }
    }
  }
  return null;
}
