import { levelBoostsType, processesCompletedType } from "../../../data/AllTypes/PlayerDataTypes.ts";
import {
  DefaultProcessMap,
  getProcessLevelIndex,
  ProcessCompletedAttributes,
  ProcessLevelIds,
  processLevelsArray,
  sharedAttributesMap,
} from "../../../data/ProcessLevelData/ProcessLevelData.tsx";
import skillChooser, {
  AllActiveResourceIds,
  getResourceInfo,
  mergeResources,
  SkillChooserInfo,
} from "../../../data/skillsData/skillsChooser.ts";
import { getLevelInfoFromAmount } from "../ProcessUtil.tsx";
import { getProcessCompleted } from "./GetProcessCompleted.ts";
import { MonsterIdDictionary } from "../../../data/AllTypes/AttackStyleAndWeaponTypes.ts";
import { AllMonstersFiltered } from "../../../data/MonsterData/AllMonsters.ts";
import { ResourceIds } from "../../../data/skillsData/ResourceIds.ts";
import { MonsterIds } from "../../../data/MonsterData/MonsterIds.ts";
import { getMonsterInfo } from "../../../data/MonsterData/MonsterInfoUtil.ts";

export const ensureCorrectLevelData = (
  processesCompleted: processesCompletedType | null,
  monsterKillStats: MonsterIdDictionary | null,
  setLevelBoostsFunction: any,
): levelBoostsType => {
  const skillingLevels = calculateTotalSkillingLevels(processesCompleted);
  const combatLevels = calculateTotalCombatLevels(monsterKillStats);
  const skillingLevelBoostsPoints = calculatePointsFromLevels(skillingLevels);
  const combatLevelBoostsPoints = calculatePointsFromLevels(combatLevels);

  const newLevelBoost: levelBoostsType = {
    combatLevelBoosts: combatLevels,
    skillingLevelBoosts: skillingLevels,
    skillingLevelBoostsPoints: skillingLevelBoostsPoints,
    combatLevelBoostsPoints: combatLevelBoostsPoints,
  };
  setLevelBoostsFunction(newLevelBoost);
  return newLevelBoost;
};

export const calculateTotalSkillingLevels = (
  processesCompleted: processesCompletedType | null,
): Record<ProcessLevelIds, number> | null => {
  const totalLevels: Record<ProcessLevelIds, number> = { ...DefaultProcessMap };
  if (!processesCompleted) return totalLevels;
  Object.values(skillChooser).forEach((skillInfo) => {
    if (!skillInfo.tabs) return;
    const skillLevels = calculateTotalSkillingLevelsFromSkill(processesCompleted, skillInfo);
    if (!skillLevels) return;

    Object.keys(skillLevels).forEach((level) => {
      const processLevel = level as any as ProcessLevelIds;
      totalLevels[processLevel] = (totalLevels[processLevel] || 0) + skillLevels[processLevel];
    });
  });

  // Return the total accumulated levels across all skills
  return totalLevels;
};

export const calculateTotalSkillingLevelsFromSkill = (
  processesCompleted: processesCompletedType | null,
  skillChooseInfo: SkillChooserInfo,
): Record<ProcessLevelIds, number> | null => {
  if (!processesCompleted) return null;

  const resourcesArray: ResourceIds[] = [];
  mergeResources(resourcesArray, skillChooseInfo);

  const totalLevels = resourcesArray.reduce(
    (acc, resourceId) => {
      const resourceInfo = getResourceInfo(resourceId);
      const processIdCast = resourceId as unknown as ResourceIds;
      const amount = getProcessCompleted(processesCompleted, processIdCast);
      const levelInfo = getLevelInfoFromAmount(resourceInfo?.runId, amount, resourceInfo?.tier);
      return accumulateLevels(acc, levelInfo, processLevelsArray); // Use helper function
    },
    { ...DefaultProcessMap } as Record<ProcessLevelIds, number>,
  );

  return totalLevels;
};

export const calculateTotalCombatLevels = (
  monsterKillStats: MonsterIdDictionary | null,
): Record<ProcessLevelIds, number> | null => {
  if (!monsterKillStats) return { ...DefaultProcessMap };

  const isMonsterIdValid = (id: MonsterIds) => {
    return Object.values(MonsterIds).includes(id);
  };

  const totalLevels = Object.entries(monsterKillStats).reduce(
    (acc, [monsterId, monsterStats]) => {
      const monsterIdCast = Number(monsterId) as MonsterIds;
      if (!isMonsterIdValid(monsterIdCast)) {
        return acc;
      }
      const monsterInfo = getMonsterInfo(monsterIdCast);

      const levelInfo = getLevelInfoFromAmount(false, monsterStats?.killCount ?? 0, monsterInfo?.tier);
      return accumulateLevels(acc, levelInfo, processLevelsArray);
    },
    { ...DefaultProcessMap } as Record<ProcessLevelIds, number>, // ✅ clone
  );

  return totalLevels;
};

const accumulateLevels = (
  acc: Record<ProcessLevelIds, number>,
  levelInfo: ProcessCompletedAttributes | null, // Adjust the type as needed
  processLevelsArray: ProcessLevelIds[],
) => {
  const index = levelInfo && getProcessLevelIndex(levelInfo?.id);
  if (index === null || index === -1) return acc; // Skip if no valid level is found

  // Loop through the levels up to the current index and set them to 1
  processLevelsArray.forEach((level, i) => {
    if (i <= index) {
      acc[level] = (acc[level] || 0) + 1; // Accumulate values for each level up to the index
    }
  });

  return acc;
};

export const calculatePointsFromLevels = (levels: Record<ProcessLevelIds, number> | null): number => {
  if (!levels) return 0;

  return Object.entries(levels).reduce((totalPoints, [levelId, amount]) => {
    return totalPoints + calculatePointsFromLevel(levelId as any as ProcessLevelIds, amount);
  }, 0);
};

export const calculatePointsFromLevel = (level: ProcessLevelIds, amount: number = 1): number => {
  return sharedAttributesMap[level].points * amount;
};

export const getTotalStaticResourceCount = (): number => {
  const totalResourceCount = AllActiveResourceIds.flat().length;
  // console.log(totalResourceCount);
  return totalResourceCount;
};

export const totalMonstersAmount = () => {
  return AllMonstersFiltered.length;
};

export const totalMonsterPoints = () => {
  return Object.values(sharedAttributesMap).reduce((total, monster) => {
    return total + monster.points * totalMonstersAmount();
  }, 0);
};
