import React, { useEffect, useState } from "react";
import { useToastStore } from "../Context/ToastStore.ts";
import { usePlayerStore } from "../Context/usePlayerStore.ts";
import { useNavigate } from "react-router-dom";
import { ACCOUNT_OVERVIEW_URL } from "../data/Constants.ts";
import ServerErrorToaster from "./UtilityComponents/Toasts/ServerErrorToaster.tsx";
import LoadingScreen from "../hooks/LoadingScreen.tsx";
import { useSaveStore } from "../Context/Stores/useCompressedDataStore.tsx";

interface PlayerStateInitializerProps {
  onInitialized: () => void;
  slotId: number;
}

const PlayerStateInitializer: React.FC<PlayerStateInitializerProps> = ({ onInitialized, slotId }) => {
  const setPlayerData = usePlayerStore((state) => state.setPlayerData);
  const addToast = useToastStore((state) => state.addToast);
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);
  const loadGameData = useSaveStore((state) => state.loadGameData);

  useEffect(() => {
    try {
      const gameData = loadGameData(slotId);
      const isGameData = gameData && gameData.state;
      const isInitialized = gameData && gameData.state.isInitialized;
      const isDefaultState = !isGameData || !isInitialized;

      if (isDefaultState) {
        addToast(<ServerErrorToaster error={"Failed to find user data in local storage"} />, 5000);
        navigate(ACCOUNT_OVERVIEW_URL, { replace: true });
      } else {
        setPlayerData(gameData.state);
        onInitialized();
      }
    } finally {
      setLoading(false);
    }
  }, [slotId]);

  if (loading) {
    return <LoadingScreen />;
  }

  return null;
};

export default PlayerStateInitializer;
