import { InventoryStates, PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { InventoryItemsData } from "../../../data/AllTypes/SkillsSpecificTypes.ts";

type Action = {
  items: InventoryItemsData;
  inventoryStates: InventoryStates;
};

export function updateInventory(state: PlayerData, action: Action): PlayerData {
  const { inventoryStates, items } = action;
  if (!items) return state;

  return {
    ...state,
    items: {
      ...state.items,
      [inventoryStates]: items,
    },
  };
}
