import { create } from "zustand";
import { persist } from "zustand/middleware";
import React from "react";
import { SLOTS } from "../../data/Constants";
import { PlayerData } from "../../data/AllTypes/PlayerDataTypes";
import {
  GamePreview,
  SlotDataResponse,
  StoredGameState,
} from "../../Components/AccountOverview/AccountOverviewTypes.ts";
import {
  compressToBase64,
  createDownloadLink,
  decompressAndParseData,
  extractPreviewInfo,
  isBase64,
} from "../../Components/AccountOverview/AccountOverviewUtils.tsx";
import ServerErrorToaster from "../../Components/UtilityComponents/Toasts/ServerErrorToaster.tsx";
import ServerSuccessToaster from "../../Components/UtilityComponents/Toasts/ServerSuccessToaster.tsx";

interface SaveStore {
  slots: Record<number, string>; // compressed strings

  // Core CRUD
  compressAndSaveGameData: (slotId: number | null, gameState: PlayerData) => void;
  getCompressDataFromIndex: (slotId: number) => string | null;
  loadGameData: (slotId: number) => StoredGameState | null;
  deleteCompressedGameData: (slotId: number) => void;
  uploadCompressedGameData: (
    slotId: number | null,
    compressedData: string,
    addToast: (component: React.ReactElement, timeout: number) => void,
  ) => void;

  // Preview + cloud
  getAllLocalGamePreviews: () => GamePreview[];
  getAllCloudGamePreviews: (storedGameState: SlotDataResponse | undefined) => GamePreview[] | undefined;

  downloadCompressedGameData: (
    slotId: number,
    addToast: (toastComponent: React.ReactElement, timeout: number) => void,
  ) => void;
}

export const useSaveStore = create<SaveStore>()(
  persist(
    (set, get) => ({
      slots: {},
      compressAndSaveGameData: (slotId, gameState) => {
        if (slotId == null || !gameState.isInitialized) return;
        // console.log(
        //   "In here saving with state: ",
        //   gameState.items.inventory[0],
        //   " saving it to slot",
        //   slotId,
        // );
        const compressed = compressToBase64(gameState);
        set((state) => ({ slots: { ...state.slots, [slotId]: compressed } }));
      },

      getCompressDataFromIndex: (slotId) => {
        return get().slots[slotId] ?? null;
      },

      loadGameData: (slotId) => {
        const compressed = get().slots[slotId];
        if (!compressed) return null;
        const decompressed = decompressAndParseData(compressed);
        if (!decompressed) return null;
        // console.log(decompressed.state.items.inventory[1], "in herere loading it from slot", slotId);
        return decompressed;
      },

      deleteCompressedGameData: (slotId) => {
        set((state) => {
          const newSlots = { ...state.slots };
          delete newSlots[slotId];
          return { slots: newSlots };
        });
      },

      uploadCompressedGameData: (slotId, compressedData, addToast) => {
        // console.log(compressedData, slotId);
        if (slotId === null) {
          addToast(<ServerErrorToaster error="Invalid slot ID!" />, 5000);
          return;
        }
        if (!isBase64(compressedData)) {
          addToast(<ServerErrorToaster error="Invalid compressed data!" />, 5000);
          return;
        }
        const parsed = decompressAndParseData(compressedData);
        if (!parsed || !parsed.state) {
          addToast(
            <ServerErrorToaster error="Invalid game data, should be a long string starting with ey!" />,
            5000,
          );
          return;
        }
        set((state) => ({ slots: { ...state.slots, [slotId]: compressedData } }));
        addToast(<ServerSuccessToaster message={`Game saved successfully to slot ${slotId}!`} />, 5000);
      },

      // ----- Preview -----
      getAllLocalGamePreviews: () => {
        const previews: GamePreview[] = [];
        const { slots } = get();
        for (const slotId of SLOTS) {
          const compressed = slots[slotId];
          if (!compressed) continue;
          const parsed = decompressAndParseData(compressed);
          if (!parsed) continue;
          previews.push(extractPreviewInfo(parsed, slotId));
        }
        return previews;
      },

      getAllCloudGamePreviews: (storedGameState) => {
        if (!storedGameState) return undefined;
        const previews: GamePreview[] = [];
        Object.entries(storedGameState.saves).forEach(([slotId, compressedData]) => {
          if (!compressedData) return;
          const parsed = decompressAndParseData(compressedData);
          if (!parsed) return;
          previews.push(extractPreviewInfo(parsed, Number(slotId)));
        });
        return previews;
      },

      downloadCompressedGameData: (slotId, addToast) => {
        const compressed = get().slots[slotId];
        if (!compressed) {
          addToast(<ServerErrorToaster error="No data found for this slot" />, 5000);
          return;
        }
        createDownloadLink(compressed, slotId);
      },
    }),
    { name: "compressed-saves" },
  ),
);
