import { useEffect } from "react";
import { usePersistentStore } from "../Context/Stores/usePersistentStore.tsx";
import { useKey } from "../Components/UtilityComponents/KeyShotcuts/useEscapeKey.tsx";

export const Initializers = () => {
  const isFullScreenMode = usePersistentStore((state) => state.isFullScreenMode);
  const setIsFullScreenMode = usePersistentStore((state) => state.setIsFullScreenMode);

  const uiScale = usePersistentStore((state) => state.uiScale);
  const isPowerSaveMode = usePersistentStore((state) => state.isPowerSaveModeSteam);
  const handleToggleFullscreen = (e: KeyboardEvent) => {
    e.preventDefault();
    setIsFullScreenMode(!usePersistentStore.getState().isFullScreenMode);
  };

  useKey("F11", handleToggleFullscreen, false);
  useEffect(() => {
    if (window.electronAPI) {
      // SYNC ON STARTUP
      // console.log("in here sync electron");
      window.electronAPI.setFullScreen?.(isFullScreenMode);
      window.electronAPI.setZoom?.(uiScale);
      window.electronAPI.setPowerSaveMode?.(isPowerSaveMode);
    }
  }, []); // Only run once when the app mounts (Login/Start)

  return null;
};
