export const getPrayerIdFromPrayerBook = (itemId: ItemIds) => {
  switch (itemId) {
    case ItemIds.MELEE_PRAYER_UNLOCK:
      return PrayerIds.TITAN_STRENGTH;
    case ItemIds.RANGED_PRAYER_UNLOCK:
      return PrayerIds.MARKSMAN;
    case ItemIds.MAGIC_PRAYER_UNLOCK:
      return PrayerIds.STAR_WARD;
    case ItemIds.STRONG_MELEE_PRAYER_UNLOCK:
      return PrayerIds.WAR_GOD;
    case ItemIds.STRONG_RANGED_PRAYER_UNLOCK:
      return PrayerIds.DEADEYE;
    case ItemIds.STRONG_MAGIC_PRAYER_UNLOCK:
      return PrayerIds.DIVINE;
    default:
      return null;
  }
};

