import { EquippedItemsSetType } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { getEquipmentInfo } from "../../../data/ItemData/AllItemsData.ts";
import { Slots } from "../../../data/AllTypes/EquipmentTypes.ts";
import { ItemIds } from "../../../data/ItemData/AllItemsIds.ts";

export const getUnlimitedRunesFromEquipment = (equipment?: EquippedItemsSetType): ItemIds[] => {
  if (!equipment) return [];

  const equipmentInfo = getEquipmentInfo(equipment[Slots.WEAPON]);
  const equipmentInfoShield = getEquipmentInfo(equipment[Slots.SHIELD]);

  const unlimitedRunesSet = new Set([
    ...(equipmentInfo?.unlimitedRunesType || []),
    ...(equipmentInfoShield?.unlimitedRunesType || []),
  ]);

  return Array.from(unlimitedRunesSet) as unknown as ItemIds[];
};
