import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { SlayerCategoriesIds } from "../../../data/MonsterData/MonsterTypes.ts";
import { ValidSlayerMasterIds } from "../../../data/AllTypes/SlayerTypes.ts";

type ChangeSlayerTaskAction = {
  slayerCategoryId: SlayerCategoriesIds;
  slayerMasterId: ValidSlayerMasterIds;
  currentAmount: number;
  totalAmount: number;
};

export const changeSlayerTask = (state: PlayerData, action: ChangeSlayerTaskAction): PlayerData => {
  const { slayerCategoryId, slayerMasterId, currentAmount, totalAmount } = action;
  return {
    ...state,
    slayerInfo: {
      ...state.slayerInfo,
      currentSlayerTask: {
        slayerCategoryId,
        slayerMasterId,
        currentAmount,
        totalAmount,
      },
    },
  };
};
