import { PlayerData, ValidQuestStatus } from "../../data/AllTypes/PlayerDataTypes.ts";
import { QuestIds } from "../../data/Quest/QuestIds.ts";

type QuestCompletedAction = {
  questId: QuestIds;
};
export function questCompletedWithRewardPending(state: PlayerData, action: QuestCompletedAction): PlayerData {
  const { questId } = action;

  // Check if the quest exists in the completedQuests record
  if (state.completedQuests && state.completedQuests[questId]) {
    return {
      ...state,
      completedQuests: {
        ...state.completedQuests,
        // [questId]: { status: ValidQuestStatus.CompletedRewardPending, finishTime: Date.now() },
        [questId]: ValidQuestStatus.CompletedRewardPending,
      },
    };
  }

  // If the quest doesn't exist in the record, return the original state
  return state;
}
