import {
  DropTableDropsType,
  ItemDataByReference,
  PlayerData,
} from "../../../data/AllTypes/PlayerDataTypes.ts";
import { ValidItemDropTypes } from "../../../data/AllTypes/DropTables.ts";

export function updateDropTableDrops(
  dropTableDrops: Record<ValidItemDropTypes, ItemDataByReference[] | undefined> | null,
  dropTableId: ValidItemDropTypes | undefined,
  dropsReceived: ItemDataByReference[] | undefined,
): ItemDataByReference[] | undefined {
  const existingDrops = (dropTableDrops && dropTableId && dropTableDrops[dropTableId]) || [];
  const updatedDrops: ItemDataByReference[] | undefined = [...existingDrops];
  dropsReceived?.forEach((dropReceived) => {
    const existingDropIndex = updatedDrops.findIndex((drop) => drop.id === dropReceived?.id);
    if (existingDropIndex !== -1) {
      // If the drop exists, increment its amount
      updatedDrops[existingDropIndex] = {
        ...updatedDrops[existingDropIndex],
        amount: updatedDrops[existingDropIndex].amount + dropReceived?.amount,
      };
    } else {
      // If the drop does not exist, add it to the array
      updatedDrops.push({ id: dropReceived?.id, amount: dropReceived?.amount });
    }
  });

  return updatedDrops;
}

export function updateReceivedDropTableDrops(
  state: PlayerData,
  action: {
    dropTableId: ValidItemDropTypes | undefined;
    dropsReceived: ItemDataByReference[] | undefined;
  },
): PlayerData {
  const { dropTableId, dropsReceived } = action;

  if (!dropTableId || !Array.isArray(dropsReceived) || dropsReceived.length === 0) {
    return state;
  }

  // Update drops
  const updatedDrops = updateDropTableDrops(state.dropTableDrops, dropTableId, dropsReceived);

  const updatedDropTableState = {
    ...state.dropTableDrops,
    [dropTableId]: updatedDrops,
  };

  return {
    ...state,
    dropTableDrops: updatedDropTableState as DropTableDropsType,
  };
}
