import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { ValidMonsterAttackStyles } from "../../../data/AllTypes/MonsterTypes.ts";

type changeNextMonsterAttackStyleAction = {
  nextMonsterAttackStyle: ValidMonsterAttackStyles;
};

export function changeNextMonsterAttackStyle(
  state: PlayerData,
  action: changeNextMonsterAttackStyleAction,
): PlayerData {
  const { nextMonsterAttackStyle } = action;
  if (!state.currentAttackProcess) return state;

  return {
    ...state,
    currentAttackProcess: {
      ...state.currentAttackProcess,
      nextMonsterAttackStyle: nextMonsterAttackStyle,
    },
  };
}
