import skillsChooser from "../../data/skillsData/skillsChooser";
import skillChooser from "../../data/skillsData/skillsChooser";
import { SkillsMapType } from "../../data/AllTypes/PlayerDataTypes.ts";
import { AllSkillIdList, SkillsId } from "../../data/skillsData/SkillsEnum.ts";
import { getUnownedTools } from "./ShopUtils/ToolShopUtil.ts";

export const totalCollectionLog = (skills: SkillsMapType) =>
  AllSkillIdList.reduce(
    (accumulator, skillIdRaw) => {
      const skillId = Number(skillIdRaw) as SkillsId;
      const tools = skillsChooser[skillId]?.shopTools;
      const toolsNotOwned = getUnownedTools(skills[skillId].toolIds, tools);
      if (tools) accumulator.totalItems += Object.keys(tools).length;
      if (tools) accumulator.totalOwnedItems += Object.keys(tools).length - toolsNotOwned.length;
      return accumulator;
    },

    { totalItems: 0, totalOwnedItems: 0 },
  );

export const countTotalShopItems = () => {
  return Object.values(skillChooser).reduce((total, skill) => {
    const toolCount = skill.shopTools ? Object.keys(skill.shopTools).length : 0;
    return total + toolCount;
  }, 0);
};
