import LContainer from "../../../Layout/LContainer.tsx";
import IconComponent from "../../AccountOverview/IconComponent.tsx";

type ServerErrorToasterType = {
  error: string | unknown;
};

const ServerErrorToaster = ({ error }: ServerErrorToasterType) => {
  const isErrorString = typeof error === "string";

  return (
    <div
      className={`toaster fixed flex text-orangeColor pointer-events-none flex-col items-center text-lg justify-center z-20 top-0 w-full animateSlideInSlow`}
    >
      <LContainer>
        <div className="flex max-w-lg gap-2 justify-center pointer-events-auto container-shadow-small cursor-pointer align-middle items-center p-2 ">
          <IconComponent iconName={"PiSealWarningFill"} iconColor={"red"} className="w-7 h-7" />
          <p className="leading-none text-center">
            {isErrorString ? error : "An error occurred. Please try again."}
          </p>
        </div>
      </LContainer>
    </div>
  );
};

export default ServerErrorToaster;
