import {
  CONTAINERS_CONFIG,
  ensureValidContainers,
  hasExtraStorageInInventory,
  normalizeItems,
  placeItemInContainer,
} from "../../Components/util/ExtraStorageUtils/ExtraStorageUtils.tsx";
import {
  InventoryStates,
  ItemDataBase,
  ItemDataByReference,
  PlayerData,
  playerItemsType,
} from "../../data/AllTypes/PlayerDataTypes.ts";

type Action = {
  newItems: ItemDataByReference[];
  inventoryState?: InventoryStates;
};

export function getItems(state: PlayerData, action: Action): PlayerData {
  const { newItems, inventoryState } = action;
  if (!newItems || newItems.length === 0) return state;
  const cleanedItems: ItemDataBase[] = normalizeItems(newItems);
  const { inventory } = state.items;
  const updatedContainers: playerItemsType = ensureValidContainers(state.items);
  const findContainer = (
    containerId: InventoryStates,
    item: ItemDataByReference,
    roundedAmount: number,
  ): boolean => {
    const container = updatedContainers[containerId];
    const { allowedItems } = CONTAINERS_CONFIG[containerId];
    const isItemAllowed = !allowedItems || allowedItems.includes(item.id);
    if (!container || !isItemAllowed) return false;
    const updated = placeItemInContainer(container, item, roundedAmount);
    if (updated !== container) {
      updatedContainers[containerId] = updated;
      return true;
    }
    return false;
  };

  for (const item of cleanedItems) {
    const roundedAmount = Math.round(item.amount);
    if (roundedAmount <= 0) continue;
    if (inventoryState) {
      findContainer(inventoryState, item, roundedAmount);
      continue;
    }
    for (const config of Object.values(CONTAINERS_CONFIG)) {
      const { unlockItemId, id: containerId } = config;
      if (!hasExtraStorageInInventory(inventory, unlockItemId)) continue;
      if (findContainer(containerId, item, roundedAmount)) break;
    }
  }
  return {
    ...state,
    items: {
      ...updatedContainers,
    },
  };
}
