import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { MonsterStatDictionary, ValidMonsterStats } from "../../../data/AllTypes/MonsterTypes.ts";

type ChangeMonsterStateAction = {
  monsterStateChange: Partial<Record<ValidMonsterStats, number>>;
};

export const changeMonsterStateReducer = (state: PlayerData, action: ChangeMonsterStateAction) => {
  const { monsterStateChange } = action;

  // Early return if there's no ongoing attack process
  if (!state.currentAttackProcess) return state;

  // Clone the current monster state stats to avoid direct mutation
  const updatedMonsterStateStats: MonsterStatDictionary = {
    ...state.currentAttackProcess.currentMonsterState,
  };

  // Iterate over the stat changes and apply them to the cloned stats object
  Object.entries(monsterStateChange).forEach(([stat, change]) => {
    if (change !== undefined) {
      // Apply the change to the corresponding stat, defaulting to 0 if it doesn't exist
      updatedMonsterStateStats[stat as ValidMonsterStats] =
        (updatedMonsterStateStats[stat as ValidMonsterStats] || 0) + change;
    }
  });

  // Return the updated state with the new monster stats
  return {
    ...state,
    currentAttackProcess: {
      ...state.currentAttackProcess,
      currentMonsterState: updatedMonsterStateStats,
    },
  };
};
