import React from "react";
import ToolTipEquipment from "../UtilityComponents/ToolTip/ToolTipEquipment.tsx";
import ToolTipPotions from "../UtilityComponents/ToolTip/ToolTipPotions.tsx";
import { ItemDataByReference, ItemType } from "../../data/AllTypes/PlayerDataTypes.ts";
import ToolTipFood from "../UtilityComponents/ToolTip/ToolTipFood.tsx";
import { ToolTipDefaultItem } from "../UtilityComponents/ToolTip/ToolTipDefaultItem.tsx";
import { getItemType } from "../../data/ItemData/AllItemsData.ts";

type InventoryToolTipDisplayProps = {
  item: ItemDataByReference | null;
};

const InventoryToolTipDisplay: React.FC<InventoryToolTipDisplayProps> = React.memo(({ item }) => {
  const itemType = getItemType(item);
  if (!item) return null;

  return (
    <>
      {itemType === ItemType.EQUIPABLE && <ToolTipEquipment item={item} />}
      {itemType === ItemType.POTION && <ToolTipPotions item={item} />}
      {itemType === ItemType.FOOD && <ToolTipFood item={item} />}
      {itemType !== ItemType.FOOD && itemType !== ItemType.POTION && itemType !== ItemType.EQUIPABLE && (
        <ToolTipDefaultItem item={item} />
      )}
    </>
  );
});

export default InventoryToolTipDisplay;
