import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { getToolDataFromId, toolWithHighestMultiplier } from "../../../data/skillsData/ToolsUtils";

import { SkillsId } from "../../../data/skillsData/SkillsEnum.ts";

export function recalculateMultipliersForSkill(skills: PlayerData["skills"][SkillsId]) {
  const defaultMultipliers = {
    currentSpeedMultiplier: 1,
    currentLootMultiplier: 1,
    currentXpMultiplier: 1,
  };
  const newTools = skills.toolIds || [];
  const toolWithHighestMultiplierId = toolWithHighestMultiplier(newTools);
  if (!toolWithHighestMultiplierId) return defaultMultipliers;
  const toolInfo = getToolDataFromId(toolWithHighestMultiplierId);
  if (!toolInfo) return defaultMultipliers;
  const currentSpeedMultiplier = toolInfo.effect.speedMultiplier ?? 1;
  const currentLootMultiplier = toolInfo.effect.lootMultiplier ?? 1;
  const currentXpMultiplier = toolInfo.effect.xpMultiplier ?? 1;

  return {
    currentSpeedMultiplier,
    currentLootMultiplier,
    currentXpMultiplier,
  };
}
