import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";

type ChangeSlayerPointsAction = {
  points: number;
};

export function changeSlayerPoints(
  state: PlayerData,
  action: ChangeSlayerPointsAction,
): PlayerData {
  const { points } = action;
  const currentPoints = state.slayerInfo.slayerPoints;

  return {
    ...state,
    slayerInfo: {
      ...state.slayerInfo,
      slayerPoints: currentPoints + points,
    },
  };
}
