import { SkillsId } from "../../../data/skillsData/SkillsEnum.ts";
import skillChooser from "../../../data/skillsData/skillsChooser.ts";
import { numberWithCommas } from "../../util/Formatter/NumberFormatter.tsx";
import ImageWithTooltip from "../ToolTip/ImageWithTooltip.tsx";

type XpGainDisplayProps = {
  skillId: SkillsId;
  xpValue: number;
  currentXpMultiplier?: number;
};

const XpGainDisplay = ({ skillId, xpValue }: XpGainDisplayProps) => {
  const icon = skillChooser[skillId]?.icon;
  const skillName = skillChooser[skillId]?.name;
  return (
    <div key={skillId} className="flex gap-1 items-center justify-center ">
      <ImageWithTooltip tooltipText={skillName} className={"w-6 max-h-6 object-contain "} icon={icon} />
      <p className="whitespace-nowrap text-lg leading-none text-green-500  ">
        <span>+</span>
        {numberWithCommas({ amount: Math.floor(xpValue) })}
        <span className="text-xs">XP</span>
      </p>
    </div>
  );
};

export default XpGainDisplay;
