import {
  CompletedQuestsType,
  LongTermProcesses,
  RunsSlotsPlayerInfo,
  SkillsMapType,
  ValidRunStatusTypes,
} from "../../data/AllTypes/PlayerDataTypes.ts";
import { areQuestsCompleted, isSkillLevelRequirementMet } from "./QuestUtils.tsx";
import ErrorToasterWithEvent from "../UtilityComponents/Toasts/ErrorToasterWithEvent";
import React from "react";
import skillChooser from "../../data/skillsData/skillsChooser.ts";
import skillsChooser from "../../data/skillsData/skillsChooser.ts";
import { RunConfig, RunIds } from "../../data/Runs/AllRunsData.ts";
import { AddToastFunctionType } from "../../Context/ToastManagerContext.tsx";
import { SkillsId } from "../../data/skillsData/SkillsEnum.ts";

export const isRunSlotAvailableAndWhatIndex = (
  currentLongTermProcesses: LongTermProcesses | null,
  skills: SkillsMapType,
  completedQuests: CompletedQuestsType,
  runId: RunIds,
  addToast: AddToastFunctionType,
  e: React.MouseEvent | undefined,
): number => {
  const staticSlotConfigs = RunConfig[runId]?.slots || [];

  for (let index = 0; index < Object.keys(staticSlotConfigs).length; index++) {
    const staticSlot = staticSlotConfigs[index];
    const runSlots = currentLongTermProcesses?.[runId];
    const slot = runSlots?.[index] ?? null;

    const slotAvailable = !slot || (!isRunInProgress(slot) && !isRunCompletedButRewardNotTaken(slot));

    if (
      slotAvailable &&
      isSkillLevelRequirementMet(skills, staticSlot?.skillReq) &&
      areQuestsCompleted(completedQuests, staticSlot?.questReq)
    ) {
      return index;
    }
  }

  addToast(<ErrorToasterWithEvent message="No more slot available" mouseEvent={e} />, 1000);
  return -1;
};

export const areRunsInProgressOrCompletedWithRewardNotTaken = (runs: LongTermProcesses | null): boolean => {
  if (!runs) return false;

  for (const run of Object.values(runs)) {
    for (const slot of Object.values(run)) {
      if (isRunInProgress(slot) || isRunCompletedButRewardNotTaken(slot)) {
        return true;
      }
    }
  }

  return false;
};

export const getCompletedRunsCountForTab = (
  currentLongTermProcesses: LongTermProcesses | null,
  skillId: SkillsId,
  tabIndex: number,
): number => {
  const tab = skillsChooser[skillId]?.tabs?.[tabIndex];
  const runId = tab?.runId;

  if (!currentLongTermProcesses || !runId) return 0;

  const runs = currentLongTermProcesses[runId];
  if (!runs) return 0;

  return Object.values(runs).filter((run) => isRunCompletedButRewardNotTaken(run)).length;
};

export const getCompletedRunsCountForSkill = (
  currentLongTermProcesses: LongTermProcesses | null,
  skillId: SkillsId,
): number | null => {
  const tabs = skillChooser[skillId]?.tabs;
  if (!tabs) {
    return null;
  }
  let totalCompletedRuns = 0;

  tabs.forEach((tab, index) => {
    if (tab.runId) {
      totalCompletedRuns += getCompletedRunsCountForTab(currentLongTermProcesses, skillId, index);
    }
  });

  return totalCompletedRuns;
};

export const isRunInProgress = (slot: RunsSlotsPlayerInfo | null): boolean => {
  if (!slot) return false;
  return slot.status === ValidRunStatusTypes.InProgress;
};

export const isRunCompletedButRewardNotTaken = (slot: RunsSlotsPlayerInfo | null): boolean => {
  if (!slot) return false;
  return slot.status === ValidRunStatusTypes.CompletedRewardPending;
};

export const isRunCompleted = (slot: RunsSlotsPlayerInfo | null): boolean => {
  if (!slot) return false;
  return slot.status === ValidRunStatusTypes.Completed;
};

export const getAllAvailableRunSlots = (
  currentLongTermProcesses: LongTermProcesses | null,
  skills: SkillsMapType,
  completedQuests: CompletedQuestsType,
  runId: RunIds,
): number[] => {
  const currentRunSlots = currentLongTermProcesses?.[runId] || [];
  const staticSlots = RunConfig[runId];
  return Object.values(staticSlots.slots)
    .map((requirements, index) => {
      const slot = currentRunSlots[index];
      const skillOk = isSkillLevelRequirementMet(skills, requirements?.skillReq);
      const questOk = areQuestsCompleted(completedQuests, requirements?.questReq);
      return skillOk && questOk && !slot ? index : null;
    })
    .filter((index): index is number => index !== null);
};
