import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { ContractDifficultyIds } from "../../../data/utilData/ClueData/ClueScrollTypes.ts";

type Action = {
  difficulty: ContractDifficultyIds;
  clueMultiplier: number;
};

export function completeClue(state: PlayerData, action: Action): PlayerData {
  const { difficulty, clueMultiplier } = action;
  if (!state.clues || !state.clues[difficulty]) return state;
  const currentClue = state.clues[difficulty];
  if (!currentClue) return state;

  const totalClues = {
    ...state.totalClues,
    [difficulty]: (state.totalClues?.[difficulty] ?? 0) + clueMultiplier,
  };
  return {
    ...state,
    clues: {
      ...state.clues,
      [difficulty]: {
        ...currentClue,
        isCompleted: true,
      },
    },
    totalClues,
  };
}
