import { MonsterIds } from "../MonsterData/MonsterIds.ts";
import { QuestIds } from "../Quest/QuestIds.ts";
import { DiaryIds } from "../AchievementDiaries/DiaryTypes.ts";
import { Difficulty } from "./DiaryTypes.ts";
import { ResourceIds } from "../skillsData/ResourceIds.ts";
import { SkillsId } from "../skillsData/SkillsEnum.ts";

/**
 * Enum defining the different types of shortcuts available
 */
export enum ShortcutType {
  MONSTER = "MONSTER",
  QUEST = "QUEST",
  DIARY = "DIARY",
  RESOURCE = "RESOURCE",
  SKILL = "SKILL",
}

export interface BaseShortcut {
  id: string; // Unique identifier for the shortcut (for drag and drop)
  type: ShortcutType;
  order: number; // Order in the list (for drag and drop)
}

/**
 * Monster shortcut - navigates to a specific monster
 */
export interface MonsterShortcut extends BaseShortcut {
  type: ShortcutType.MONSTER;
  monsterId: MonsterIds;
}

/**
 * Quest shortcut - navigates to a specific quest
 */
export interface QuestShortcut extends BaseShortcut {
  type: ShortcutType.QUEST;
  questId: QuestIds;
}

/**
 * Diary shortcut - navigates to a specific diary with difficulty
 */
export interface DiaryShortcut extends BaseShortcut {
  type: ShortcutType.DIARY;
  diaryId: DiaryIds;
  difficulty: Difficulty;
}

/**
 * Resource shortcut - navigates to a specific resource/process
 */
export interface ResourceShortcut extends BaseShortcut {
  type: ShortcutType.RESOURCE;
  resourceId: ResourceIds;
}

/**
 * Skill shortcut - navigates to a skill page
 */
export interface SkillShortcut extends BaseShortcut {
  type: ShortcutType.SKILL;
  skillId: SkillsId | "Combat";
}

/**
 * Discriminated union type for all shortcut types
 * This allows TypeScript to narrow the type based on the 'type' field
 */
export type Shortcut = MonsterShortcut | QuestShortcut | DiaryShortcut | ResourceShortcut | SkillShortcut;

/**
 * Type guard functions to check shortcut types
 */
export const isMonsterShortcut = (shortcut: Shortcut): shortcut is MonsterShortcut => {
  return shortcut.type === ShortcutType.MONSTER;
};

export const isQuestShortcut = (shortcut: Shortcut): shortcut is QuestShortcut => {
  return shortcut.type === ShortcutType.QUEST;
};

export const isDiaryShortcut = (shortcut: Shortcut): shortcut is DiaryShortcut => {
  return shortcut.type === ShortcutType.DIARY;
};

export const isResourceShortcut = (shortcut: Shortcut): shortcut is ResourceShortcut => {
  return shortcut.type === ShortcutType.RESOURCE;
};

export const isSkillShortcut = (shortcut: Shortcut): shortcut is SkillShortcut => {
  return shortcut.type === ShortcutType.SKILL;
};



