import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";

type ChangeSlayerStreakAction = {
  streak: number;
};

export function changeSlayerStreak(
  state: PlayerData,
  action: ChangeSlayerStreakAction,
): PlayerData {
  const { streak } = action;
  const currentStreak = state.slayerInfo.slayerStreak;

  return {
    ...state,
    slayerInfo: {
      ...state.slayerInfo,
      slayerStreak: currentStreak + streak,
    },
  };
}
