type ErrorToasterProps = {
  message: string;
};

function ErrorToaster({ message }: ErrorToasterProps) {
  return (
    <div className="toaster text-red-500  fixed left-0 bottom-10 z-[50] pointer-events-none flex justify-center w-full animateSlideUpError">
      {message}
    </div>
  );
}

export default ErrorToaster;
