import { MonsterIdDictionary } from "../../../data/AllTypes/AttackStyleAndWeaponTypes.ts";
import { MonsterIds } from "../../../data/MonsterData/MonsterInfoUtil.ts";

export function getMonsterKillCount(
  monsterKillStats: MonsterIdDictionary | undefined | null,
  monsterId: MonsterIds | null | undefined,
): number {
  if (!monsterKillStats || !monsterId) return 0;
  return monsterKillStats[monsterId]?.killCount ?? 0;
}

export function getPaddingTopImg(monsterHp: number) {
  return monsterHp < 180 ? "pt-12" : monsterHp < 700 ? "pt-6" : monsterHp < 5000 ? "pt-4" : "";
}
