import { getUnlimitedRunesFromEquipment } from "../../Components/util/CombatUtils/getUnlimitedRunesFromEquipment.ts";
import { checkItemCostInInventory } from "../../Components/util/ResourceUtils.tsx";
import {
  EquippedItemsSetType,
  ItemDataByReference,
  playerItemsType,
} from "../../data/AllTypes/PlayerDataTypes.ts";
import { useMemo } from "react";
import { createDeepMemoizedCheckCostSelector, usePlayerStore } from "../../Context/usePlayerStore.ts";

export const calculateItemCostCheck = (
  items: playerItemsType,
  equippedSet: EquippedItemsSetType,
  itemCost: ItemDataByReference[] | null | undefined,
  currentLootMultiplier: number,
): boolean => {
  if (!itemCost || itemCost.length === 0) {
    return true;
  }
  // 1. Get exclusion list
  const excludeItems = getUnlimitedRunesFromEquipment(equippedSet);

  // 2. Perform the main check
  return checkItemCostInInventory(itemCost, items, currentLootMultiplier, excludeItems);
};

export const useCheckItemCostDynamic = (
  itemCost: ItemDataByReference[] | null | undefined,
  currentLootMultiplier = 1,
): boolean => {
  // Use React's useMemo to cache the selector function itself, based on the dynamic arguments.
  const memoizedSelector = useMemo(
    () => createDeepMemoizedCheckCostSelector(itemCost, currentLootMultiplier),
    [itemCost, currentLootMultiplier],
  );
  return usePlayerStore((store) => memoizedSelector(store.state));
};
