import { PlayerData } from "../../data/AllTypes/PlayerDataTypes.ts";
import { InventoryItemsData } from "../../data/AllTypes/SkillsSpecificTypes.ts";
import { DEFAULT_BANK_SLOT_SIZE } from "../../data/Constants.ts";

type depositToBankAction = {
  items: InventoryItemsData;
};

export function depositToBank(state: PlayerData, action: depositToBankAction): PlayerData {
  const { items } = action;

  let newBank = [...state.items.bank];
  const totalBankSlots = DEFAULT_BANK_SLOT_SIZE + (state.extraBankSlots ?? 0);
  if (newBank.length < totalBankSlots) {
    // Expand bank to match the correct size
    newBank = [...newBank, ...Array(totalBankSlots - newBank.length).fill(null)];
  } else if (newBank.length > totalBankSlots) {
    // Shrink bank by removing only excess null slots
    const nonNullItems = newBank.filter((item) => item !== null);
    const nullSlotsToKeep = totalBankSlots - nonNullItems.length;

    // Ensure we keep enough null slots to match totalBankSlots
    newBank = [...nonNullItems, ...Array(nullSlotsToKeep).fill(null)];
  }

  items.forEach((item) => {
    // Skip if the item or its name is null
    if (item === null || item.id === null) return;

    // Find the index of the existing item in the bank
    const existingItemIndex = newBank.findIndex((bankItem) => bankItem && bankItem.id === item.id);

    // If the item exists, update its amount
    if (existingItemIndex !== -1) {
      const existingItem = newBank[existingItemIndex];
      if (existingItem) {
        newBank[existingItemIndex] = {
          ...existingItem,
          amount: existingItem.amount + item.amount,
        };
      }
    } else {
      // If the item does not exist, find an empty slot and add the item
      const emptySlotIndex = newBank.findIndex((item) => item === null);
      if (emptySlotIndex !== -1) {
        newBank[emptySlotIndex] = { ...item };
      }
    }
  });

  // Return the updated state with the new bank
  return {
    ...state,
    items: {
      ...state.items,
      bank: newBank,
    },
  };
}
