import { PlayerData } from "../../data/AllTypes/PlayerDataTypes.ts";
import { Difficulty, ValidDiaryStatus } from "../../data/AllTypes/DiaryTypes.ts";
import { getDiaryObject } from "../../Components/util/DiaryUtils.tsx";
import { DiaryIds } from "../../data/AchievementDiaries/DiaryTypes.ts";

type DiaryAction = {
  diaryId: DiaryIds;
  difficulty: Difficulty;
};

export function diaryCompleted(state: PlayerData, action: DiaryAction): PlayerData {
  const { diaryId, difficulty } = action;

  // Check if the diary entry exists
  const diaryObject = getDiaryObject(state.completedAchievementDiary, diaryId);

  // If the diary object exists, update the existing entry
  if (diaryObject) {
    return {
      ...state,
      completedAchievementDiary: {
        ...state.completedAchievementDiary,
        [diaryId]: {
          ...diaryObject,
          [difficulty]: ValidDiaryStatus.CompletedRewardPending,
        },
      },
    };
  }

  // If the diary object doesn't exist, create a new entry
  return {
    ...state,
    completedAchievementDiary: {
      ...state.completedAchievementDiary,
      [diaryId]: {
        [difficulty]: ValidDiaryStatus.CompletedRewardPending,
      },
    },
  };
}
