import { PlayerData } from "../../data/AllTypes/PlayerDataTypes.ts";
import { SteamAchievementId } from "../../data/Constants.ts";

type addSteamAchievementAction = {
  achievementId: SteamAchievementId;
};
export function addSteamAchievement(state: PlayerData, action: addSteamAchievementAction): PlayerData {
  const { achievementId } = action;
  const currentAchievements = state.steamAchievements || [];
  if (currentAchievements.includes(achievementId)) {
    // Achievement already unlocked
    return state;
  }
  return {
    ...state,
    steamAchievements: [...currentAchievements, achievementId],
  };
}
