import {
  MonsterCompletedDictionary,
  ProcessCompletedDictionary,
  SkillIdNumberDictionary,
} from "./SkillsSpecificTypes.ts";
import { DiaryIds, ValidDiaryIds } from "../AchievementDiaries/DiaryTypes.ts";
import { SkillsId } from "../skillsData/SkillsEnum.ts";
import { ItemDataByReference } from "./PlayerDataTypes.ts";
import { QuestIds } from "../Quest/QuestIds.ts";

export type AchievementDiaryObject = {
  name: string;
  id: DiaryIds;
  iconSmall: string;
  iconBig: string;
  associatedSkill: SkillsId[]; // SkillsId
  diaryInfo: Record<Difficulty, AchievementDiary>;
};

export type AchievementDiary = {
  itemRewards: ItemDataByReference[];
  difficulty: Difficulty;
  skillReq?: SkillIdNumberDictionary;
  processReq: ProcessCompletedDictionary;
  monsterReq: MonsterCompletedDictionary;
  questReq?: QuestIds[];
  combatLevelRequired?: number;
};

export enum Difficulty {
  EASY = "EASY",
  MEDIUM = "MEDIUM",
  HARD = "HARD",
  EXPERT = "EXPERT",
  NERD = "NERD",
}

export enum ValidDiaryStatus {
  CompletedRewardPending = "Completed, Reward Pending",
  Completed = "Completed",
}
export type AchievementDiaryData = Record<Difficulty, ValidDiaryStatus>;

export type CompletedAchievementDiary = Partial<Record<ValidDiaryIds, AchievementDiaryData>>;
