import { ItemPrices } from "../../data/AllShopsData/AllItemPrices.ts";
import { SELL_PERCENTAGE } from "../../data/Constants.ts";
import { ItemIds } from "../../data/ItemData/AllItemsIds.ts";

export const getSellPrice = (itemId: ItemIds | null | undefined): number => {
  if (itemId) {
    const defaultPriceIfNoDynamicPrice = Math.floor(ItemPrices[itemId] * SELL_PERCENTAGE);
    return defaultPriceIfNoDynamicPrice ?? 0;
  }
  return 0;
};

export const getBuyPrice = (itemId: ItemIds | null | undefined): number => {
  return itemId ? (ItemPrices[itemId] ?? 0) : 0;
};
