import React, { createContext, ReactNode, useContext, useState } from "react";
import { useNavigate } from "react-router-dom";
import { useTokenRefresh } from "../hooks/Auth/useTokenRefresh.ts";
import { useAuthStore } from "../hooks/Auth/useAuthToken.ts";
import { useHandleApiError } from "../hooks/Auth/useHandleApiError.tsx";
import { ACCOUNT_OVERVIEW_URL, LOGIN_URL } from "../data/Constants.ts";
import { LoginResponse, useLoginSteamAuto, useLoginUser } from "../hooks/DatabaseSearch/useLoginUser.ts";

type SteamCredential = {
  ticket: string;
  appId: number;
};
interface AuthContextType {
  login: (credential: string | SteamCredential, method: LoginMethod) => void;
  logout: () => void;
  setLoading: (loading: boolean) => void;
  loading: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const useAuth = (): AuthContextType => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
};

interface AuthProviderProps {
  children: ReactNode;
}
type LoginMethod = "google" | "steam";

export const AuthProvider: React.FC<AuthProviderProps> = ({ children }) => {
  const navigate = useNavigate();
  const { isLoggedIn, saveAuth, clearAuth } = useAuthStore();
  const { handleApiError } = useHandleApiError();
  const [loading, setLoading] = useState<boolean>(false);
  const googleLoginMutation = useLoginUser();
  const steamLoginAutoMutation = useLoginSteamAuto();

  const login = async (credential: string | SteamCredential, method: LoginMethod = "google") => {
    setLoading(true);
    try {
      let data: LoginResponse;
      if (method === "google") {
        data = await googleLoginMutation.mutateAsync({ token: credential as string });
      } else {
        const { ticket, appId } = credential as SteamCredential;
        data = await steamLoginAutoMutation.mutateAsync({
          ticket,
          appId,
        });
      }
      saveAuth({
        accessToken: data.accessToken,
        refreshToken: data.refreshToken,
        userId: data.userId,
      });
      navigate(ACCOUNT_OVERVIEW_URL);
    } catch (error) {
      handleApiError(error, "Failed to save data to cloud");
    } finally {
      setLoading(false);
    }
  };

  const logout = () => {
    navigate(LOGIN_URL);
    clearAuth();
  };

  useTokenRefresh(isLoggedIn, logout);
  return (
    <AuthContext.Provider
      value={{
        login,
        setLoading,
        logout,
        loading,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
};
