import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";

type ChangeHealthRestoreMultiplierAction = {
  healthRestoreMultiplier: number; // New multiplier value
};

export function changeHealthRestoreMultiplier(
  state: PlayerData,
  action: ChangeHealthRestoreMultiplierAction,
): PlayerData {
  const { healthRestoreMultiplier } = action;
  const now = Date.now();

  // Calculate the elapsed time since the last health restoration
  const elapsedTimeSinceLastRestore =
    now - (state.healthInfo.nextHealthRestoreTime - state.healthInfo.healthRestoreBaseInterval);

  // Determine how much of the interval had passed, as a fraction, with the old multiplier
  const fractionOfIntervalPassed =
    elapsedTimeSinceLastRestore /
    (state.healthInfo.healthRestoreBaseInterval / state.healthInfo.healthRestoreMultiplier);

  // Adjust the remaining time for the next restoration using the new multiplier
  const adjustedRemainingTime =
    (1 - fractionOfIntervalPassed) * (state.healthInfo.healthRestoreBaseInterval / healthRestoreMultiplier);

  // Calculate the new next restore time
  const newNextRestoreTime = now + adjustedRemainingTime;

  return {
    ...state,
    healthInfo: {
      ...state.healthInfo,
      healthRestoreMultiplier: healthRestoreMultiplier,
      nextHealthRestoreTime: newNextRestoreTime,
    },
  };
}
