import { ItemDataByReference } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { SkillIdNumberDictionary } from "../../../data/AllTypes/SkillsSpecificTypes.ts";
import ToasterItemGainAndCost from "./ToasterItemGainAndCost.tsx";
import XpGainDisplays from "../UIDisplays/XpGainDisplays.tsx";
import React from "react";
import FloatingToast from "./FloatingToast.tsx";

type ToasterWithEventProps = {
  xp: SkillIdNumberDictionary | null;
  itemGain: ItemDataByReference[] | null | undefined;
  itemCost: ItemDataByReference[] | null | undefined;
  mouseEvent: React.MouseEvent | undefined;
};

const ToasterWithEvent = ({ xp, itemGain, itemCost, mouseEvent }: ToasterWithEventProps) => {
  return (
    <FloatingToast mouseEvent={mouseEvent}>
      <XpGainDisplays xp={xp} />
      <ToasterItemGainAndCost itemGain={itemGain} itemCost={itemCost} hideTooltip={true} />
    </FloatingToast>
  );
};

export default ToasterWithEvent;
