export const getShiningClassBasedOnProbability = (probability: number | null | undefined) => {
  if (!probability) return "shining-green";
  if (probability <= 0.001) {
    return "shining-dark-red";
  } else if (probability > 0.001 && probability <= 0.01) {
    return "shining-red";
  } else if (probability > 0.01 && probability <= 0.04) {
    return "shining-yellow";
  } else {
    return "shining-green";
  }
};
