import { SkillIdNumberDictionary } from "../../../data/AllTypes/SkillsSpecificTypes.ts";
import { CurrentPotionType, PotionItemType, SkillsMapType } from "../../../data/AllTypes/PlayerDataTypes.ts";

import { SkillsId } from "../../../data/skillsData/SkillsEnum.ts";
import { ItemIds } from "../../../data/ItemData/AllItemsIds.ts";

export const calcBoost = (
  skills: SkillsMapType,
  potion: PotionItemType | null,
): SkillIdNumberDictionary | null => {
  if (!potion || !potion.statBoost) return null;

  let newBoostedLevelObject: SkillIdNumberDictionary = {};
  for (const skillKey of Object.keys(potion.statBoost || {}) as unknown as SkillsId[]) {
    const { level } = skills[skillKey];
    const boostInfo = potion.statBoost[skillKey];

    if (boostInfo) {
      const { baseBoost, percentBoost } = boostInfo;
      let totalBoost = baseBoost;
      if (percentBoost !== undefined) {
        const totalBoostFromPercentBoost = Math.floor(level * percentBoost);
        totalBoost = baseBoost + totalBoostFromPercentBoost;
      }

      const newBoostedLevel = totalBoost;

      newBoostedLevelObject = {
        ...newBoostedLevelObject,
        [skillKey]: newBoostedLevel,
      };
    }
  }
  return newBoostedLevelObject;
};

