/**
 * Returns the potion ID and timestamp of the next potion to expire,
 * excluding a specific potion ID if provided.
 * If no valid potions are active, returns null.
 */
export const getNextExpiringPotion = (
  potionsWithDurations: CurrentPotionType,
  excludeId?: ItemIds | null,
): { potionId: ItemIds; remainingSeconds: number } | null => {
  if (!potionsWithDurations || Object.keys(potionsWithDurations).length === 0) {
    return null;
  }

  // Filter out excluded or invalid potions
  const validPotions = Object.entries(potionsWithDurations).filter(
    ([id, remaining]) => id !== String(excludeId) && typeof remaining === "number" && remaining > 0,
  );

  if (validPotions.length === 0) return null;

  // Find the potion with the smallest remaining duration (expires soonest)
  const [nextPotionId, nextPotionDuration] = validPotions.reduce((earliest, current) =>
    current[1] < earliest[1] ? current : earliest,
  );

  return {
    potionId: Number(nextPotionId) as ItemIds,
    remainingSeconds: nextPotionDuration,
  };
};
