import { arrow, autoUpdate, flip, FloatingArrow, offset, shift, useFloating } from "@floating-ui/react";
import { useEffect, useRef, useState } from "react";
import { BG_COLOR } from "../../../data/Constants.ts";

type TooltipProps = {
  children: React.ReactNode;
  content: React.ReactNode | undefined;
  placement?: "top" | "right" | "bottom" | "left";
  tooltipClassName?: string;
  className?: string;
  delay?: number;
};
let lastTooltipTime = 0;

const TooltipWrapper = ({
  children,
  content,
  placement = "top",
  tooltipClassName = "",
  className,
  delay = 200,
}: TooltipProps) => {
  const [open, setOpen] = useState(false);
  const timeoutRef = useRef<number | null>(null);
  const arrowRef = useRef<SVGSVGElement | null>(null);

  const { refs, floatingStyles, update, context } = useFloating({
    placement,
    middleware: [
      offset(12), // adjust to match arrow height + gap
      flip(),
      shift({ padding: 5 }),
      arrow({ element: arrowRef }),
    ],
    whileElementsMounted: autoUpdate,
  });

  useEffect(() => {
    if (open) {
      update();
    }
  }, [open, update]);

  const getAdjustedDelay = () => {
    const timeSinceLast = Date.now() - lastTooltipTime;
    return timeSinceLast < 1000 ? 0 : delay;
  };

  const show = () => {
    const adjustedDelay = getAdjustedDelay();
    timeoutRef.current = window.setTimeout(() => {
      lastTooltipTime = Date.now();
      setOpen(true);
    }, adjustedDelay);
  };

  const hide = () => {
    if (timeoutRef.current) {
      clearTimeout(timeoutRef.current);
    }
    setOpen(false);
  };

  return (
    <>
      <span
        className={`w-full relative ${className}`}
        ref={refs.setReference}
        onMouseEnter={show}
        onMouseLeave={hide}
        onFocus={show}
        onBlur={hide}
      >
        {children}
      </span>

      {open && content && (
        <div
          ref={refs.setFloating}
          style={floatingStyles}
          className={`z-[1000] bg-bgColor whitespace-nowrap leading-none h-fit text-orangeColor border border-black text-xs px-2 py-1 rounded shadow-md transition-opacity duration-150 ${tooltipClassName}`}
        >
          <FloatingArrow
            ref={arrowRef}
            context={context}
            fill={BG_COLOR}
            stroke="black"
            strokeWidth={1}
            height={7}
            width={14}
            className="z-[-1]"
          />
          {content}
        </div>
      )}
    </>
  );
};
export default TooltipWrapper;
