import { ReactNode, useRef } from "react";
import { useLocation } from "react-router-dom"; // <-- to detect current path
import { useDeviceType } from "../hooks/useDeviceType.tsx";
import forestBgMobile from "../assets/backgrounds/forest.webp";
import mineBgMobile from "../assets/backgrounds/mine.webp";

type LoginLayoutProps = {
  children: ReactNode;
};

const LoginLayout = ({ children }: LoginLayoutProps) => {
  const { isMobile, isTablet } = useDeviceType();
  const containerRef = useRef<HTMLDivElement>(null);
  const location = useLocation();
  // const navigate = useNavigate();

  // Check if we're on the login page
  const isLoginPage = location.pathname === "/login";
  const getBackgroundImage = (isLoginPage: boolean) => {
    if (isLoginPage) return mineBgMobile;
    if (!isLoginPage) return forestBgMobile;
  };
  const backgroundImage = getBackgroundImage(isLoginPage);
  const backgroundSize = isMobile ? "cover" : isLoginPage ? "150%" : "145%";
  // const backgroundSize = isMobile ? "sm:bg-cover" : isLoginPage ? "150%" : "145%";

  const blackBg = isTablet || isMobile ? "bg-black/80" : "bg-black/50";
  return (
    <div className="grid text-orangeColor select-none   place-items-center flex-col min-h-screen h-full min-w-screen bg-black/90">
      <div className="grid lg:grid-cols-2  relative grid-cols-1 w-full h-full" ref={containerRef}>
        <div
          className={`lg:sticky lg:top-0 lg:block hidden border-r-2 border-black lg:h-screen h-full bg-blend-overlay ${blackBg}`}
          style={{
            ["--bg-image-login" as any]: `url("${backgroundImage}")`,
            backgroundImage: "var(--bg-image-login)",
            backgroundSize: backgroundSize,
            backgroundRepeat: "no-repeat",
            backgroundPosition: "80% 95%",
          }}
        ></div>
        <div className="bg-bgColorSecondary flex flex-col gutter">{children}</div>
      </div>

      {/*</div>*/}
    </div>
  );
};

export default LoginLayout;
