type QuestReqEquipmentToolTipProps = {
  questReq: number[] | undefined;
};
const QuestReqEquipmentToolTip = ({ questReq }: QuestReqEquipmentToolTipProps) => {
  const questReqLength = questReq?.length;
  if (!questReq || !questReqLength || questReqLength === 0) return null;
  const questReqSplice = questReq?.slice(0, 2);

  return (
    <>
      <h2 className="text-red-500 ">Quest Req:</h2>
      {questReqSplice?.map((quest) => <p key={quest}>{quest}</p>)}
      {questReqLength > 2 && <p> + {questReqLength - 2} More...</p>}
    </>
  );
};

export default QuestReqEquipmentToolTip;
