import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { InventoryItemsData } from "../../../data/AllTypes/SkillsSpecificTypes.ts";

type UpdateBankItemsAction = {
  items: InventoryItemsData;
};

export function updateBank(state: PlayerData, action: UpdateBankItemsAction): PlayerData {
  const updatedBank = action.items; // Directly use action.items as updatedBank

  // Return the updated state with the new bank items
  return {
    ...state,
    items: {
      ...state.items,
      bank: updatedBank,
    },
  };
}
