import {
  CurrentMonsterTasks,
  CurrentResourceTasks,
  PlayerData,
} from "../../../data/AllTypes/PlayerDataTypes.ts";
import { ContractDifficultyIds } from "../../../data/utilData/ClueData/ClueScrollTypes.ts";
import { ClueScrollInfoMap } from "../../../data/utilData/ClueData/AllClueScrollData.ts";
import { ResourceIds } from "../../../data/skillsData/ResourceIds.ts";
import { getMonsterKillCount } from "../../../Components/CombatStyle/Monster/MonsterUtils.ts";
import { getProcessCompleted } from "../../../Components/util/LevelUtils/GetProcessCompleted.ts";
import { getRandomElement, getRandomInRange } from "../../../Components/Clue/ClueUtil.ts";
import { getMonsterInfo, MonsterIds } from "../../../data/MonsterData/MonsterInfoUtil.ts";
import { getResourceInfo } from "../../../data/skillsData/skillsChooser.ts";
import { PLACEHOLDER_NAME } from "../../../data/Constants.ts";

type Action = {
  difficulty: ContractDifficultyIds;
  clueMultiplier: number;
};

export function startClue(state: PlayerData, action: Action): PlayerData {
  const { difficulty, clueMultiplier } = action;
  const clueScrollData = ClueScrollInfoMap[difficulty];
  const { taskRolls, monsterTasks, resourceTasks } = clueScrollData;

  const allMonsterIds = (Object.keys(monsterTasks) as unknown as MonsterIds[]).filter((id) => {
    const info = getMonsterInfo(id);
    return info && info.name !== PLACEHOLDER_NAME;
  });
  const allResourceIds = (Object.keys(resourceTasks) as unknown as ResourceIds[]).filter((id) => {
    const info = getResourceInfo(id);
    return info && info.name !== PLACEHOLDER_NAME;
  });
  const selectedMonsterTasks: CurrentMonsterTasks = {};
  const selectedResourceTasks: CurrentResourceTasks = {};

  const totalWeight = allMonsterIds.length + allResourceIds.length;

  for (let i = 0; i < taskRolls; i++) {
    const isMonsterTask = Math.random() * totalWeight < allMonsterIds.length;

    if (isMonsterTask) {
      const id = getRandomElement(allMonsterIds); // allow duplicates
      const task = monsterTasks[id];
      if (!task) continue;
      const { min, max } = task;
      const newMin = min * clueMultiplier;
      const newMax = max * clueMultiplier;
      const randomAmount = getRandomInRange(newMin, newMax);
      const currentAmount = getMonsterKillCount(state.monsterKillStats, id);

      const existing = selectedMonsterTasks[id];

      selectedMonsterTasks[id] = {
        amount: (existing?.amount ?? 0) + randomAmount,
        prev: existing?.prev ?? currentAmount,
      };
    } else {
      const id = getRandomElement(allResourceIds); // allow duplicates
      const task = resourceTasks[id];
      if (!task) continue;
      const { min, max } = task;
      const newMin = min * clueMultiplier;
      const newMax = max * clueMultiplier;
      const randomAmount = getRandomInRange(newMin, newMax);
      const currentAmount = getProcessCompleted(state.processesCompleted, id);

      const existing = selectedResourceTasks[id];

      selectedResourceTasks[id] = {
        amount: (existing?.amount ?? 0) + randomAmount,
        prev: existing?.prev ?? currentAmount,
      };
    }
  }

  const previousClueData = state.clues?.[difficulty] ?? {};
  const previousClues = state.clues ?? {};

  return {
    ...state,
    clues: {
      ...previousClues,
      [difficulty]: {
        ...previousClueData,
        isCompleted: false,
        currentMonsterTasks: selectedMonsterTasks,
        currentResourceTasks: selectedResourceTasks,
        clueMultiplier: clueMultiplier,
      },
    },
  };
}
