import { useMutation } from "@tanstack/react-query";
import { useHandleApiError } from "../Auth/useHandleApiError.tsx";
import axiosInstance from "../../api/axiosInstance.ts";

export const linkGoogleAccount = async (linkCode: string, googleToken: string) => {
  const res = await axiosInstance.post("/api/link/confirm", { linkCode, googleToken });
  return res.data;
};

export const useLinkGoogleAccount = () => {
  const { handleApiError } = useHandleApiError();

  return useMutation({
    mutationFn: ({ linkCode, googleToken }: { linkCode: string; googleToken: string }) =>
      linkGoogleAccount(linkCode, googleToken),
    onError: (err) => handleApiError(err, "Failed to link Google account"),
  });
};
