type SkeletonLoadingFillParentProps = {
  className?: string;
  skeletonType?: "skeleton" | "skeleton-dark" | "skeleton-light";
};
const SkeletonLoadingFillParent = ({ className, skeletonType }: SkeletonLoadingFillParentProps) => {
  return <div className={` w-full h-full   ${skeletonType ?? "skeleton"} ${className}`}></div>;
};

export default SkeletonLoadingFillParent;
