import { PlayerData } from "../../data/AllTypes/PlayerDataTypes.ts";
import { DEFAULT_BANK_SLOT_SIZE } from "../../data/Constants.ts";

type BuyBankSpaceAction = {
  amount: number;
};

export function buyBankSpace(state: PlayerData, action: BuyBankSpaceAction): PlayerData {
  const { amount } = action;

  // Ensure extraBankSlots is properly initialized
  const extraBankSlots = state.extraBankSlots ?? 0;
  const newExtraBankSlots = extraBankSlots + amount;
  const newBankSpace = DEFAULT_BANK_SLOT_SIZE + newExtraBankSlots;

  // Ensure the bank array is correctly expanded to match the new bank space
  const newBank = state.items.bank ? [...state.items.bank] : [];
  while (newBank.length < newBankSpace) {
    newBank.push(null);
  }

  return {
    ...state,
    items: {
      ...state.items,
      bank: newBank,
    },
    extraBankSlots: newExtraBankSlots,
  };
}
