import { useEffect } from "react";
import { useGetShortcuts } from "../../../Context/usePlayerStore.ts";
import { useShortcutNavigation } from "../../../hooks/Navigation/useShortcutNavigation.ts";

export function useKey(
  key: string,
  callback: (e: KeyboardEvent) => void,
  checkInput: boolean = true, // New parameter
  eventType: keyof WindowEventMap = "keydown",
) {
  useEffect(() => {
    const handleKeyEvent = (e: KeyboardEvent) => {
      const isMatch = e.key.toLowerCase() === key.toLowerCase();
      // If checkInput is false, it triggers regardless of focus.
      // If checkInput is true, it only triggers if NOT in an input.
      const shouldTrigger = isMatch && (!checkInput || !isInInputField());

      e.stopPropagation();
      if (shouldTrigger) {
        callback(e);
      }
    };
    window.addEventListener(eventType, handleKeyEvent as EventListener);
    return () => window.removeEventListener(eventType, handleKeyEvent as EventListener);
  }, [key, callback, checkInput, eventType]);
}
export const useShortcutKeyBindings = () => {
  const shortcuts = useGetShortcuts();
  const { navigateToShortcut } = useShortcutNavigation();

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Ignore if typing in input/textarea
      if (isInInputField()) return;

      // Handle both top-row numbers and numpad
      const match = e.code.match(/^Digit([1-9])$|^Numpad([1-9])$/);
      if (match) {
        const keyNum = Number(match[1] || match[2]); // extract the pressed number (1–5)
        const shortcut = shortcuts?.find((s) => s.order === keyNum - 1);
        if (shortcut) {
          navigateToShortcut(shortcut);
          e.preventDefault(); // prevent accidental browser shortcuts
        }
      }
    };

    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [shortcuts, navigateToShortcut]);
};

export const isInInputField = () => {
  const el = document.activeElement;
  if (!el) return false;

  const tag = el.tagName;
  const type = (el as HTMLInputElement).type;

  // All elements where typing should NOT trigger shortcuts
  const blockedTags = ["INPUT", "TEXTAREA", "SELECT"];
  if (blockedTags.includes(tag)) return true;

  // Extra: contenteditable divs
  if ((el as HTMLElement).isContentEditable) return true;

  // Extra: input types where shortcuts should not fire
  const blockedTypes = ["text", "number", "email", "password", "search", "tel", "url"];
  if (tag === "INPUT" && blockedTypes.includes(type)) return true;

  return false;
};
