import {
  AutoCombatIds,
  ItemDataByReference,
  ItemDataWithSource,
  playerItemsType,
} from "../../../data/AllTypes/PlayerDataTypes.ts";
import { CONTAINERS_CONFIG, hasExtraStorageInInventory } from "../ExtraStorageUtils/ExtraStorageUtils.tsx";
import { InventoryItemsData } from "../../../data/AllTypes/SkillsSpecificTypes.ts";
import { SlayerBuyIds } from "../../../data/Slayer/SlayerBuys.ts";

import { ItemIds } from "../../../data/ItemData/AllItemsIds.ts";
import { AllFoodItemsIds } from "../../../data/ItemData/food/AllFoodItems.ts";
import { AllPotionItems } from "../../../data/ItemData/potions/AllPotionItems.ts";

export type autoCombatConfigValues = {
  capacity: number;
  allowedItems: ItemIds[];
  unlockKey: SlayerBuyIds;
  name: string;
  id: AutoCombatIds;
};
export const AUTO_COMBAT_CONFIG: Record<AutoCombatIds, autoCombatConfigValues> = {
  [AutoCombatIds.Food]: {
    capacity: 1,
    allowedItems: AllFoodItemsIds,
    unlockKey: SlayerBuyIds.AUTO_EAT,
    name: "Food",
    id: AutoCombatIds.Food,
  },
  [AutoCombatIds.Boost]: {
    capacity: 1,
    allowedItems: AllPotionItems,
    unlockKey: SlayerBuyIds.AUTO_POTION_BOOST,
    name: "Boost",
    id: AutoCombatIds.Boost,
  },
};

export const getToolTipText = (autoCombatId: AutoCombatIds, eatAt?: number): string => {
  const tooltipFood = `Auto eat when at ${eatAt ?? 0}hp or below`;
  const tooltipBoost = `Auto use potions when its about to expire`;
  switch (autoCombatId) {
    case AutoCombatIds.Food:
      return tooltipFood;
    case AutoCombatIds.Boost:
      return tooltipBoost;
  }
};

export const itemsThatAlreadyExistInInventory = (
  items: playerItemsType,
  itemsToGet: ItemDataWithSource[],
): ItemDataByReference[] => {
  const itemsToGoToInventory: ItemDataByReference[] = [];

  const itemsToLookAt = allItemsToConsider(items);

  // ✅ Add items to `itemsToGoToInventory` if they already exist in `itemsToLookAt`
  for (const itemToGet of itemsToGet) {
    if (itemsToLookAt.some((existingItem) => existingItem?.id === itemToGet.id)) {
      itemsToGoToInventory.push(itemToGet);
    }
  }

  return itemsToGoToInventory;
};

export const allItemsToConsider = (items: playerItemsType): InventoryItemsData => {
  const result: InventoryItemsData = [...items.inventory]; // always include inventory

  for (const [storageId, config] of Object.entries(CONTAINERS_CONFIG)) {
    const containerKey = storageId as keyof playerItemsType;
    const unlockItemId = config.unlockItemId;

    if (hasExtraStorageInInventory(items.inventory, unlockItemId)) {
      const containerItems = items[containerKey];
      if (Array.isArray(containerItems)) {
        result.push(...containerItems);
      }
    }
  }

  return result;
};

export const isItemsInInventory = (items: playerItemsType, itemsToCheck: ItemDataByReference[]): boolean => {
  const itemsToLookAt = allItemsToConsider(items);
  return itemsToCheck.every((item) =>
    itemsToLookAt.some((existingItem) => existingItem?.id === item.id && existingItem.amount >= item.amount),
  );
};

export const isItemInInventory = (items: playerItemsType, item: ItemDataByReference): boolean => {
  const itemsToLookAt = allItemsToConsider(items);
  const isEnoughOfItemInInventory = itemsToLookAt.some(
    (existingItem) => existingItem?.id === item.id && existingItem.amount >= item.amount,
  );
  return isEnoughOfItemInInventory;
};

export const itemsFromBankToInventory = (
  bank: InventoryItemsData,
  itemsToGet: ItemDataByReference[],
): ItemDataByReference[] => {
  const itemsToGoToInventory: ItemDataByReference[] = [];

  // ✅ Add items to `itemsToGoToInventory` if they already exist in `bank`
  for (const itemToGet of itemsToGet) {
    if (bank.some((existingItem) => existingItem?.id === itemToGet.id)) {
      itemsToGoToInventory.push(itemToGet);
    }
  }

  return itemsToGoToInventory;
};

export const removeItemsFromList = (
  allItems: ItemDataWithSource[],
  itemsToRemove: ItemDataByReference[],
): ItemDataWithSource[] => {
  // Extract only names from itemsToRemove
  const idsToRemove = itemsToRemove.map((item) => item.id);

  // Filter out items that exist in namesToRemove
  return allItems.filter((item) => !idsToRemove.includes(item.id));
};

export const getItemsStillNeeded = (
  items: playerItemsType,
  requiredItems: ItemDataByReference[],
): ItemDataByReference[] => {
  const inventory = allItemsToConsider(items);
  return requiredItems
    .map((requiredItem) => {
      const inventoryItem = inventory.find((invItem) => invItem?.id === requiredItem.id);
      if (inventoryItem) {
        const remainingAmount = requiredItem.amount - inventoryItem.amount;
        return remainingAmount > 0 ? { ...requiredItem, amount: remainingAmount } : null;
      }
      return requiredItem;
    })
    .filter((item): item is ItemDataByReference => item !== null);
};
export const canWithdrawFromBank = (
  itemsStillNeeded: ItemDataByReference[],
  bankItems: InventoryItemsData,
  shouldBeHigherThanOne: boolean,
): boolean => {
  const amount = shouldBeHigherThanOne ? 1 : 0;
  return itemsStillNeeded.some((neededItem) =>
    bankItems?.some((bankItem) => bankItem?.id === neededItem.id && bankItem?.amount > amount),
  );
};

export const getItemsToWithdraw = (
  bankItems: InventoryItemsData,
  itemsStillNeeded: ItemDataByReference[],
): ItemDataByReference[] => {
  return itemsStillNeeded
    .map((neededItem) => {
      const bankItem = bankItems.find((bItem) => bItem?.id === neededItem.id);
      if (bankItem) {
        const withdrawAmount = Math.min(bankItem.amount, neededItem.amount);
        return withdrawAmount > 0 ? { ...neededItem, amount: withdrawAmount } : null;
      }
      return null;
    })
    .filter((item): item is ItemDataByReference => item !== null);
};

export const getAllItemsToWithdraw = (
  bankItems: InventoryItemsData,
  requiredItems: ItemDataByReference[],
): ItemDataByReference[] => {
  return requiredItems
    .map((neededItem) => {
      const bankItem = bankItems.find((bItem) => bItem?.id === neededItem.id);
      if (bankItem) {
        return bankItem;
      }
      return null;
    })
    .filter((item): item is ItemDataByReference => item !== null);
};

export const getAllButOneItemsToWithdraw = (
  bankItems: InventoryItemsData,
  requiredItems: ItemDataByReference[],
): ItemDataByReference[] => {
  return requiredItems
    .map((neededItem) => {
      const bankItem = bankItems.find((bItem) => bItem?.id === neededItem.id);
      if (bankItem && bankItem.amount > 1) {
        const withdrawAmount = bankItem.amount - 1;
        return {
          ...neededItem,
          amount: withdrawAmount,
        };
      }
      return null;
    })
    .filter((item): item is ItemDataByReference => item !== null);
};
