import { PlayerData } from "../../data/AllTypes/PlayerDataTypes.ts";
import { recalculateMultipliersForSkill } from "./ReducerUtils/recalculateMultipliersForSkill.ts";

import { SkillsId } from "../../data/skillsData/SkillsEnum.ts";

export function refreshToolMultipliers(playerData: PlayerData): PlayerData {
  const updatedSkills = { ...playerData.skills };

  Object.keys(updatedSkills).forEach((skillId) => {
    const skillIdTyped = Number(skillId) as SkillsId;
    const skill = updatedSkills[skillIdTyped];
    const multipliers = recalculateMultipliersForSkill(skill);

    updatedSkills[skillIdTyped] = {
      ...skill,
      ...multipliers,
    };
  });

  return {
    ...playerData,
    skills: updatedSkills,
  };
}
