// Calculate the remaining XP required to reach the next level

export function calculateRemainingXp(currentLevel: number, currentXP: number): number {
  const nextXpEntry = xpTable126[currentLevel];
  if (!nextXpEntry) return 0;
  return nextXpEntry.xp - currentXP;
}

function calculateNextLevelXp(currentLevel: number): number {
  const nextXpEntry = xpTable126[currentLevel];
  // if (currentLevel >= 99) {
  //   const calculateOverLevel99 = calculateLevelAbove99(currentXP);
  //   return xpTable126[calculateOverLevel99]?.xp;
  // }

  return nextXpEntry?.xp;
}
// Calculate the progress towards the next level as a percentage
function calculateProgress(currentLevel: number, currentXP: number): number {
  let currentXpEntry = xpTable126[currentLevel - 1];
  let nextXpEntry = xpTable126[currentLevel];
  // if (currentLevel >= 99) {
  //   currentXpEntry = xpTable126[calculateLevelAbove99(currentXP) - 1];
  //   nextXpEntry = xpTable126[calculateLevelAbove99(currentXP)];
  // }
  if (!currentXpEntry || !nextXpEntry) {
    return 0; // Invalid levels
  }

  const xpDifference = nextXpEntry.xp - currentXpEntry.xp;
  const progress = ((currentXP - currentXpEntry.xp) / xpDifference) * 100;
  const progressRounded = parseFloat(progress.toFixed(2));
  return progressRounded;
}
function calculateTotalLevel(state: PlayerData): number {
  // Sum level from skills only
  return AllSkillIdList.reduce((total, skill) => {
    return total + state.skills[skill].level;
  }, 0);
}

export function calculateMaxTotalLevel() {
  const skillsAmount = Object.keys(skillChooser).length;
  return skillsAmount * MAX_LEVEL;
}
export function calculateMaxTotalXp() {
  const skillsAmount = Object.keys(skillChooser).length;
  const maxXp = xpTable126[xpTable126.length - 1].xp;
  return maxXp * skillsAmount;
}

function calculateTotalXp(state: PlayerData): number {
  // Sum XP from skillsXp only
  if (!state.skillsXp) return 0; // early return if undefined

  return AllSkillIdList.reduce((total, skill) => {
    const skillData = state.skillsXp?.[skill]; // optional chaining
    return total + (skillData?.xp ?? 0); // default to 0 if missing
  }, 0);
}

export const getCombatLevel = (skills: SkillsMapType) => {
  return calculateCombatLevel(
    // skills[SkillsId.Attack].level,
    skills[SkillsId.Melee].level,
    skills[SkillsId.Defence].level,
    skills[SkillsId.Hitpoints].level,
    skills[SkillsId.Ranged].level,
    skills[SkillsId.Magic].level,
    skills[SkillsId.Prayer].level,
  );
};
function calculateCombatLevel(
  melee: number,
  defence: number,
  hitpoints: number,
  ranged: number,
  magic: number,
  prayer: number,
): number {
  const base = 0.25 * (defence + hitpoints + Math.floor(prayer / 2));
  const meleeLevel = 0.4875 * melee;
  const rangedLevel = 0.4875 * ranged;
  const magicLevel = 0.4875 * magic;

  const highestStyle = Math.max(meleeLevel, rangedLevel, magicLevel);
  const combatLevel = base + highestStyle;

  return Math.floor(combatLevel);
}
// Helper function to calculate total bonuses
const calculateTotalBonuses = (equippedItems: EquippedItemsSetType, combatPoints: number) => {
  const totalBonuses: TotalBonuses = {
    totalAccuracyMelee: 0,
    totalAccuracyMagic: 0,
    totalAccuracyRanged: 0,
    totalDefenceMelee: 0,
    totalDefenceMagic: 0,
    totalDefenceRanged: 0,
    totalMeleeDmg: 0,
    totalRangedDmg: 0,
    totalMagicDmg: 0,
    totalSlayer: 0,
    totalForest: 0,
    totalMine: 0,
    totalSea: 0,
    totalField: 0,
    totalTemple: 0,
    totalMarket: 0,
  };

  for (const slot in equippedItems) {
    if (
      slot === "totalStats" ||
      slot === "currentWeaponStyle" ||
      slot === "currentSpell" ||
      slot === "currentPrayer"
    )
      continue;
    if (equippedItems[slot as Slots] !== null) {
      const equippedItemRef = equippedItems[slot as Slots];
      if (!equippedItemRef) return;
      const equipmentStats = getEquipmentStats(equippedItemRef, combatPoints);
      if (!equipmentStats) return;
      totalBonuses.totalAccuracyMelee += equipmentStats.accuracyMelee || 0;
      totalBonuses.totalAccuracyMagic += equipmentStats.accuracyMagic || 0;
      totalBonuses.totalAccuracyRanged += equipmentStats.accuracyRanged || 0;
      totalBonuses.totalDefenceMelee += equipmentStats.defenceMelee || 0;
      totalBonuses.totalDefenceMagic += equipmentStats.defenceMagic || 0;
      totalBonuses.totalDefenceRanged += equipmentStats.defenceRanged || 0;
      totalBonuses.totalMeleeDmg += equipmentStats.meleeDmg || 0;
      totalBonuses.totalRangedDmg += equipmentStats.rangedDmg || 0;
      totalBonuses.totalMagicDmg += equipmentStats.magicDmg || 0;
      totalBonuses.totalSlayer += equipmentStats.slayer || 0;
      totalBonuses.totalForest += equipmentStats.forestDmg || 0;
      totalBonuses.totalMine += equipmentStats.mineDmg || 0;
      totalBonuses.totalSea += equipmentStats.seaDmg || 0;
      totalBonuses.totalField += equipmentStats.fieldDmg || 0;
      totalBonuses.totalTemple += equipmentStats.templeDmg || 0;
      totalBonuses.totalMarket += equipmentStats.marketDmg || 0;
    }
  }

  totalBonuses.totalAccuracyMelee = Number(totalBonuses.totalAccuracyMelee.toFixed(0));
  totalBonuses.totalAccuracyMagic = Number(totalBonuses.totalAccuracyMagic.toFixed(0));
  totalBonuses.totalAccuracyRanged = Number(totalBonuses.totalAccuracyRanged.toFixed(0));
  totalBonuses.totalDefenceMelee = Number(totalBonuses.totalDefenceMelee.toFixed(0));
  totalBonuses.totalDefenceMagic = Number(totalBonuses.totalDefenceMagic.toFixed(0));
  totalBonuses.totalDefenceRanged = Number(totalBonuses.totalDefenceRanged.toFixed(0));
  totalBonuses.totalMeleeDmg = Number(totalBonuses.totalMeleeDmg.toFixed(0));
  totalBonuses.totalRangedDmg = Number(totalBonuses.totalRangedDmg.toFixed(0));
  totalBonuses.totalMagicDmg = Number(totalBonuses.totalMagicDmg.toFixed(2));
  totalBonuses.totalSlayer = Number(totalBonuses.totalSlayer.toFixed(2));
  totalBonuses.totalForest = Number(totalBonuses.totalForest.toFixed(2));
  totalBonuses.totalMine = Number(totalBonuses.totalMine.toFixed(2));
  totalBonuses.totalSea = Number(totalBonuses.totalSea.toFixed(2));
  totalBonuses.totalField = Number(totalBonuses.totalField.toFixed(2));
  totalBonuses.totalTemple = Number(totalBonuses.totalTemple.toFixed(2));
  totalBonuses.totalMarket = Number(totalBonuses.totalMarket.toFixed(2));
  return totalBonuses;
};

export {
  calculateLevel,
  calculateNextLevelXp,
  calculateProgress,
  calculateTotalLevel,
  calculateTotalXp,
  calculateCombatLevel,
  calculateTotalBonuses,
};
