import { PlayerData, ValidRunStatusTypes } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { getResourceInfo } from "../../../data/skillsData/skillsChooser.ts";
import { ResourceIds } from "../../../data/skillsData/ResourceIds.ts";
import { RunIds } from "../../../data/Runs/AllRunsData.ts";
import { rollItemWithProbability } from "../../../Components/util/ProcessUtil.tsx";
import {
  combineItemGain,
  updateItemsWithLootMultiplier,
} from "../../../Components/util/MultiplierUpdaterUtils.tsx";

type UpdateRunSlotAction = {
  runId: RunIds;
  slot: number;
  resourceId: ResourceIds;
  lootMultiplier: number;
  xpMultiplier?: number;
};

export function startRun(state: PlayerData, action: UpdateRunSlotAction): PlayerData {
  const { runId, slot, resourceId, lootMultiplier, xpMultiplier } = action;

  const now = Date.now();
  const resourceInfo = getResourceInfo(resourceId);
  const duration = Math.ceil(resourceInfo?.time ? resourceInfo.time * 1000 : 0);
  const finishedTime = now + duration;

  const currentRuns = { ...state.currentLongTermProcesses };
  const runSlots = { ...(currentRuns?.[runId] ?? {}) };

  const itemGainAlways = resourceInfo?.itemGainAlways;
  const itemGainWithProbability = resourceInfo?.itemGainWithProbability;

  const flattenedItems = rollItemWithProbability(itemGainWithProbability, lootMultiplier);
  const alwaysItems = updateItemsWithLootMultiplier(itemGainAlways, lootMultiplier);
  const combinedItem = combineItemGain(alwaysItems, flattenedItems);

  return {
    ...state,
    currentLongTermProcesses: {
      ...currentRuns,
      [runId]: {
        ...runSlots,
        [slot]: {
          status: ValidRunStatusTypes.InProgress,
          resourceId,
          startedTime: now,
          finishedTime: finishedTime - 1000,
          duration,
          itemGain: combinedItem,
          xpMultiplier,
          lootMultiplier,
        },
      },
    },
  };
}
