// useCheckItemCost.ts
import { usePlayerStore } from "../usePlayerStore";
import { getUnlimitedRunesFromEquipment } from "../../Components/util/CombatUtils/getUnlimitedRunesFromEquipment";
import { checkItemCostInInventory } from "../../Components/util/ResourceUtils";
import { ItemDataByReference } from "../../data/AllTypes/PlayerDataTypes.ts";

export const checkItemCostNow = (
  itemCost: ItemDataByReference[] | null | undefined,
  currentLootMultiplier = 1,
) => {
  const state = usePlayerStore.getState();
  const { equippedItems, items } = state.state;
  const { currentSet, sets } = equippedItems;
  const excludeItems = getUnlimitedRunesFromEquipment(sets[currentSet]);

  return checkItemCostInInventory(itemCost, items, currentLootMultiplier ?? 1, excludeItems);
};

// 2️⃣ Reactive / subscribable (for UI)
export const useCheckItemCost = (
  itemCost: ItemDataByReference[] | null | undefined,
  currentLootMultiplier = 1,
) => {
  return usePlayerStore((state) => {
    const { currentSet, sets } = state.state.equippedItems;
    const items = state.state.items;

    const excludeItems = getUnlimitedRunesFromEquipment(sets[currentSet]);
    console.log("checking item cost");

    return checkItemCostInInventory(itemCost, items, currentLootMultiplier, excludeItems);
  });
};
