import { PlayerData } from "../../data/AllTypes/PlayerDataTypes.ts";
import { Slots } from "../../data/AllTypes/EquipmentTypes.ts";
import { calculateTotalBonuses } from "../../Components/Reducer/playerCalculations.ts";
import { StanceIds } from "../../data/ItemData/AllWeaponStances.ts";

type UnequipItemAction = {
  slot: Slots;
  setIndex: number; // Added setIndex to target a specific set
};

export function unequipItem(state: PlayerData, action: UnequipItemAction): PlayerData {
  const { slot, setIndex } = action;

  // Retrieve the specific set and remove the item
  const updatedSet = {
    ...state.equippedItems.sets[setIndex],
    [slot]: null, // Unequip the item from the specified slot
  };

  // Recalculate bonuses for the updated set
  const totalBonuses =
    calculateTotalBonuses(updatedSet, state.levelBoosts.combatLevelBoostsPoints) ||
    state.equippedItems.sets[setIndex].totalStats;

  // Check if the unequipped item was a weapon
  let newWeaponStyle = updatedSet.currentWeaponStyle;
  let newSpell = updatedSet.currentSpell;

  if (slot === Slots.WEAPON) {
    // If unequipping a weapon, determine if we should reset the weapon style
    const currentWeapon = updatedSet[Slots.WEAPON];
    const defenceStance = [StanceIds.DefenceMelee, StanceIds.DefenceMagic, StanceIds.DefenceRanged];
    if (!currentWeapon) {
      if (defenceStance.includes(updatedSet.currentWeaponStyle)) {
        newWeaponStyle = StanceIds.DefenceMelee; // Set to a default defence stance if the current style is a defence stance
      } else {
        newWeaponStyle = StanceIds.Melee;
      }
    }
  }

  // Update the equippedItems object with the modified set
  const updatedEquippedItems = {
    ...state.equippedItems,
    sets: {
      ...state.equippedItems.sets,
      [setIndex]: {
        ...updatedSet,
        totalStats: { ...totalBonuses },
        currentWeaponStyle: newWeaponStyle,
        currentSpell: newSpell,
      },
    },
  };

  return {
    ...state,
    equippedItems: updatedEquippedItems,
  };
}
