import LContainer from "../../../Layout/LContainer.tsx";
import { ImageMap } from "../../../data/ImageMap.ts";

type ServerSuccessToasterType = {
  message: string;
};

const ServerSuccessToaster = ({ message }: ServerSuccessToasterType) => {
  return (
    <div
      className={`toaster fixed flex  pointer-events-none flex-col items-center text-lg justify-center text-orangeColor z-20 top-0 w-full animateSlideInSlow`}
    >
      <LContainer>
        <div className="flex max-w-lg gap-2 justify-center pointer-events-auto container-shadow-small cursor-pointer align-middle items-center p-2">
          <img src={ImageMap.loading} alt="Success" className="w-6 h-6 object-contain" />
          <p className="leading-none text-center text-green-500">{message}</p>
        </div>
      </LContainer>
    </div>
  );
};

export default ServerSuccessToaster;
