import { ItemDataByReference, ItemType, LongTermProcessSlots } from "../../data/AllTypes/PlayerDataTypes.ts";
import { getAndMergeItemData } from "../../data/ItemData/AllItemsData.ts";
import { isRunCompletedButRewardNotTaken } from "./RunsUtils.tsx";
import { SkillIdNumberDictionary } from "../../data/AllTypes/SkillsSpecificTypes.ts";
import { SkillsId } from "../../data/skillsData/SkillsEnum.ts";
import { ITEMS_TO_LOWER_PROP } from "../../data/Constants.ts";

export const updateItemsWithLootMultiplier = (
  items: ItemDataByReference[] | null | undefined,
  lootMultiplier: number,
): ItemDataByReference[] => {
  if (!items) return [];

  return items.map((itemRef) => {
    return {
      ...itemRef,
      amount: Math.floor(itemRef.amount * lootMultiplier),
    };
  });
};

export const adjustLootAmountsAndProbabilities = (
  items: ItemDataByReference[] | null | undefined,
  lootMultiplier: number,
): ItemDataByReference[] => {
  if (!items) return [];

  return items.map((itemRef) => {
    const itemData = getAndMergeItemData(itemRef);
    const isSpecial = ITEMS_TO_LOWER_PROP.includes(itemData.type);

    if (isSpecial) {
      const oldProb = itemRef.probability ?? 1;
      // multiply probability
      let newProb = oldProb * lootMultiplier;

      // if probability stays ≤ 1 → no amount change
      if (newProb <= 1) {
        return {
          ...itemRef,
          amount: itemRef.amount,
          probability: newProb,
        };
      }

      // if probability goes over 1 → convert overflow to amount
      const extraAmount = Math.floor(newProb); // guaranteed extra items
      return {
        ...itemRef,
        amount: extraAmount, // amount increases
        probability: 1, // capped at 1
      };
    }

    // normal items → multiply amount normally
    return {
      ...itemRef,
      amount: Math.floor(itemRef.amount * lootMultiplier),
    };
  });
};
export const removeSpecialItemTypes = (
  items: ItemDataByReference[] | null | undefined,
): ItemDataByReference[] => {
  if (!items) return [];
  return items.filter((itemRef) => {
    const itemData = getAndMergeItemData(itemRef);
    return !ITEMS_TO_LOWER_PROP.includes(itemData.type);
  });
};

export const extractAllItemsFromRuns = (
  currentRuns: LongTermProcessSlots | null | undefined,
): ItemDataByReference[] => {
  if (!currentRuns) return [];
  const allItems: ItemDataByReference[] = [];
  Object.values(currentRuns).forEach((slot) => {
    if (!slot.resourceId) return;
    if (!isRunCompletedButRewardNotTaken(slot)) return;
    const itemGain = slot.itemGain;
    if (!itemGain) return;
    allItems.push(...itemGain);
  });

  return allItems;
};
export const updateItemWithMultiplier = (item: ItemDataByReference, lootMultiplier: number) => {
  return {
    ...item,
    amount: Math.floor(item.amount * lootMultiplier),
  };
};

export const updatedXpWithMultiplier = (
  xp: SkillIdNumberDictionary | null,
  xpMultiplier: number,
): SkillIdNumberDictionary => {
  if (!xp) return {};
  return Object.entries(xp).reduce((acc, [key, value]) => {
    const skillId = Number(key) as SkillsId;
    acc[skillId] = value! * xpMultiplier;
    return acc;
  }, {} as SkillIdNumberDictionary);
};
export const mergeXpDictionaries = (
  target: SkillIdNumberDictionary,
  source: SkillIdNumberDictionary,
): SkillIdNumberDictionary => {
  Object.entries(source).forEach(([skillId, xpValue]) => {
    const idNum = Number(skillId) as SkillsId;
    target[idNum] = (target[idNum] || 0) + (xpValue || 0);
  });
  return target;
};

export const removePetsFromItems = (items: ItemDataByReference[]): ItemDataByReference[] => {
  return items.filter((item) => getAndMergeItemData(item).type !== ItemType.PET);
};

export const removeAllButPetsFromItems = (items: ItemDataByReference[]): ItemDataByReference[] => {
  return items.filter((item) => getAndMergeItemData(item).type === ItemType.PET);
};

export const combineItemGain = (
  itemGain: ItemDataByReference[] | null | undefined,
  alwaysDrops: ItemDataByReference[] | null | undefined,
): ItemDataByReference[] => {
  return [...(itemGain || []), ...(alwaysDrops || [])];
};
