import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";

type setIsMonsterAliveAction = {
  isMonsterAlive: boolean;
};

export function setIsMonsterAlive(state: PlayerData, action: setIsMonsterAliveAction): PlayerData {
  if (state.currentAttackProcess && state.currentAttackProcess.currentMonsterState) {
    return {
      ...state,
      currentAttackProcess: {
        ...state.currentAttackProcess,
        isMonsterAlive: action.isMonsterAlive,
      },
    };
  }
  return state;
}
