import { levelBoostsType, PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";

type SetLevelBoostsAction = {
  newLevelsInfo: levelBoostsType;
};

export function setLevelBoosts(state: PlayerData, action: SetLevelBoostsAction): PlayerData {
  const { newLevelsInfo } = action;

  return {
    ...state,
    levelBoosts: {
      ...newLevelsInfo,
    },
  };
}
