import { ItemWithAmount } from "../UtilityComponents/UIDisplays/ItemWithAmount.tsx";
import { ItemDataByReference } from "../../data/AllTypes/PlayerDataTypes.ts";
import TooltipContentWithAmountProb from "../UtilityComponents/ToolTip/TooltipContentWithAmountProb.tsx";
import TooltipWrapper from "../UtilityComponents/ToolTip/TooltipWrapper.tsx";
import InventoryToolTipDisplay from "../Inventory/InventoryToolTipDisplay.tsx";
import { getItemInfoFromId } from "../../data/ItemData/AllItemsData.ts";

type ItemWithToolTipProps = {
  item: ItemDataByReference | null | undefined;
  isLowOpacity?: boolean;
  className?: string | 0;
  amount?: number;
  toolTipAmount?: number;
  itemWithAmountClassName?: string;
  removePaddingX?: boolean;
  probability?: number | null;
  dropRolls?: number;
  customToolTipText?: string;
  multiplier?: number;
  showInventoryToolTip?: boolean;
  hideTooltip?: boolean;
  imageClassName?: string | 0;
  clickable?: boolean;
  showHelpLink?: boolean;
};

const ItemWithToolTip = ({
  item,
  className,
  isLowOpacity,
  toolTipAmount,
  amount,
  itemWithAmountClassName,
  removePaddingX,
  probability,
  dropRolls,
  customToolTipText,
  multiplier,
  showInventoryToolTip,
  hideTooltip = false,
  imageClassName,
  clickable = showInventoryToolTip,
  showHelpLink,
}: ItemWithToolTipProps) => {
  if (!item) return null;
  const itemInfo = getItemInfoFromId(item.id);
  if (!itemInfo) return null;
  const toolTipAmountToShow = toolTipAmount ?? item.amount;
  const toolTipNameToShow = customToolTipText ?? itemInfo.name;
  const amountCustom = amount ?? item.amount;
  const customItem = {
    ...item,
    amount: amountCustom,
  };
  const contentToShow = showInventoryToolTip ? (
    <InventoryToolTipDisplay item={item} />
  ) : (
    <TooltipContentWithAmountProb
      itemName={toolTipNameToShow}
      amount={toolTipAmountToShow}
      dropRolls={dropRolls}
      probability={probability}
    />
  );

  return (
    <div className={` ${className || ""}`}>
      <TooltipWrapper content={hideTooltip ? undefined : contentToShow}>
        <ItemWithAmount
          item={customItem}
          clickable={clickable}
          className={itemWithAmountClassName}
          removePaddingX={removePaddingX}
          isLowOpacity={isLowOpacity}
          multiplier={multiplier}
          imageClassName={imageClassName}
          showHelpLink={showHelpLink}
        />
      </TooltipWrapper>
    </div>
  );
};

export default ItemWithToolTip;
