import { MonsterAttackStylesType, ValidMonsterAttackStyles } from "../../../data/AllTypes/MonsterTypes.ts";

export function getNextAttackStyle(
  attackStyles: MonsterAttackStylesType | undefined,
): ValidMonsterAttackStyles {
  const randomValue = Math.random();
  let cumulativeProbability = 0;
  if (!attackStyles || attackStyles.length === 0) {
    return "Melee"; // Default style if attackStyles is undefined or empty
  }

  for (const style of attackStyles) {
    cumulativeProbability += style.probability;
    if (randomValue <= cumulativeProbability) {
      return style.attackStyleName;
    }
  }

  // Fallback in case of rounding errors
  return attackStyles[attackStyles.length - 1].attackStyleName;
}
