import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { SkillIdNumberDictionary } from "../../../data/AllTypes/SkillsSpecificTypes.ts";
import { SkillsId } from "../../../data/skillsData/SkillsEnum.ts";

type action = {
  changeBoostedLevel: SkillIdNumberDictionary;
  overflow: boolean | undefined;
};

export const changeBoostedStats = (state: PlayerData, action: action) => {
  const { changeBoostedLevel, overflow } = action;

  let newState = { ...state };

  for (const skillId in changeBoostedLevel) {
    const skillIdTyped = Number(skillId) as SkillsId;
    const currentBaselevel = newState.skills[skillIdTyped].level;
    const currentBoostedLevel = newState.skills[skillIdTyped].boostedLevel;
    const statChange = changeBoostedLevel[skillIdTyped] || 0;

    //Should not be able to boost a stat above one time the statboost, otherwise it will be boosted forever
    const maximumBoostedStat = currentBaselevel + statChange;

    const newBoostedStat = Math.min(
      Math.max(maximumBoostedStat, currentBoostedLevel),
      currentBoostedLevel + statChange,
    );

    const newBoostedStatAbove0 = Math.max(newBoostedStat, 0);

    let finalBoostedStat = 0;
    if (overflow) {
      finalBoostedStat = newBoostedStatAbove0;
    } else {
      const currentStats = Math.max(currentBaselevel, currentBoostedLevel);
      finalBoostedStat = Math.min(newBoostedStatAbove0, currentStats);
    }

    if (currentBoostedLevel === currentBaselevel && skillIdTyped === SkillsId.Hitpoints) {
      newState = {
        ...newState,
        skills: {
          ...newState.skills,
          [skillIdTyped]: {
            ...newState.skills[skillIdTyped],
            boostedLevel: finalBoostedStat,
          },
        },
        healthInfo: {
          ...newState.healthInfo,
          nextHealthRestoreTime:
            Date.now() +
            (newState.healthInfo.healthRestoreBaseInterval * 1000) /
              newState.healthInfo.healthRestoreMultiplier,
        },
      };
    } else if (
      finalBoostedStat > currentBaselevel &&
      skillIdTyped !== SkillsId.Prayer &&
      skillIdTyped !== SkillsId.Hitpoints
    ) {
      newState = {
        ...newState,
        skills: {
          ...newState.skills,
          [skillIdTyped]: {
            ...newState.skills[skillIdTyped],
            boostedLevel: finalBoostedStat,
          },
        },
      };
    } else if (
      finalBoostedStat < currentBaselevel &&
      skillIdTyped !== SkillsId.Prayer &&
      skillIdTyped !== SkillsId.Hitpoints
    ) {
      newState = {
        ...newState,
        skills: {
          ...newState.skills,
          [skillIdTyped]: {
            ...newState.skills[skillIdTyped],
            boostedLevel: finalBoostedStat,
          },
        },
      };
    } else {
      newState = {
        ...newState,
        skills: {
          ...newState.skills,
          [skillIdTyped]: {
            ...newState.skills[skillIdTyped],
            boostedLevel: finalBoostedStat,
          },
        },
      };
    }
  }

  return newState;
};
