import React, { Component } from "react";

// Type for the state of the error boundary
interface State {
  hasError: boolean;
}

// Type for the props of the ErrorBoundary component
interface ErrorBoundaryProps {
  children: React.ReactNode; // This will allow any valid React node (string, element, array, etc.)
  fallback?: React.ReactNode; // Optional fallback UI in case of an error
}

class ErrorBoundary extends Component<ErrorBoundaryProps, State> {
  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = { hasError: false };
  }

  // This lifecycle method is called when an error is thrown in a child component
  static getDerivedStateFromError(): State {
    return { hasError: true };
  }

  // This method is called when an error is caught
  // componentDidCatch(error: Error, errorInfo: ErrorInfo): void {
  // Send the error to Sentry for tracking (only in production)
  // if (import.meta.env.MODE === "production") {
  // The key here is to extract the relevant data from errorInfo and pass a plain object to Sentry
  // Sentry.captureException(error, {
  //   extra: {
  //     componentStack: errorInfo.componentStack, // This is a string that gives context about the error
  //     // You can add more context here if needed
  //   },
  // });
  // }
  // }

  render() {
    // If an error is caught, display the fallback UI
    if (this.state.hasError) {
      // Ensure that fallback is directly JSX and not a function
      return this.props.fallback || <div>Something went wrong. Please try again later.</div>;
    }

    // If no error, render the children normally
    return this.props.children;
  }
}

export default ErrorBoundary;
