import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";

type ReorderShortcutsAction = {
  shortcuts: Array<{ id: string; order: number }>;
};

/**
 * Reorders shortcuts based on the provided array of id and order pairs
 * Used for drag and drop functionality
 */
export function reorderShortcuts(state: PlayerData, action: ReorderShortcutsAction): PlayerData {
  const shortcuts = state.shortcuts ?? [];
  const { shortcuts: reorderedIds } = action;

  // Create a map of new orders by shortcut ID
  const orderMap = new Map<string, number>();
  reorderedIds.forEach((item) => {
    orderMap.set(item.id, item.order);
  });

  // Update shortcuts with new orders
  const updatedShortcuts = shortcuts.map((shortcut) => {
    const newOrder = orderMap.get(shortcut.id);
    if (newOrder !== undefined) {
      return {
        ...shortcut,
        order: newOrder,
      };
    }
    return shortcut;
  });

  // Sort by order to ensure correct sequence
  updatedShortcuts.sort((a, b) => a.order - b.order);

  return {
    ...state,
    shortcuts: updatedShortcuts,
  };
}




