import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import getTotalCollectionLogs from "../../../hooks/useTotalCollectionLogs.tsx";

export function changeCollectionLogSlotNumber(
  state: PlayerData,
  action: { changeInCollectionLogSlots: number },
): PlayerData {
  const currentTotalLogs =
    (isNaN(state.collectionLogSlot) ? 0 : (state.collectionLogSlot ?? 0)) + action.changeInCollectionLogSlots;

  const TOTAL_COLLECTION_LOGS = getTotalCollectionLogs();

  let collectionLogMaxedTimestamp = state.collectionLogMaxedTimestamp;
  // if (currentTotalLogs >= totalLogs && !state.collectionLogMaxedTimestamp) {
  if (currentTotalLogs >= TOTAL_COLLECTION_LOGS) collectionLogMaxedTimestamp = new Date().getTime();

  return {
    ...state,
    collectionLogSlot: currentTotalLogs,
    collectionLogMaxedTimestamp: collectionLogMaxedTimestamp,
  };
}
