const selectPlayerItemsData = (state: PlayerData): playerItemsType => state.items;
const selectCurrentEquippedSet = (state: PlayerData): EquippedItemsSetType =>
  state.equippedItems.sets[state.equippedItems.currentSet];

export const createDeepMemoizedCheckCostSelector = (
  itemCost: ItemDataByReference[] | null | undefined,
  currentLootMultiplier: number,
) => {
  return createSelector(
    [selectPlayerItemsData, selectCurrentEquippedSet],
    (items: playerItemsType, equippedSet: EquippedItemsSetType) =>
      calculateItemCostCheck(items, equippedSet, itemCost, currentLootMultiplier),
  );
};

