export const SkillIcons = Object.fromEntries(
  Object.entries(skillChooser).map(([skill, data]) => [skill, data.icon]),
) as Record<SkillsId, string>;

export const getAllResources = (): ResourceMapPartial => {
  return AllResources;
};

export const mergeResources = (target: ResourceIds[], skill: SkillChooserInfo): void => {
  if (!skill.tabs) return;

  for (const tab of skill.tabs) {
    if (tab.resources) {
      target.push(...tab.resources); // spread and push all resources
    }
  }
};

export const getResourceInfo = (resourceId: ResourceIds | null | undefined): ResourcesTypeFinal | null => {
  if (!resourceId) return null;
  const allResources = getAllResources(); // Fetch all static resources
  const res = allResources[resourceId];
  if (!res) return null;
  return {
    ...res,
    name: res.name || PLACEHOLDER_NAME,
    img: res.img || PLACEHOLDER_IMG,
  };
};
export default skillChooser;
