export function changeSlayerMonsterAmount(
  state: PlayerData,
  action: changeSlayerMonsterAmountAction,
): PlayerData {
  const { amount } = action;

  if (!state.slayerInfo.currentSlayerTask) {
    return state;
  }

  const currentAmount = state.slayerInfo.currentSlayerTask.currentAmount;
  const newAmount = currentAmount + amount;

  // If task completes
  if (newAmount <= 0) {
    const slayerPointsGain = calculateSlayerPointsFromSlayerMaster(state.slayerInfo);

    return {
      ...state,
      slayerInfo: {
        ...state.slayerInfo,
        currentSlayerTask: null, // task completed and removed
        slayerStreak: state.slayerInfo.slayerStreak + 1,
        slayerPoints: state.slayerInfo.slayerPoints + slayerPointsGain,
      },
    };
  }
  // Otherwise just decrement/increment the amount
  return {
    ...state,
    slayerInfo: {
      ...state.slayerInfo,
      currentSlayerTask: {
        ...state.slayerInfo.currentSlayerTask,
        currentAmount: newAmount,
      },
    },
  };
}
