import { MonsterTypeFinal } from "../AllTypes/MonsterTypes.ts";
import { SlayerCategoriesIds } from "./MonsterTypes.ts";
import { AllMonsters, AllMonstersFiltered } from "./AllMonsters.ts";
import { MonsterIds } from "./MonsterIds.ts";
import { PLACEHOLDER_IMG, PLACEHOLDER_NAME } from "../Constants.ts";

export { MonsterIds };

export const getMonsterInfo = (monsterId: MonsterIds | null | undefined): MonsterTypeFinal | null => {
  if (!monsterId) return null;
  const monster = AllMonsters[monsterId];
  if (!monster) return null;

  return {
    ...monster,
    name: monster.name || PLACEHOLDER_NAME,
    img: monster.img || PLACEHOLDER_IMG,
  };
};

export const bossMonsterIds = AllMonstersFiltered.filter((monsterId) => {
  const monster = getMonsterInfo(monsterId);

  return monster?.slayer?.category?.includes(SlayerCategoriesIds.BOSS);
});
