import { PlayerData } from "../../data/AllTypes/PlayerDataTypes.ts";
import { PrayerIds } from "../../data/utilData/AllPrayers.ts";

type unlockPrayerAction = {
  prayerId: PrayerIds;
};

export const unlockPrayer = (state: PlayerData, action: unlockPrayerAction): PlayerData => {
  if (state.prayerUnlockList.includes(action.prayerId)) return state;

  const newPrayers = [...state.prayerUnlockList, action.prayerId];
  return {
    ...state,
    prayerUnlockList: newPrayers,
  };
};
