import skillChooser, { ToolsMap } from "./skillsChooser";
import { ShopItemsType } from "../AllTypes/SkillsSpecificTypes";
import { ToolIds } from "./Tools";

export const AllTools: ToolsMap = (() => {
  const tools: ToolsMap = {};
  Object.values(skillChooser).forEach((skill) => {
    if (skill.shopTools) {
      Object.entries(skill.shopTools).forEach(([toolId, data]) => {
        tools[Number(toolId) as ToolIds] = data;
      });
    }
  });

  return tools as Record<ToolIds, ShopItemsType>;
})();

export const getToolDataFromId = (id: ToolIds): ShopItemsType | undefined => {
  return AllTools[id];
};

export const toolWithHighestMultiplier = (toolIds: ToolIds[] | null): ToolIds | null => {
  if (!toolIds || toolIds.length === 0) return null;

  return toolIds.reduce<ToolIds | null>((bestId, toolId) => {
    const tool = getToolDataFromId(toolId);
    if (!tool) return bestId;

    const score =
      (tool.effect?.speedMultiplier ?? 1) +
      (tool.effect?.xpMultiplier ?? 1) +
      (tool.effect?.lootMultiplier ?? 1);

    if (!bestId) return toolId;
    const bestTool = getToolDataFromId(bestId);
    if (!bestTool) return toolId;

    const bestScore =
      (bestTool.effect?.speedMultiplier ?? 1) +
      (bestTool.effect?.xpMultiplier ?? 1) +
      (bestTool.effect?.lootMultiplier ?? 1);

    return score > bestScore ? toolId : bestId;
  }, null);
};
