import { InventoryItemsData } from "../../../data/AllTypes/SkillsSpecificTypes.ts";
import {
  InventoryStates,
  ItemDataByReference,
  ItemType,
  playerItemsType,
} from "../../../data/AllTypes/PlayerDataTypes.ts";
import { isInventorySpaceNow } from "../ResourceUtils.tsx";
import {
  ALLOWED_SCROLL_BOTTLE_ITEMS,
  ALLOWED_SEED_BOX_ITEMS,
  getContainerIdByUnlockItemId,
  StorageIds,
} from "./ExtraStorageUtils.tsx";
import { getAndMergeItemData, getItemInfoFromId } from "../../../data/ItemData/AllItemsData.ts";
import { getItemFunction, useItemFunction } from "../../../Context/usePlayerStore.ts";
import { AddToastFunctionType } from "../../../Context/ToastManagerContext.tsx";
import { DragEndEvent } from "@dnd-kit/core";
import { ItemIds } from "../../../data/ItemData/AllItemsIds.ts";

export const removeNullItems = (items: InventoryItemsData): ItemDataByReference[] => {
  return items.filter((item): item is ItemDataByReference => item !== null);
};

export const depositItemsToInventoryUtil = (
  itemGain: ItemDataByReference[],
  addToast: AddToastFunctionType,
  useItems: useItemFunction,
  getItems: getItemFunction,
  currentInventoryState: InventoryStates,
  e: React.MouseEvent,
): void => {
  if (!isInventorySpaceNow(itemGain, addToast, e, null, undefined, null, true)) return;
  useItems(itemGain, currentInventoryState);
  getItems(itemGain, "inventory");
};

export const depositItemsToExtraStorageUtil = (
  itemGain: ItemDataByReference[],
  addToast: AddToastFunctionType,
  useItems: useItemFunction,
  getItems: getItemFunction,
  placeToPutIt: StorageIds | undefined,
  e: DragEndEvent,
): void => {
  const currentInventory = itemGain;
  if (!isInventorySpaceNow(currentInventory, addToast, e)) return;
  useItems(currentInventory, "inventory");
  getItems(currentInventory, placeToPutIt);
};

export const getItemContainerAmountSmallText = (
  item: ItemDataByReference | null,
  playerItems: playerItemsType,
): number | string | null | undefined => {
  if (!item) return null;
  let smallText = null;
  const itemData = getAndMergeItemData(item);
  if (itemData?.type === ItemType.EXTRA_CONTAINER) {
    const containerId = getContainerIdByUnlockItemId(itemData.id);
    if (!containerId) return null;
    const container = playerItems[containerId];
    smallText = container && removeNullItems(container).length;
  }

  return smallText;
};

export const getItemsSmallText = (item: ItemDataByReference | null): number | string | null | undefined => {
  if (!item) return null;
  let smallText = null;
  const itemData = getAndMergeItemData(item);
  if (ALLOWED_SEED_BOX_ITEMS.includes(itemData.id) || ALLOWED_SCROLL_BOTTLE_ITEMS.includes(itemData.id)) {
    const itemInfo = getItemInfoFromId(item.id);
    smallText = itemInfo?.name.slice(0, 3);
  }
  return smallText;
};

export const isItemLocked = (
  lockedItemIds: ItemIds[] | undefined,
  itemId: ItemIds | null | undefined,
): boolean => {
  if (!lockedItemIds) return false;
  return lockedItemIds.some((id) => id === itemId);
};
export const filterUnlockedItems = (
  items: InventoryItemsData,
  lockedItemIds: ItemIds[] | undefined,
): InventoryItemsData => {
  if (!lockedItemIds || lockedItemIds.length === 0) return items;
  return items.filter((item) => !isItemLocked(lockedItemIds, item?.id));
};
