import { SkillIdNumberDictionary } from "../../data/AllTypes/SkillsSpecificTypes.ts";
import { PlayerData } from "../../data/AllTypes/PlayerDataTypes.ts";
import {
  calculateCombatLevel,
  calculateLevel,
  calculateProgress,
  calculateTotalLevel,
  calculateTotalXp,
} from "../../Components/Reducer/playerCalculations.ts";

import { SkillsId } from "../../data/skillsData/SkillsEnum.ts";
import { MAX_XP } from "../../data/Constants.ts";

interface Action {
  newXP: SkillIdNumberDictionary;
}

export function roundToTwoDecimals(value: number): number {
  return parseFloat(value.toFixed(2));
}

export function getXp(state: PlayerData, action: Action): PlayerData {
  const xpChangeObject = action.newXP;

  // Start with shared references
  let skills = state.skills;
  const skillsXp = { ...state.skillsXp };
  let levelUpOccurred = false;
  let combatLevelChanged = false;

  let levelUpInfo: { skillId: SkillsId | null; newLevel: number | null } = {
    skillId: null,
    newLevel: null,
  };

  for (const skillIdRaw in xpChangeObject) {
    const skillId = Number(skillIdRaw) as SkillsId;
    const oldXpData = state.skillsXp[skillId];
    const oldSkillData = state.skills[skillId];

    const newXp = Math.min(oldXpData.xp + (xpChangeObject[skillId] ?? 0), MAX_XP);
    const newLevel = calculateLevel(newXp);
    const progress = calculateProgress(newLevel, newXp);
    const deltaBoosted = oldSkillData.boostedLevel - oldSkillData.level;

    // Always update skillsXp
    skillsXp[skillId] = { xp: newXp, progress };

    // Only mutate skills if level changed
    if (newLevel > oldSkillData.level) {
      if (!levelUpOccurred) {
        skills = { ...state.skills }; // clone once lazily
        levelUpOccurred = true;
      }

      skills[skillId] = {
        ...oldSkillData,
        level: newLevel,
        boostedLevel: newLevel + deltaBoosted,
        maxedTimestamp: oldSkillData.maxedTimestamp ?? (newXp >= MAX_XP ? Date.now() : undefined),
      };

      levelUpInfo = { skillId, newLevel };

      // Mark if this affects combat level
      if (
        [
          // SkillsId.Attack,
          SkillsId.Melee,
          SkillsId.Defence,
          SkillsId.Hitpoints,
          SkillsId.Ranged,
          SkillsId.Magic,
          SkillsId.Prayer,
        ].includes(skillId)
      ) {
        combatLevelChanged = true;
      }
    }
  }

  // Only recalc combat level if relevant level changed
  let stats = state.stats;
  if (combatLevelChanged) {
    const s = skills;
    const newCombatLevel = calculateCombatLevel(
      // s[SkillsId.Attack].level,
      s[SkillsId.Melee].level,
      s[SkillsId.Defence].level,
      s[SkillsId.Hitpoints].level,
      s[SkillsId.Ranged].level,
      s[SkillsId.Magic].level,
      s[SkillsId.Prayer].level,
    );

    if (newCombatLevel !== state.stats.combatLevel) {
      stats = { ...state.stats, combatLevel: newCombatLevel };
    }
  }

  const newTotalXp = roundToTwoDecimals(calculateTotalXp({ ...state, skillsXp }));
  const newTotalLevel = calculateTotalLevel({ ...state, skills });

  const total =
    newTotalXp !== state.total.xp || newTotalLevel !== state.total.level
      ? { ...state.total, xp: newTotalXp, level: newTotalLevel }
      : state.total;

  // If nothing changed at all, return original reference
  if (!levelUpOccurred && total === state.total && stats === state.stats) {
    // Only XP progress updated — no new refs for unaffected parts
    return { ...state, skillsXp };
  }

  return {
    ...state,
    skills,
    skillsXp,
    stats,
    total,
    levelUpInfo,
  };
}
