export type PartialItemData = Partial<Record<number, ItemDataRaw>>;

const combineItems = (...itemSources: PartialItemData[]): PartialItemData => {
  const combinedItems: PartialItemData = {};
  itemSources.forEach((source) => {
    Object.keys(source).forEach((key) => {
      combinedItems[+key] = source[+key];
    });
  });
  return combinedItems;
};

export const getItemByReferenceFromId = (itemId: number): ItemDataByReference => {
  return { id: itemId, amount: 1 };
};

export const getItemDataFromId = (itemId: number): ItemDataRawFinal | null => {
  const res = AllItemsData[itemId] || (DynamicItemsData[itemId] as XpLampItemType);
  if (!res) return null;
  return {
    ...res,
    name: res.name || PLACEHOLDER_NAME,
    img: res.img || PLACEHOLDER_IMG,
  };
};

export function getAndMergeItemData(item: ItemDataByReference): ItemDataFinal {
  const itemData = getItemDataFromId(item.id);
  if (!itemData) {
    return {
      id: item.id,
      name: PLACEHOLDER_NAME,
      img: PLACEHOLDER_IMG,
      type: ItemType.DEFAULT,
      amount: item.amount,
      probability: item.probability,
    };
  }

  return {
    ...itemData,
    amount: item.amount,
    ...(item.probability !== undefined && { probability: item.probability }),
  };
}

export const getItemInfoFromId = (itemId: number | undefined): ItemDataRawFinal | null => {
  if (itemId === undefined) return null;
  const itemData = getItemDataFromId(itemId);
  if (!itemData) return null;
  return itemData;
};

export function getEquipmentInfo(item: ItemDataByReference | null | undefined) {
  if (!item) return null;
  const itemData = getAndMergeItemData(item) as EquiptableItemType;
  return itemData?.equipmentInfo;
}

export function getEquipmentStats(item: ItemDataByReference | null | undefined, combatPoints: number) {
  if (!item) return null;
  const itemData = getAndMergeItemData(item) as EquiptableItemType;
  if (itemData.equipmentStats === undefined) return null;
  const currentSlot = itemData.equipmentInfo?.slot;
  const slotMultiplier = getSlotMultiplier(currentSlot, combatPoints);
  const newStats = Object.entries(itemData.equipmentStats).reduce<ValidEquiptmentStatsDictionary>(
    (acc, [key, value]) => {
      acc[key as keyof ValidEquiptmentStatsDictionary] = Number((value * slotMultiplier).toFixed(2));
      return acc;
    },
    {} as ValidEquiptmentStatsDictionary,
  );
  return newStats;
}
