export function getItemType(item: ItemDataByReference | null | undefined) {
  if (!item) return null;
  const itemData = getAndMergeItemData(item);
  return itemData.type;
}

export const AllItemsData: PartialItemData = combineItems(
  HeadData,
  BodyData,
  LegsData,
  ShieldData,
  RingData,
  AmmoData,
  NeckData,
  PetData,
  WeaponData,
  DefaultData,
  CapeData,
  FoodData,
  PotionData,
  FeetSlotItems,
  ExtraContainerItems,
  ClueItems,
  OpenableItems,
);
