import { ImageMap } from "../../data/ImageMap.ts";
import { GAME_NAME, isDemo } from "../../data/Constants.ts";

type RockyIdleProps = {
  isSmall?: boolean;
};

const RockyIdle = ({ isSmall = false }: RockyIdleProps) => {
  return (
    <div className="flex gap-2 mb-4 items-center uppercase text self-center mx-auto w-full justify-center relative">
      <img
        src={ImageMap.logoIcon}
        alt="logo"
        className={`${
          isSmall ? "w-12 h-12 sm:w-16 sm:h-16" : "w-20 h-20 sm:w-24 sm:h-24"
        } object-contain rounded modal-slide-in-small`}
      />

      <div className="relative">
        <h1
          className={`${
            isSmall ? "text-3xl sm:text-5xl" : "text-4xl sm:text-7xl"
          } leading-none font-semibold text-shadow`}
        >
          {GAME_NAME}
        </h1>
        {isDemo && (
          <span
            className="absolute -bottom-3 right-0 transform translate-y-1
                 text-xs sm:text-sm
                 bg-gradient-to-r from-selectColor to-selectColor
                 text-white px-2 py-0.5 rounded font-bold shadow-lg
                 tracking-widest border border-borderColor"
          >
            DEMO VERSION
          </span>
        )}
      </div>
    </div>
  );
};

export default RockyIdle;
