import { CSSProperties, useState } from "react";
import { ItemDataByReference } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { getImageSource } from "../../../data/utilData/ImagesUtils/GetImageUtil.ts";
import SkeletonLoadingFillParent from "../../SkeletonLoading/SkeletonLoadingFillParent.tsx";

type ItemWithAmountProps = {
  item: ItemDataByReference;
  amount: number;
  imageClassName?: string;
  containerClassName?: string;
  skeletonClassName?: string;
  style?: CSSProperties;
  skeletonType?: "skeleton" | "skeleton-dark" | "skeleton-light";
};

const ImgGetImageSourceWithSkeletonLoading = ({
  item,
  containerClassName,
  imageClassName,
  style,
  amount,
  skeletonClassName,
  skeletonType,
}: ItemWithAmountProps) => {
  const [imageLoaded, setImageLoaded] = useState(false);

  return (
    <div className={`${containerClassName}`}>
      {!imageLoaded && (
        <SkeletonLoadingFillParent skeletonType={skeletonType} className={skeletonClassName} />
      )}
      <img
        style={style}
        src={getImageSource(item, amount)}
        alt={"image"}
        onLoad={() => setImageLoaded(true)}
        onError={() => setImageLoaded(false)}
        className={`pointer-events-none ${imageClassName}   ${imageLoaded ? "" : "hidden"}`}
      />
    </div>
  );
};

export default ImgGetImageSourceWithSkeletonLoading;
