import { useRefreshAccessToken } from "../DatabaseSearch/useRefreshToken.ts";
import { useEffect } from "react";
import { jwtDecode } from "jwt-decode";
import { REFRESH_MARGIN, SHOULD_SAVE } from "../../data/Constants.ts";
import { useAuthStore } from "./useAuthToken.ts";
import { useHandleApiError } from "./useHandleApiError.tsx";

export const useTokenRefresh = (isLoggedIn: boolean, logout: () => void) => {
  const { mutate: refreshAccessToken } = useRefreshAccessToken();
  const { refreshToken: storedRefreshToken, saveTokens, accessToken } = useAuthStore();
  const { handleApiError } = useHandleApiError();

  const refreshToken = () => {
    if (!storedRefreshToken) {
      logout();
      return;
    }
    refreshAccessToken(
      { refreshToken: storedRefreshToken },
      {
        onSuccess: (data) => {
          saveTokens({ accessToken: data.accessToken, refreshToken: data.refreshToken });
        },
        onError: (error) => handleApiError(error, "Failed to refresh token"),
      },
    );
  };

  useEffect(() => {
    if (!SHOULD_SAVE(location) || !isLoggedIn) {
      return;
    }
    const checkToken = () => {
      if (!accessToken) {
        refreshToken();
        return;
      }
      const decoded = jwtDecode<{ exp: number }>(accessToken);
      const expirationTime = decoded.exp * 1000;
      const refreshTime = expirationTime - REFRESH_MARGIN; // Refresh 30 minutes before expiration
      const currentTime = Date.now();
      if (currentTime >= refreshTime || !accessToken) {
        refreshToken();
      }
    };

    const refreshInterval = setInterval(
      () => {
        checkToken();
      },
      10 * 60 * 1000,
    );

    const handleVisibilityChange = () => {
      if (document.visibilityState === "visible") {
        checkToken();
      }
    };

    document.addEventListener("visibilitychange", handleVisibilityChange);

    return () => {
      clearInterval(refreshInterval);
      document.removeEventListener("visibilitychange", handleVisibilityChange);
    };
  }, [isLoggedIn, accessToken]);
  return { refreshToken };
};
