import React, { createContext, ReactNode, useContext, useState } from "react";
import { ItemDataByReference } from "../data/AllTypes/PlayerDataTypes.ts";
import { useGetContract, usePlayerStore } from "./usePlayerStore.ts";
import { useToastStore } from "./ToastStore.ts";
import ToasterWithEvent from "../Components/UtilityComponents/Toasts/ToasterWithEvent.tsx";
import { ContractDifficultyIds } from "../data/utilData/ClueData/ClueScrollTypes.ts";
import { ClueScrollInfoMap } from "../data/utilData/ClueData/AllClueScrollData.ts";
import { SkillIdNumberDictionary } from "../data/AllTypes/SkillsSpecificTypes.ts";
import { getPrayerIdFromPrayerBook } from "../data/utilData/AllPrayers.ts";

interface ModalContextProps {
  isXpLampModalOpen: boolean;
  isPrayerModalOpen: boolean;
  isWarningModalOpen: boolean;
  currentXpLampItem: ItemDataByReference | null;
  currentPrayerItem: ItemDataByReference | null;
  currentDroppingItem: ItemDataByReference | null;
  openXpLampModal: (item: ItemDataByReference) => void;
  closeXpLampModal: () => void;
  openPrayerModal: (item: ItemDataByReference) => void;
  closePrayerModal: () => void;
  openWarningModal: (item: ItemDataByReference) => void;
  closeWarningModal: () => void;
  currentClueDifficulty: ContractDifficultyIds | null;
  closeCurrentClue: () => void;
  openCurrentClue: (difficulty: ContractDifficultyIds | null) => void;
  handleUseXpLampConfirm: (e: React.MouseEvent, xpObject: SkillIdNumberDictionary) => void;
  handleUnlockPrayerConfirm: (e: React.MouseEvent) => void;
  handleGetClueReward: (e: React.MouseEvent) => void;
  handleCompleteDropItem: () => void;
}

const ModalContext = createContext<ModalContextProps | undefined>(undefined);

export const useModalContext = () => {
  const context = useContext(ModalContext);
  if (!context) {
    throw new Error("useModalContext must be used within a ModalProvider");
  }
  return context;
};

// Modal Provider
export const ModalProvider = ({ children }: { children: ReactNode }) => {
  const [isXpLampModalOpen, setIsXpLampModalOpen] = useState(false);
  const [isPrayerModalOpen, setIsPrayerModalOpen] = useState(false);
  const [isWarningModalOpen, setIsWarningModalOpen] = useState(false);
  const [currentXpLampItem, setCurrentXpLampItem] = useState<ItemDataByReference | null>(null);
  const [currentPrayerItemRef, setCurrentPrayerItemRef] = useState<ItemDataByReference | null>(null);
  const [currentDroppingItem, setCurrentDroppingItem] = useState<ItemDataByReference | null>(null);
  const [currentClueDifficulty, setCurrentClueDifficulty] = useState<ContractDifficultyIds | null>(null);

  const useOneItem = usePlayerStore((state) => state.useOneItem);
  const currentClues = useGetContract();
  const addToast = useToastStore((state) => state.addToast);
  const unlockPrayer = usePlayerStore((state) => state.unlockPrayer);

  const openCurrentClue = (difficulty: ContractDifficultyIds | null) => {
    setCurrentClueDifficulty(difficulty);
  };

  const closeCurrentClue = () => {
    setCurrentClueDifficulty(null);
  };

  const openXpLampModal = (item: ItemDataByReference) => {
    setCurrentXpLampItem(item);
    setIsXpLampModalOpen(true);
  };

  const closeXpLampModal = () => {
    setIsXpLampModalOpen(false);
    setCurrentXpLampItem(null);
  };

  const openPrayerModal = (item: ItemDataByReference) => {
    setCurrentPrayerItemRef(item);
    setIsPrayerModalOpen(true);
  };

  const closePrayerModal = () => {
    setIsPrayerModalOpen(false);
    setCurrentPrayerItemRef(null);
  };

  const openWarningModal = (item: ItemDataByReference) => {
    setCurrentDroppingItem(item);
    setIsWarningModalOpen(true);
  };

  const closeWarningModal = () => {
    setIsWarningModalOpen(false);
    setCurrentDroppingItem(null);
  };

  const handleCompleteDropItem = () => {
    if (currentDroppingItem === null) return;
    setCurrentDroppingItem(null);
    closeWarningModal();
  };

  const handleGetClueReward = (e: React.MouseEvent) => {
    if (!currentClueDifficulty || !currentClues) return;
    const currentRewards = ClueScrollInfoMap[currentClueDifficulty]?.rewards;
    if (!currentRewards) return;
    addToast(<ToasterWithEvent xp={null} itemGain={currentRewards} itemCost={null} mouseEvent={e} />, 1000);
    closeCurrentClue();
  };

  const handleUnlockPrayerConfirm = (e: React.MouseEvent) => {
    if (!currentPrayerItemRef) return;
    useOneItem(currentPrayerItemRef);
    const oneItem = { ...currentPrayerItemRef, amount: 1 };
    addToast(<ToasterWithEvent xp={null} itemGain={null} itemCost={[oneItem]} mouseEvent={e} />, 1000);
    const prayerId = getPrayerIdFromPrayerBook(currentPrayerItemRef.id);
    if (!prayerId) return;
    unlockPrayer(prayerId);
  };
  const handleUseXpLampConfirm = (e: React.MouseEvent, xpObject: SkillIdNumberDictionary) => {
    if (!currentXpLampItem) return;
    const oneItem = { ...currentXpLampItem, amount: 1 };
    addToast(<ToasterWithEvent xp={xpObject} itemGain={null} itemCost={[oneItem]} mouseEvent={e} />, 1000);
    useOneItem(currentXpLampItem);
    closeXpLampModal();
  };

  return (
    <ModalContext.Provider
      value={{
        isXpLampModalOpen,
        isPrayerModalOpen,
        isWarningModalOpen,
        currentXpLampItem,
        currentPrayerItem: currentPrayerItemRef,
        currentDroppingItem,
        currentClueDifficulty,
        openXpLampModal,
        closeXpLampModal,
        openPrayerModal,
        closePrayerModal,
        openWarningModal,
        closeWarningModal,
        handleUseXpLampConfirm,
        handleUnlockPrayerConfirm,
        openCurrentClue,
        closeCurrentClue,
        handleGetClueReward,
        handleCompleteDropItem,
      }}
    >
      {children}
    </ModalContext.Provider>
  );
};
