import { useMediaQuery } from "./useMediaQuery.tsx";

export function useDeviceType() {
  const isMobile = useMediaQuery("(max-width: 639px)"); // Matches up to 'sm'
  const isTablet = useMediaQuery("(min-width: 640px) and (max-width: 1023px)"); // Matches between 'sm' and 'lg'
  const isDesktop = useMediaQuery("(min-width: 1024px) and (max-width: 1279px)"); // Matches between 'lg' and 'xl'
  const isLargeDesktop = useMediaQuery("(min-width: 1280px) and (max-width: 1535px)");
  const isXLargeDesktop = useMediaQuery("(min-width: 1536px)");

  return {
    isMobile, // Matches below 'sm' (up to 639px)
    isTablet, // Matches 'sm' and 'md' breakpoints (640px to 1023px)
    isDesktop, // Matches 'lg' breakpoints (1024px to 1279px)
    isLargeDesktop, // Matches between 'xl' and '2xl'
    isXLargeDesktop, // Matches '2xl' and above
  };
}
