import forestBgMobile from "../../src/assets/backgrounds/forest_mobile.webp";
import forestBg from "../../src/assets/backgrounds/forest.webp";
import { useDeviceType } from "./useDeviceType.tsx";
import LoadingComponent from "../Components/UtilityComponents/LoadingComponent.tsx";

const LoadingScreen = () => {
  const { isMobile } = useDeviceType();

  const backgroundImage = isMobile ? `url(${forestBgMobile})` : `url(${forestBg})`;

  return (
    <div
      className="bg-green-500 text-white w-screen h-screen fixed inset-0 flex items-center justify-center"
      style={{
        backgroundImage: backgroundImage,
        backgroundPosition: "center 80%",
      }}
    >
      <LoadingComponent />
    </div>
  );
};

export default LoadingScreen;
