export const checkItemCostAndAmount = (
  itemCost: ItemDataByReference[] | null,
  currentLootMultiplier: number,
  state: PlayerData,
  active: boolean,
  stopProcess: () => void,
  addToast: AddToastFunctionType,
): boolean => {
  if (itemCost) {
    const inventory = state.items.inventory;
    for (const cost of itemCost) {
      if (cost?.amount && cost.id) {
        const existingItemIndex = inventory?.findIndex((inventoryItem) => inventoryItem?.id === cost.id);
        const existingItem = inventory?.[existingItemIndex];
        if (!existingItem) {
          stopProcess();
          if (active) {
            addToast(<ErrorToaster message="Not enough items" />, 1000);
          }
          return false;
        }
        if (
          existingItemIndex === -1 ||
          (inventory && existingItemIndex && existingItem?.amount < cost.amount * currentLootMultiplier)
        ) {
          stopProcess();
          if (active) {
            addToast(<ErrorToaster message="Not enough items" />, 1000);
          }
          return false; // Return false if any item doesn't meet the requirement
        }
      }
    }
  }
  return true;
};

export const calculateItemProbability = (
  item: ItemDataByReference,
  // itemGain: ItemDataByReference[],
  probabilityMultiplier: number,
): number | null => {
  const itemData = getAndMergeItemData(item);
  // let probability = itemData.probability ?? calculateLastDropProbability(itemGain);
  let probability = itemData.probability ?? 1;

  // Apply probabilityMultiplier **only if the item is a Pet**
  if (itemData.type === ItemType.PET && probability) {
    probability *= probabilityMultiplier;
  }

  return probability;
};

