export const rollItemWithProbability = (
  items: ItemDataByReference[] | null | undefined,
  lootMultiplier: number = 1,
): ItemDataByReference[] => {
  if (!items || !items.length) return [];

  // First apply the same logic used everywhere else
  const normalizedItems = adjustLootAmountsAndProbabilities(items, lootMultiplier);
  // Keep items that can be rolled (probability exists)
  const itemsWithProbability = normalizedItems.filter((item) => item.probability !== undefined);
  const itemsWithoutProbability = normalizedItems.filter((item) => item.probability === undefined);

  if (itemsWithProbability.length === 0) {
    return normalizedItems;
  }

  // Build a probability list (probability already adjusted)
  const totalProbability = itemsWithProbability.reduce((sum, item) => sum + (item.probability ?? 0), 0);

  // Normalize when total > 1
  const adjustedItems =
    totalProbability > 1
      ? itemsWithProbability.map((item) => ({
          ...item,
          probability: (item.probability ?? 0) / totalProbability,
        }))
      : itemsWithProbability;

  // RNG roll
  const randomNumber = Math.random();
  let acc = 0;

  for (const item of adjustedItems) {
    acc += item.probability ?? 0;
    if (randomNumber <= acc) {
      return [item]; // return rolled item
    }
  }

  // If nothing rolled, return fallback
  return itemsWithoutProbability.length > 0
    ? [itemsWithoutProbability[itemsWithoutProbability.length - 1]]
    : [];
};

export const simulateRolls = (items: ItemDataByReference[], numberOfSimulations: number) => {
  const resultMap = new Map();

  for (let i = 0; i < numberOfSimulations; i++) {
    const rolledItems = rollItemWithProbability(items);

    for (const rolledItem of rolledItems) {
      if (resultMap.has(rolledItem.id)) {
        const existingItem = resultMap.get(rolledItem.id);
        existingItem.amount += rolledItem.amount;
        resultMap.set(rolledItem.id, existingItem);
      } else {
        resultMap.set(rolledItem.id, { ...rolledItem });
      }
    }
  }

  // Convert the map to an array
  return Array.from(resultMap.values()) as ItemDataByReference[];
};

export const getProcessLevelInfoFromAmount = (
  processCompletedAmount: number,
  tier: number | undefined,
): ProcessCompletedMapType[ProcessLevelIds] | null => {
  const selectedIndex = getTierIndexFromAmount(processCompletedAmount, tier);
  if (selectedIndex === null) return null;
  const processLevelsArray = Object.keys(ProcessCompletedMap) as any as ProcessLevelIds[];
  const processLevelKey = processLevelsArray[selectedIndex];

  return processLevelKey ? ProcessCompletedMap[processLevelKey] : null;
};

export const getLevelInfoFromAmount = (
  runId: RunIds | undefined | boolean,
  processCompletedAmount: number,
  tier: number | undefined,
): RunCompletedMapType[ProcessLevelIds] | ProcessCompletedMapType[ProcessLevelIds] | null => {
  if (runId) return getRunLevelInfoFromAmount(processCompletedAmount, tier);
  return getProcessLevelInfoFromAmount(processCompletedAmount, tier);
};
export const getMonsterCompletedMapInfo = (killcount: number | undefined, tier: number | undefined) => {
  return getCombatInfoFromAmount(killcount, tier);
};

export const getRunLevelInfoFromAmount = (
  processCompletedAmount: number | undefined,
  tier: number | undefined,
): RunCompletedMapType[ProcessLevelIds] | null => {
  const selectedIndex = getTierIndexFromAmount(processCompletedAmount, tier);

  if (selectedIndex === null) return null;
  const processLevelsArray = Object.keys(RunCompletedMap) as any as ProcessLevelIds[];
  const processLevelKey = processLevelsArray[selectedIndex];
  return processLevelKey ? RunCompletedMap[processLevelKey as ProcessLevelIds] : null;
};

export const getCombatInfoFromAmount = (
  killcount: number | undefined,
  tier: number | undefined,
): ProcessCompletedMapType[ProcessLevelIds] | null => {
  const selectedIndex = getTierIndexFromAmount(killcount, tier);
  if (selectedIndex === null) return null;
  const processLevelsArray = Object.keys(CombatCompletedMap) as any as ProcessLevelIds[];
  const processLevelKey = processLevelsArray[selectedIndex];
  return processLevelKey ? CombatCompletedMap[processLevelKey] : null;
};

export const getTierIndexFromAmount = (
  processCompletedAmount: number | undefined,
  tier: number | undefined,
): number | null => {
  if (tier === undefined || tier >= Object.keys(Tiers).length) return null;
  const tierInfos = Tiers[tier as keyof typeof Tiers];
  if ((processCompletedAmount ?? 0) < tierInfos[0]) {
    return null;
  }
  const tierIndex = tierInfos.findIndex((tierAmount) => (processCompletedAmount ?? 0) < tierAmount);
  // If tierIndex is -1, the amount exceeds the highest tier amount, return the highest tier
  return tierIndex === -1 ? tierInfos.length - 1 : tierIndex - 1;
};

export const amountTillNextTierIndex = (processCompletedAmount: number, tier: number) => {
  const tierThresholds = Tiers[tier];
  const currentTierIndex = getTierIndexFromAmount(processCompletedAmount, tier);
  const nextTierIndex = currentTierIndex !== null ? currentTierIndex + 1 : 0;
  const nextTierAtAmount = tierThresholds[nextTierIndex] ?? Infinity;
  const missingAmountForNextTier = nextTierAtAmount - processCompletedAmount;
  return missingAmountForNextTier;
};

export const getTierInfoFromResourcesTier = (tier: number | undefined): number[] | [] => {
  if (tier === undefined) return [];
  return Tiers[tier as keyof typeof Tiers];
};

export const getCurrentProcessLevelAmount = (
  processCompletedAmount: number,
  resourceTier: number | undefined,
) => {
  const tierIndex = getTierIndexFromAmount(processCompletedAmount, resourceTier);
  const currentTierValues = getTierInfoFromResourcesTier(resourceTier);
  return tierIndex !== null ? currentTierValues[tierIndex] : 0;
};
