import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { Shortcut, ShortcutType } from "../../../data/AllTypes/ShortcutTypes.ts";
import { MonsterIds } from "../../../data/MonsterData/MonsterIds.ts";
import { QuestIds } from "../../../data/Quest/QuestIds.ts";
import { DiaryIds } from "../../../data/AchievementDiaries/DiaryTypes.ts";
import { Difficulty } from "../../../data/AllTypes/DiaryTypes.ts";
import { ResourceIds } from "../../../data/skillsData/ResourceIds.ts";
import { SkillsId } from "../../../data/skillsData/SkillsEnum.ts";
import { MAX_SHORTCUTS } from "../../../data/Constants.ts";

type AddShortcutAction =
  | {
      type: ShortcutType.MONSTER;
      monsterId: MonsterIds;
    }
  | {
      type: ShortcutType.QUEST;
      questId: QuestIds;
    }
  | {
      type: ShortcutType.DIARY;
      diaryId: DiaryIds;
      difficulty: Difficulty;
    }
  | {
      type: ShortcutType.RESOURCE;
      resourceId: ResourceIds;
    }
  | {
      type: ShortcutType.SKILL;
      skillId: SkillsId | "Combat";
    };

/**
 * Adds a new shortcut to the shortcuts array
 * Generates a unique ID and assigns the next order number
 */
export function addShortcut(state: PlayerData, action: AddShortcutAction): PlayerData {
  const shortcuts = state.shortcuts ?? [];
  
  // Check if maximum shortcuts limit is reached
  if (shortcuts.length >= MAX_SHORTCUTS) {
    // Return state unchanged if limit reached
    return state;
  }
  
  const maxOrder = shortcuts.length > 0 ? Math.max(...shortcuts.map((s) => s.order)) : -1;
  const nextOrder = maxOrder + 1;

  // Generate unique ID (using timestamp + random for uniqueness)
  const id = `${action.type}_${Date.now()}_${Math.random().toString(36).substring(2, 9)}`;

  let newShortcut: Shortcut;

  switch (action.type) {
    case ShortcutType.MONSTER:
      newShortcut = {
        id,
        type: ShortcutType.MONSTER,
        monsterId: action.monsterId,
        order: nextOrder,
      };
      break;
    case ShortcutType.QUEST:
      newShortcut = {
        id,
        type: ShortcutType.QUEST,
        questId: action.questId,
        order: nextOrder,
      };
      break;
    case ShortcutType.DIARY:
      newShortcut = {
        id,
        type: ShortcutType.DIARY,
        diaryId: action.diaryId,
        difficulty: action.difficulty,
        order: nextOrder,
      };
      break;
    case ShortcutType.RESOURCE:
      newShortcut = {
        id,
        type: ShortcutType.RESOURCE,
        resourceId: action.resourceId,
        order: nextOrder,
      };
      break;
    case ShortcutType.SKILL:
      newShortcut = {
        id,
        type: ShortcutType.SKILL,
        skillId: action.skillId,
        order: nextOrder,
      };
      break;
  }

  // Check if shortcut already exists (prevent duplicates)
  const existingShortcut = shortcuts.find((shortcut) => {
    switch (action.type) {
      case ShortcutType.MONSTER:
        return shortcut.type === ShortcutType.MONSTER && shortcut.monsterId === action.monsterId;
      case ShortcutType.QUEST:
        return shortcut.type === ShortcutType.QUEST && shortcut.questId === action.questId;
      case ShortcutType.DIARY:
        return (
          shortcut.type === ShortcutType.DIARY &&
          shortcut.diaryId === action.diaryId &&
          shortcut.difficulty === action.difficulty
        );
      case ShortcutType.RESOURCE:
        return shortcut.type === ShortcutType.RESOURCE && shortcut.resourceId === action.resourceId;
      case ShortcutType.SKILL:
        return shortcut.type === ShortcutType.SKILL && shortcut.skillId === action.skillId;
    }
  });

  if (existingShortcut) {
    // Shortcut already exists, return state unchanged
    return state;
  }

  return {
    ...state,
    shortcuts: [...shortcuts, newShortcut],
  };
}

