import { create } from "zustand";
import { persist } from "zustand/middleware";
import { ALL, LOOT_OPTIONS, LootOption } from "../../data/Constants.ts";
import { BankSortType } from "../../Pages/BankSort.tsx";

// Define all persistent state you want to keep
interface PersistentState {
  lootOption: LootOption;
  setLootOption: (option: LootOption) => void;

  showCompleted: boolean;
  setShowCompleted: (show: boolean) => void;

  showIncompletable: boolean;
  setShowIncompletable: (show: boolean) => void;

  // --- Bank / Deposit ---
  currentDepositAmount: number | string;
  setCurrentDepositAmount: (amount: number | string) => void;

  // --- Shop ---
  currentBuyAmount: number | string;
  setCurrentBuyAmount: (amount: number | string) => void;

  insertMode: boolean;
  setInsertMode: (mode: boolean) => void;

  // --- SavingHeader visibility ---
  showSavingHeader: boolean;
  setShowSavingHeader: (visible: boolean) => void;

  deathModalShown: boolean;
  setDeathModalShown: (shown: boolean) => void;

  lastSteamAchievementCheck: number;
  setLastSteamAchievementCheck: (ts: number) => void;

  forceSteamAchievementCheck: number;
  setForceSteamAchievementCheck: (force: number) => void;
  // showWelcomeBackModal: boolean;
  // setShowWelcomeBackModal: (shown: boolean) => void;
  lastSeenPatchVersion: string;
  setLastSeenPatchVersion: (version: string) => void;

  uiScale: number;
  setUiScale: (scale: number) => void;

  isPowerSaveModeSteam: boolean;
  setIsPowerSaveModeSteam: (enabled: boolean) => void;

  isPowerSaveModeWeb: boolean;
  setIsPowerSaveModeWeb: (enabled: boolean) => void;

  isFullScreenMode: boolean;
  setIsFullScreenMode: (enabled: boolean) => void;

  bankSortMode: BankSortType | null;
  setBankSortMode: (mode: BankSortType) => void;
}

export const usePersistentStore = create<PersistentState>()(
  persist(
    (set) => ({
      lootOption: LOOT_OPTIONS.LOOT_ON_GROUND,
      setLootOption: (option) => set({ lootOption: option }),

      showCompleted: true,
      setShowCompleted: (show) => set({ showCompleted: show }),

      showIncompletable: true,
      setShowIncompletable: (show) => set({ showIncompletable: show }),

      currentDepositAmount: ALL,
      setCurrentDepositAmount: (amount) => set({ currentDepositAmount: amount }),

      currentBuyAmount: 1,
      setCurrentBuyAmount: (amount) => set({ currentBuyAmount: amount }),

      insertMode: false,
      setInsertMode: (mode) => set({ insertMode: mode }),

      showSavingHeader: true,
      setShowSavingHeader: (visible) => set({ showSavingHeader: visible }),

      deathModalShown: false,
      setDeathModalShown: (shown) => set({ deathModalShown: shown }),

      lastSteamAchievementCheck: 0,
      setLastSteamAchievementCheck: (ts) => set({ lastSteamAchievementCheck: ts }),

      forceSteamAchievementCheck: 0,
      setForceSteamAchievementCheck: (force) => set({ forceSteamAchievementCheck: force }),

      bankSortMode: null,
      setBankSortMode: (mode) => set({ bankSortMode: mode }),

      lastSeenPatchVersion: "v0.0.0",
      setLastSeenPatchVersion: (version) => set({ lastSeenPatchVersion: version }),
      uiScale: 1.0, // Default 100%
      setUiScale: (scale) => {
        set({ uiScale: scale });
        if (window.electronAPI) {
          window.electronAPI.setZoom(scale);
        }
      },
      isPowerSaveModeSteam: false,
      setIsPowerSaveModeSteam: (enabled: boolean) => {
        set({ isPowerSaveModeSteam: enabled });
        if (window.electronAPI?.setPowerSaveMode) {
          window.electronAPI.setPowerSaveMode(enabled);
        }
      },
      isPowerSaveModeWeb: true,
      setIsPowerSaveModeWeb: (enabled: boolean) => {
        set({ isPowerSaveModeWeb: enabled });
      },

      isFullScreenMode: true,
      setIsFullScreenMode: (enabled: boolean) => {
        if (window.electronAPI?.setFullScreen) {
          set({ isFullScreenMode: enabled });
          window.electronAPI.setFullScreen(enabled);
        }
      },
    }),
    {
      name: "persistent-state",
      onRehydrateStorage: () => (state) => {
        if (state && window.electronAPI) {
          window.electronAPI.setZoom(state.uiScale);
          window.electronAPI.setPowerSaveMode(state.isPowerSaveModeSteam);
          window.electronAPI.setFullScreen(state.isFullScreenMode);
        }
      },
    },
  ),
);
