export const hasExtraStorageInInventory = (
  inventory: InventoryItemsData,
  itemIds: extraStorageItemIds | null,
): boolean => {
  if (!itemIds) return true;
  return inventory.some((item) => item?.id === itemIds);
};

export const placeItemInContainer = (
  container: InventoryItemsData,
  item: ItemDataByReference,
  amount: number,
): InventoryItemsData => {
  let updatedContainer = container;
  // Check if the item already exists in the container
  const existingItemIndex = updatedContainer.findIndex((containerItem) => containerItem?.id === item.id);
  if (existingItemIndex !== -1) {
    // If the item exists, update its amount
    updatedContainer = updatedContainer.map((slot, index) =>
      index === existingItemIndex && slot !== null ? { ...slot, amount: slot.amount + amount } : slot,
    );
    return updatedContainer;
  }

  // If the item don't exist, place it in the first empty (null) slot
  const emptySlotIndex: number = updatedContainer.findIndex((slot) => slot === null);
  if (emptySlotIndex !== -1) {
    updatedContainer = updatedContainer.map((slot, index) =>
      index === emptySlotIndex ? { id: item.id, amount: amount } : slot,
    );
    return updatedContainer;
  }
  return updatedContainer;
};

