export const currentItemsToShow = (
  items: playerItemsType,
  currentInventoryState: InventoryStates,
): InventoryItemsData => {
  return items[currentInventoryState] ?? items["inventory"];
};

export function getContainerIdByUnlockItemId(unlockItemId: number): StorageIds | undefined {
  for (const [containerIdStr, config] of Object.entries(CONTAINERS_CONFIG)) {
    if (config.unlockItemId === unlockItemId) {
      return Number(containerIdStr) as StorageIds;
    }
  }
  return undefined;
}

export const getItemsFromAllContainers = (playerItems: playerItemsType): InventoryItemsData => {
  const allItems: InventoryItemsData = [...playerItems.inventory];
  for (const [containerId, config] of Object.entries(CONTAINERS_CONFIG)) {
    const containerKey = Number(containerId) as InventoryStates;
    const unlockItemId = config.unlockItemId;
    const hasUnlockItem = hasExtraStorageInInventory(playerItems.inventory, unlockItemId);
    if (hasUnlockItem) {
      const containerItems = playerItems[containerKey];
      if (containerItems) {
        allItems.push(...containerItems);
      }
    }
  }

  return allItems;
};
export function ensureValidContainers(originalContainers: playerItemsType): playerItemsType {
  const fixed: playerItemsType = { ...originalContainers };

  for (const config of Object.values(CONTAINERS_CONFIG)) {
    const containerId = config.id;
    const capacity = config.capacity;
    const original = originalContainers[containerId];
    const items = Array.isArray(original) ? original.slice(0, capacity) : [];
    while (items.length < capacity) items.push(null);
    fixed[containerId] = items;
  }
  return fixed;
}

export const getTotalAmountOfItemFromAllContainers = (
  itemId: ItemIds,
  playerItems: playerItemsType,
): number => {
  let total = 0;
  //todo make a util that based on the playerItems returns all the containers, maybe not the bank
  const allItems = getItemsFromAllContainers(playerItems);
  allItems.forEach((item) => {
    if (item && item.id === itemId) {
      total += item.amount;
    }
  });
  return total;
};

export const getTotalAmountOfItemsFromAllContainers = (
  itemCost: ItemDataByReference[] | null | undefined,
  playerItems: playerItemsType,
): ItemDataByReference[] => {
  const allItems = getItemsFromAllContainers(playerItems);
  if (!itemCost || itemCost.length === 0) return [];
  const totalsMap: Record<ItemIds, number> = {} as Record<ItemIds, number>;
  itemCost.forEach(({ id }) => {
    totalsMap[id] = 0;
  });

  allItems.forEach((item) => {
    if (item && item.id in totalsMap) {
      totalsMap[item.id] += item.amount;
    }
  });

  return Object.entries(totalsMap).map(([id, amount]) => ({
    id: Number(id) as ItemIds,
    amount,
  }));
};

export function normalizeItems(items: ItemDataByReference[]): ItemDataBase[] {
  return items.map(({ id, amount }) => ({
    id,
    amount: Math.round(amount),
  }));
}
