import { MonsterIds } from "../../../data/MonsterData/MonsterIds.ts";
import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";

type AddOfflineMonsterAction = {
  monsterId: MonsterIds;
};

export function addOfflineMonster(state: PlayerData, action: AddOfflineMonsterAction): PlayerData {
  const { monsterId } = action;
  const current = state.offlineMonsters || [];
  if (current.includes(monsterId)) {
    return state;
  }
  return {
    ...state,
    offlineMonsters: [...current, monsterId],
  };
}
