import {
  AchievementDiaryData,
  CompletedAchievementDiary,
  Difficulty,
  ValidDiaryStatus,
} from "../../data/AllTypes/DiaryTypes.ts";
import { AllAchievementDiaries } from "../../data/AchievementDiaries/AllAchievementDiaries.ts";
import { areQuestsCompleted, isSkillLevelRequirementMet } from "./QuestUtils.tsx";
import {
  InventoryItemsData,
  MonsterCompletedDictionary,
  ProcessCompletedDictionary,
} from "../../data/AllTypes/SkillsSpecificTypes.ts";
import {
  CompletedQuestsType,
  processesCompletedType,
  SkillsMapType,
} from "../../data/AllTypes/PlayerDataTypes.ts";
import {
  BOOST_EXTRA_EXPERT_SECONDS,
  BOOST_EXTRA_MEDIUM_SECONDS,
  EASY_DIARY_REWARD_MULTIPLIER,
  EXPERT_DIARY_REWARD_MULTIPLIER,
  TOTAL_DIARIES,
  TOTAL_DIARY_DIFFICULTY,
} from "../../data/Constants.ts";
import { MonsterIdDictionary } from "../../data/AllTypes/AttackStyleAndWeaponTypes.ts";
import { ResourceIds } from "../../data/skillsData/ResourceIds.ts";
import { getMonsterKillCount } from "../CombatStyle/Monster/MonsterUtils.ts";
import { DiaryIds, ValidDiaryIds } from "../../data/AchievementDiaries/DiaryTypes.ts";

import { SkillsId } from "../../data/skillsData/SkillsEnum.ts";
import React from "react";
import ErrorToasterWithEvent from "../UtilityComponents/Toasts/ErrorToasterWithEvent.tsx";
import { MonsterIds } from "../../data/MonsterData/MonsterInfoUtil.ts";

export const countCompletedDiaries = (completedAchievementDiary: CompletedAchievementDiary) => {
  let completedCount = 0;
  for (const diaryId in completedAchievementDiary) {
    const diaryIdAsNumber = Number(diaryId) as ValidDiaryIds;
    const diary = getDiaryObject(completedAchievementDiary, diaryIdAsNumber);
    if (diary) {
      for (const difficulty in diary) {
        if (
          diary[difficulty as Difficulty] === ValidDiaryStatus.Completed ||
          diary[difficulty as Difficulty] === ValidDiaryStatus.CompletedRewardPending
        ) {
          completedCount++;
        }
      }
    }
  }

  return completedCount;
};

export const countRewardNotTakenDiaries = (completedAchievementDiary: CompletedAchievementDiary) => {
  let completedCount = 0;
  for (const diaryId in completedAchievementDiary) {
    const diaryIdAsNumber = Number(diaryId) as ValidDiaryIds;
    const diary = getDiaryObject(completedAchievementDiary, diaryIdAsNumber);
    if (diary) {
      const notTakenRewardYetNumber = countCompletedNotRewarded(diary);
      completedCount += notTakenRewardYetNumber;
    }
  }

  return completedCount;
};

export const areAllDiariesCompleted = (completedAchievementDiary: CompletedAchievementDiary): boolean => {
  if (Object.keys(completedAchievementDiary).length === 0) {
    return false;
  }

  return Object.entries(AllAchievementDiaries).every(([diaryId, diary]) => {
    const diaryIdAsNumber = Number(diaryId) as ValidDiaryIds;

    return Object.keys(diary).every(
      (difficulty) =>
        completedAchievementDiary[diaryIdAsNumber]?.[difficulty as Difficulty] ===
          ValidDiaryStatus.Completed ||
        completedAchievementDiary[diaryIdAsNumber]?.[difficulty as Difficulty] ===
          ValidDiaryStatus.CompletedRewardPending,
    );
  });
};

export function getDiaryObject(
  completedAchievementDiary: CompletedAchievementDiary,
  diaryId: ValidDiaryIds,
): AchievementDiaryData | undefined {
  if (isCompletedAchievementDiary(completedAchievementDiary)) {
    return completedAchievementDiary[diaryId];
  }
  return undefined;
}
function isCompletedAchievementDiary(obj: any): obj is Record<ValidDiaryIds, AchievementDiaryData> {
  return obj && typeof obj === "object" && Object.keys(obj).every((key) => typeof key === "string");
}

export const isDiaryCompletedOrPendingWithToaster = (
  completedAchievementDiary: CompletedAchievementDiary,
  diaryId: ValidDiaryIds | undefined,
  difficulty: Difficulty | undefined,
  addToast: (toastComponent: React.ReactElement, timeout: number) => void,
  e: React.MouseEvent,
): boolean => {
  const isCompletedOrPending = isDiaryCompletedOrPending(completedAchievementDiary, diaryId, difficulty);
  if (!isCompletedOrPending) {
    addToast(<ErrorToasterWithEvent message="You need to have completed the diary" mouseEvent={e} />, 1000);
    return false;
  }
  return isCompletedOrPending;
};

export function isDiaryCompletedOrPending(
  completedAchievementDiary: CompletedAchievementDiary,
  diaryId: ValidDiaryIds | undefined,
  difficulty: Difficulty | undefined,
): boolean {
  if (!diaryId || !difficulty) return false;
  return (
    isDiaryCompleted(completedAchievementDiary, diaryId, difficulty) ||
    isDiaryCompletedWithRewardPending(completedAchievementDiary, diaryId, difficulty)
  );
}
export const isDiaryCompletedWithRewardPending = (
  completedAchievementDiary: CompletedAchievementDiary,
  diaryId: ValidDiaryIds,
  difficulty: Difficulty,
): boolean => {
  const diaryObject = getDiaryObject(completedAchievementDiary, diaryId);
  return diaryObject?.[difficulty] === ValidDiaryStatus.CompletedRewardPending;
};
export const isDiaryCompleted = (
  completedAchievementDiary: CompletedAchievementDiary,
  diaryId: ValidDiaryIds,
  difficulty: Difficulty,
): boolean => {
  const diaryObject = getDiaryObject(completedAchievementDiary, diaryId);
  return diaryObject?.[difficulty] === ValidDiaryStatus.Completed;
};

export function countCompletedNotRewarded(tasks: AchievementDiaryData | undefined): number {
  if (!tasks) return 0;
  return Object.values(tasks).filter((status) => status === ValidDiaryStatus.CompletedRewardPending).length;
}

export type CompletedDiaryEntry = {
  difficulty: Difficulty;
  diaryId: ValidDiaryIds;
  itemRewards: InventoryItemsData;
} | null;

export const checkDiaries = (
  completedAchievementDiary: CompletedAchievementDiary,
  skills: SkillsMapType,
  completedQuests: CompletedQuestsType,
  combatLevel: number,
  monsterKillStats: MonsterIdDictionary | null,
  processesCompleted: processesCompletedType | null,
) => {
  const completedDiaries: CompletedDiaryEntry[] = [];

  for (const [diaryId, diary] of Object.entries(AllAchievementDiaries)) {
    for (const difficultyRaw in diary.diaryInfo) {
      const difficulty = difficultyRaw as Difficulty;
      const diaryIdCast = Number(diaryId) as ValidDiaryIds;
      const diaryObject = getDiaryObject(completedAchievementDiary, diaryIdCast);
      if (!diaryObject || !isDiaryCompletedOrPending(completedAchievementDiary, diaryIdCast, difficulty)) {
        const { skillReq, questReq, combatLevelRequired, processReq, monsterReq, itemRewards } =
          diary.diaryInfo[difficulty];
        const requirementsMet = isSkillLevelRequirementMet(skills, skillReq);
        const questsRequirementsMet = areQuestsCompleted(completedQuests, questReq);
        const combatLevelRequirementMet = combatLevel >= (combatLevelRequired || 0);
        const processReqMet = isProcessReqMet(processesCompleted, processReq);
        const monsterKcReqMet = isMonsterKcReqMet(monsterKillStats, monsterReq);
        if (
          requirementsMet &&
          questsRequirementsMet &&
          combatLevelRequirementMet &&
          processReqMet &&
          monsterKcReqMet
        ) {
          completedDiaries.push({
            difficulty: difficulty,
            diaryId: diaryIdCast,
            itemRewards,
          });
        }
      }
    }
  }
  return completedDiaries;
};

export const isProcessReqMet = (
  processesCompleted: processesCompletedType | null,
  processReq: ProcessCompletedDictionary | undefined,
) => {
  if (!processesCompleted || !processReq) return true;
  return Object.entries(processReq).every(([processId, reqAmount]) => {
    const processIdAsNumber = Number(processId) as ResourceIds;
    const processCompleted = processesCompleted[processIdAsNumber];
    return processCompleted && processCompleted >= reqAmount;
  });
};
export const isMonsterKcReqMet = (
  monsterKillStats: MonsterIdDictionary | null,
  monsterReq: MonsterCompletedDictionary | undefined,
) => {
  if (!monsterKillStats) return false;
  if (!monsterReq) return true;
  return Object.entries(monsterReq).every(([monsterId, reqAmount]) => {
    const monsterIdAsNumber = Number(monsterId) as MonsterIds;
    const monsterKc = getMonsterKillCount(monsterKillStats, monsterIdAsNumber);
    return monsterKc && monsterKc >= reqAmount;
  });
};

export const getTotalDiariesCount = () => {
  return TOTAL_DIARIES * TOTAL_DIARY_DIFFICULTY;
};

export const getDiaryCompletionCount = (diaryObject: AchievementDiaryData | undefined) => {
  if (!diaryObject) return 0;
  return Object.values(diaryObject).filter(
    (completedDiaries) =>
      completedDiaries === ValidDiaryStatus.Completed ||
      completedDiaries === ValidDiaryStatus.CompletedRewardPending,
  ).length;
};

export const calculateDiaryProgress = (completedDiaries: number) => {
  return completedDiaries ? Math.floor((completedDiaries / TOTAL_DIARY_DIFFICULTY) * 100) : 0;
};

export const calculateDiaryFromSkill = (skillId: SkillsId): DiaryIds | undefined => {
  const diaryEntry = Object.entries(AllAchievementDiaries).find(([_, diaryInfo]) =>
    diaryInfo.associatedSkill?.includes(skillId),
  );

  return diaryEntry ? (diaryEntry[0] as unknown as DiaryIds) : undefined;
};

export function getDiarySkillText(difficulty: Difficulty, diaryId?: DiaryIds, skillId?: SkillsId): string {
  if (
    (diaryId === DiaryIds.FORTRESS && difficulty === Difficulty.EASY) ||
    (diaryId === DiaryIds.FORTRESS && difficulty === Difficulty.NERD)
  ) {
    return `Some Juicy loot`;
  }

  if (difficulty === Difficulty.MEDIUM) {
    return `+${BOOST_EXTRA_MEDIUM_SECONDS}s boost duration`;
  }
  if (difficulty === Difficulty.EXPERT) {
    return `+${BOOST_EXTRA_EXPERT_SECONDS}s boost duration`;
  }

  if (difficulty === Difficulty.HARD) {
    return `A nice place to store stuff`;
  }

  if (difficulty === Difficulty.NERD) {
    const percent = Math.round((EXPERT_DIARY_REWARD_MULTIPLIER - 1) * 100);
    return `+${percent}% Xp + Loot`;
  }

  if (difficulty === Difficulty.EASY) {
    const percent = Math.round((EASY_DIARY_REWARD_MULTIPLIER - 1) * 100);
    if (skillId === SkillsId.Farming) {
      return `+${percent}% Xp + Loot`;
    }
    return `+${percent}% Speed`;
  }

  return "";
}
