import TooltipWrapper from "./TooltipWrapper.tsx";
import TooltipContentWithAmountProb from "./TooltipContentWithAmountProb.tsx";

type ImageWithTooltipProps = {
  placement?: "top" | "right" | "bottom" | "left";
  icon: string;
  tooltipText?: string;
  className?: string;
};

const ImageWithTooltip = ({ placement, tooltipText, icon, className }: ImageWithTooltipProps) => {
  return (
    <TooltipWrapper
      content={<TooltipContentWithAmountProb itemName={tooltipText} />}
      className={"grid place-items-center"}
      placement={placement}
    >
      <img src={icon} alt={tooltipText} className={className} />
    </TooltipWrapper>
  );
};

export default ImageWithTooltip;
