import { PlayerData, ValidQuestStatus } from "../../data/AllTypes/PlayerDataTypes.ts";
import { QuestIds } from "../../data/Quest/QuestIds.ts";

export type QuestRewardGivenAction = {
  questId: QuestIds;
};
export function questRewardGiven(state: PlayerData, action: QuestRewardGivenAction): PlayerData {
  const { questId } = action;

  // Check if the quest exists and mark the reward as given
  if (state.completedQuests && state.completedQuests[questId]) {
    return {
      ...state,
      completedQuests: {
        ...state.completedQuests,
        // [questId]: { status: ValidQuestStatus.Completed },
        [questId]: ValidQuestStatus.Completed,
      },
    };
  }

  // Return the original state if the quest does not exist
  return state;
}
