export const SHOULD_SAVE = (location: Location): boolean => {
  return !UNSAVEABLE_WORDS.some((word) => {
    const lowerWord = word.toLowerCase(); // Ensure case insensitivity
    const path = location.pathname.toLowerCase();
    const hash = location.hash.toLowerCase();
    return path.includes(lowerWord) || hash.includes(lowerWord);
  });
};

export const isSlayerMonsterAvailable = (slayerCategoryId: SlayerCategoriesIds): boolean => {
  if (isDemo) {
    return !demoRemoveSlayerList.includes(slayerCategoryId);
  }
  return true;
};

