import { FoodItemType, ItemDataByReference } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { getAndMergeItemData } from "../../../data/ItemData/AllItemsData.ts";
import { useGetPlayerSkills } from "../../../Context/usePlayerStore.ts";

import { SkillsId } from "../../../data/skillsData/SkillsEnum.ts";
import { getSkillNameFromId } from "../../util/SkillsUtil/SkillUtil.tsx";
import ToolTipHeader from "./ToolTipHeader.tsx";

type ToolTipFoodProps = {
  item: ItemDataByReference;
};

const ToolTipFood = ({ item }: ToolTipFoodProps) => {
  const itemData = getAndMergeItemData(item) as FoodItemType;
  const skills = useGetPlayerSkills();

  return (
    <div>
      {/*<h2 className="text-orangeColor">{itemData.name}</h2>*/}
      <ToolTipHeader itemData={itemData} />
      {Object.keys(itemData.statBoost).map((key) => {
        const keyTyped = Number(key) as SkillsId;
        const skillName = getSkillNameFromId(keyTyped);

        const currentLevel = skills[keyTyped].level;
        const currentBoostedLevel = skills[keyTyped].boostedLevel;
        const deltaLevel = currentLevel - currentBoostedLevel;

        const statsBoosts = itemData.statBoost[keyTyped] ?? 0;
        let totalLevelChange = 0;

        const maxLevelWithOverflow = currentLevel + statsBoosts;

        if (itemData.statBoost !== undefined && !itemData.overFlow) {
          totalLevelChange = statsBoosts - deltaLevel;
          totalLevelChange = Math.min(deltaLevel, statsBoosts);
        }
        if (itemData.overFlow && deltaLevel < 0) {
          totalLevelChange = statsBoosts - Math.abs(deltaLevel);
        }
        if (itemData.overFlow && currentBoostedLevel > currentLevel) {
          totalLevelChange = maxLevelWithOverflow - currentBoostedLevel;
        } else if (itemData.overFlow && currentBoostedLevel <= currentLevel) {
          totalLevelChange = maxLevelWithOverflow - currentLevel;
        }

        return (
          <div className="flex gap-[2px]" key={key}>
            <p>{skillName}: </p>
            <div className="flex">
              {totalLevelChange && totalLevelChange > 0 ? (
                <p className="text-green-500"> +{totalLevelChange}</p>
              ) : (
                <p> +0</p>
              )}
              <span>/{statsBoosts}</span>
            </div>
          </div>
        );
      })}
    </div>
  );
};

export default ToolTipFood;
