import {
  BerserkerStats,
  combatMilestonesData,
  GearUpgrades,
} from "../GlobalBoosts/TotalLevelAchievements.ts";
import { Slots } from "../AllTypes/EquipmentTypes.ts";

export function calculateHighestGearUpgradesUpTo(points: number): GearUpgrades {
  const milestones = combatMilestonesData;
  const highestGear: GearUpgrades = {};

  // Iterate over each milestone and accumulate highest values for each slot
  Object.keys(milestones)
    .map((key) => parseInt(key))
    .forEach((milestonePoints) => {
      // Stop if the milestone's points exceed the threshold
      if (milestonePoints > points) return;

      const reward = milestones[milestonePoints];
      if (reward.gearUpgrade) {
        for (const slot in reward.gearUpgrade) {
          const slotName = slot as Slots;
          const upgradeLevel = reward.gearUpgrade[slotName] || 0;

          // Track only the highest level seen for each slot
          highestGear[slotName] = Math.max(highestGear[slotName] || 0, upgradeLevel);
        }
      }
    });

  return highestGear;
}
export function calculateHighestUpgradeForSlotUpTo(points: number, slot: Slots): number {
  const milestones = combatMilestonesData;
  let highestUpgradeLevel = 0;

  Object.keys(milestones)
    .map((key) => parseInt(key))
    .forEach((milestonePoints) => {
      if (milestonePoints > points) return;

      const reward = milestones[milestonePoints];
      if (reward.gearUpgrade) {
        const upgradeLevel = reward.gearUpgrade[slot] ?? 0; // Use 0 if reward.gearUpgrade[slot] is undefined
        highestUpgradeLevel = Math.max(highestUpgradeLevel, upgradeLevel);
      }
    });
  return highestUpgradeLevel;
}

export function calculateHighestBerserkerStatsUpTo(points: number): Partial<BerserkerStats> | null {
  const milestones = combatMilestonesData;
  const highestBerserkerStats: Partial<BerserkerStats> = {};
  Object.keys(milestones)
    .map((key) => parseInt(key))
    .forEach((milestonePoints) => {
      if (milestonePoints > points) return;

      const reward = milestones[milestonePoints];

      if (reward.maxHit !== undefined) {
        highestBerserkerStats.maxHit = Math.max(highestBerserkerStats.maxHit || 0, reward.maxHit);
      }

      if (reward.attackSpeed !== undefined) {
        highestBerserkerStats.attackSpeed = Math.max(
          highestBerserkerStats.attackSpeed || 0,
          reward.attackSpeed,
        );
      }

      if (reward.accuracy !== undefined) {
        highestBerserkerStats.accuracy = Math.max(highestBerserkerStats.accuracy || 0, reward.accuracy);
      }

      if (reward.activeTime !== undefined) {
        highestBerserkerStats.activeTime = Math.max(highestBerserkerStats.activeTime || 0, reward.activeTime);
      }

      if (reward.tier !== undefined) {
        highestBerserkerStats.tier = Math.max(highestBerserkerStats.tier || 0, reward.tier);
      }
    });

  if (!highestBerserkerStats.maxHit) return null;

  return highestBerserkerStats;
}

export function calculateHighestAttackSpeedUpTo(points: number): number {
  const milestones = combatMilestonesData;
  let highestAttackSpeed = 1;

  Object.keys(milestones)
    .map((key) => parseInt(key))
    .forEach((milestonePoints) => {
      if (milestonePoints > points) return;

      const reward = milestones[milestonePoints];

      if (reward.baseAttackSpeedBonus !== undefined) {
        highestAttackSpeed = Math.max(highestAttackSpeed, reward.baseAttackSpeedBonus);
      }
    });

  return highestAttackSpeed;
}
