// const slingshotAmmo = generateArrowData(arrowImages.slingshotAmmo);
const bronzeArrows = generateArrowData(arrowImages.bronzeArrow);
const jadeArrows = generateArrowData(arrowImages.jadeArrow);
const platinumArrows = generateArrowData(arrowImages.platinumArrow);
const diamondArrows = generateArrowData(arrowImages.diamondArrow);
const sunstoneArrows = generateArrowData(arrowImages.sunstoneArrow);
const boneArrows = generateArrowData(arrowImages.boneArrow);

// export const getSlingshotAmmoImage = (arrowNumber: number) =>
//   getImageForArrowType(slingshotAmmo, arrowNumber);
export const getBronzeArrowImage = (arrowNumber: number) => getImageForArrowType(bronzeArrows, arrowNumber);
export const getJadeArrowImage = (arrowNumber: number) => getImageForArrowType(jadeArrows, arrowNumber);
export const getPlatinumArrowImage = (arrowNumber: number) =>
  getImageForArrowType(platinumArrows, arrowNumber);
export const getDiamondArrowImage = (arrowNumber: number) => getImageForArrowType(diamondArrows, arrowNumber);
export const getSunstoneArrowImage = (arrowNumber: number) =>
  getImageForArrowType(sunstoneArrows, arrowNumber);
export const getBoneArrowImage = (arrowNumber: number) => getImageForArrowType(boneArrows, arrowNumber);

function getImageForArrowType(arrowsData: Record<number, Arrow>, arrowNumber: number): string {
  let arrowImage = Object.values(arrowsData)[0].img;

  for (const arrow of Object.values(arrowsData)) {
    if (arrowNumber >= arrow.amount) {
      arrowImage = arrow.img;
    } else {
      break;
    }
  }

  return arrowImage;
}
