import { Slots } from "../../../data/AllTypes/EquipmentTypes.ts";
import { EquippedItemsSetType } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { ItemIds } from "../../../data/ItemData/AllItemsIds.ts";
import { AllWeaponStances, StanceIds } from "../../../data/ItemData/AllWeaponStances.ts";
import { SkillsId } from "../../../data/skillsData/SkillsEnum.ts";

export const isItemWorn = (equippedItems: EquippedItemsSetType, slot: Slots, itemId: ItemIds): boolean => {
  if (!equippedItems) return false;
  const itemAtSlot = equippedItems[slot];
  if (!itemAtSlot) return false;
  return itemAtSlot.id !== itemId;
};

export const twistedBowDmgMultiplier = (monsterMagicLevel: number) => {
  const twistedBowDmg =
    250 +
    ((10 * 3 * monsterMagicLevel) / 10 - 14) / 100 -
    Math.pow((3 * monsterMagicLevel) / 10 - 100, 2) / 100;
  const roundedTwistedBowAcc = Math.max(Math.min(twistedBowDmg, 250), 0);

  return roundedTwistedBowAcc / 100;
};

export const twistedBowAccuracyMultiplier = (monsterMagicLevel: number) => {
  const twistedBowAcc =
    140 +
    ((10 * 3 * monsterMagicLevel) / 10 - 10) / 100 -
    Math.pow((3 * monsterMagicLevel) / 10 - 140, 2) / 100;

  const roundedTwistedBowAcc = Math.max(Math.min(twistedBowAcc, 140), 0);
  return roundedTwistedBowAcc / 100;
};

/**
 * Smartly finds the best matching stance for a new weapon based on the previous stance's intent.
 */
export const getBestMatchingStance = (
  previousStanceId: StanceIds,
  newWeaponStanceIds: StanceIds[],
): StanceIds => {
  const prevStance = AllWeaponStances[previousStanceId];
  // 1. If the new weapon supports the exact same ID, keep it.
  if (newWeaponStanceIds.includes(previousStanceId)) {
    return previousStanceId;
  }

  // 2. Check if the player was training Defence.
  const wasTrainingDefence = prevStance.experience.includes(SkillsId.Defence);

  if (wasTrainingDefence) {
    // Look for a stance in the new weapon that also trains Defence
    const defensiveStance = newWeaponStanceIds.find((id) =>
      AllWeaponStances[id].experience.includes(SkillsId.Defence),
    );
    if (defensiveStance) return defensiveStance;
  }

  // 3. Fallback: If no defensive match or wasn't training defence,
  // try to find an offensive one, or just pick the first available.
  return newWeaponStanceIds[0];
};
