import { useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "./Providers/AuthProvider.tsx";
import { LOGIN_URL } from "./data/Constants.ts";

const SteamLoginCallback = () => {
  const { login } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    console.log(params);
    //THIS IS WRONG, THE BACKEND NEEDS A TICKET THAT IS ASOOSIATED WITH AN ARROUND AND THEN IT HOPEFULY WILL SET THE CORRECT USERID FROM THE DB
    const steamTicket = params.get("ticket");
    if (steamTicket) {
      // Send Steam ID to backend /api/login/steam to get access tokens
      // The login function will save accessToken, refreshToken, and userId to session storage
      login(steamTicket, "steam");
    } else {
      // No Steam ID found, redirect back to login
      console.error("No Steam ticket found in callback");
      navigate(LOGIN_URL);
    }
  }, [login, navigate]);

  return <div>Logging in via Steam...</div>;
};

export default SteamLoginCallback;
