import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { getMonsterInfo, MonsterIds } from "../../../data/MonsterData/MonsterInfoUtil.ts";
import { getNextAttackStyle } from "../../../Components/util/CombatUtils/getNextAttackStyle.ts";

type StartAttackProcessAction = {
  monsterId: MonsterIds;
  attackDuration: number;
};

export function startAttackProcess(state: PlayerData, action: StartAttackProcessAction): PlayerData {
  const { monsterId, attackDuration } = action;

  const monsterInfo = getMonsterInfo(monsterId);
  if (!monsterInfo) {
    console.error(`Monster with ID ${monsterId} not found.`);
    return state;
  }

  //should be random not just the first attackStyle
  const nextAttackStyle = getNextAttackStyle(monsterInfo.attackStyles);

  return {
    ...state,
    currentAttackProcess: {
      ...state.currentAttackProcess,
      monsterId,
      currentMonsterState: monsterInfo.stats,
      nextMonsterAttackStyle: nextAttackStyle,
      isMonsterAlive: true,
      attackDuration,
    },
  };
}
