export enum ExtendedDropTableIds {
  "Always Drops" = 2001,
  "Regular Drops" = 2002,
}

export type ValidItemDropTypes = ValidExtendedDropTableIds | ValidDropTableIds;

export type DropTables = Record<DropTableIds, DropTable>;

export type DropTable = {
  name: string;
  id: DropTableIds;
  drops: ItemDataByReference[];
};

export type DropTableDrops = {
  id: DropTableIds;
  dropRollAmount: number;
  probability: number;
};

