import { EquiptableItemType, ItemDataByReference, PlayerData } from "../../data/AllTypes/PlayerDataTypes.ts";
import { calculateTotalBonuses } from "../../Components/Reducer/playerCalculations.ts";
import { Slots } from "../../data/AllTypes/EquipmentTypes.ts";
import { StanceIds } from "../../data/ItemData/AllWeaponStances.ts";
import { getAndMergeItemData } from "../../data/ItemData/AllItemsData.ts";
import { getBestMatchingStance } from "../../Components/util/CombatUtils/AttackUtils.ts";

type EquipItemAction = {
  item: ItemDataByReference | null;
  slot: Slots;
  amount: number;
  setIndex: number;
};

export function equipItem(state: PlayerData, action: EquipItemAction): PlayerData {
  const { item, slot, amount, setIndex } = action;
  const itemData = item && (getAndMergeItemData(item) as EquiptableItemType);
  const itemStats = itemData?.equipmentInfo?.weaponStats;

  const isItemStackable = itemData?.equipmentInfo?.equipMultiple;
  const equippedItem = state.equippedItems.sets[setIndex][slot];
  const isEquippedTheSame = equippedItem?.id === item?.id;

  let newAmount = amount;
  if (
    isEquippedTheSame &&
    isItemStackable &&
    equippedItem?.amount !== undefined &&
    equippedItem.id === item?.id
  ) {
    newAmount += equippedItem.amount;
  }

  // Create a new immutable set copy
  const updatedSet = {
    ...state.equippedItems.sets[setIndex],
    [slot]: {
      ...item,
      amount: newAmount,
    },
    totalStats:
      calculateTotalBonuses(
        { ...state.equippedItems.sets[setIndex], [slot]: { ...item, amount: newAmount } },
        state.levelBoosts.combatLevelBoostsPoints,
      ) || state.equippedItems.sets[setIndex].totalStats,
  };
  // Determine the new combat stance
  let newWeaponStyle;
  let newSpell = updatedSet.currentSpell;

  if (slot === Slots.WEAPON && itemStats) {
    newWeaponStyle = getBestMatchingStance(updatedSet.currentWeaponStyle, itemStats.stances);
  } else {
    // If not a weapon, maintain or reset weapon style
    const currentWeaponRef = updatedSet[Slots.WEAPON];
    const currentWeapon = currentWeaponRef && (getAndMergeItemData(currentWeaponRef) as EquiptableItemType);
    const weaponStats = currentWeapon?.equipmentInfo?.weaponStats;
    if (!weaponStats) {
      // We are now bare-handed. Try to maintain the "Defence" intent from whatever weapon we just took off.
      newWeaponStyle = getBestMatchingStance(updatedSet.currentWeaponStyle, [
        StanceIds.Melee,
        StanceIds.DefenceMelee,
      ]);
    } else {
      // Keep the current style as it is already valid for the equipped weapon.
      newWeaponStyle = updatedSet.currentWeaponStyle;
    }
  }

  // Ensure immutability by creating a new equippedItems object
  const updatedEquippedItems = {
    ...state.equippedItems,
    sets: {
      ...state.equippedItems.sets,
      [setIndex]: {
        ...updatedSet,
        currentWeaponStyle: newWeaponStyle,
        currentSpell: newSpell,
      },
    },
  };
  return {
    ...state,
    equippedItems: updatedEquippedItems,
  };
}
