import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";

// Reducer to change the uiSettings map on PlayerData in an immutable way.
export const changeUISetting = (state: PlayerData, params: { key: string; value: number }): PlayerData => {
  const { key, value } = params;

  // Existing map (or empty object if missing)
  const existingUISettings = state.uiSettings ?? {};

  // Prevent unnecessary updates
  if (existingUISettings[key] === value) {
    return state;
  }

  return {
    ...state,
    uiSettings: {
      ...existingUISettings,
      [key]: value,
    },
  };
};
