const statBoostSuperRestore: Partial<
  Record<SkillsId, { baseBoost: number; percentBoost?: number | undefined }>
> = {};

const superRestorePotionBoost = { baseBoost: 8, percentBoost: 0.25 };

for (const skillId of AllSkillIdList) {
  const skillIdTyped = Number(skillId) as SkillsId;
  statBoostSuperRestore[skillIdTyped] = {
    ...superRestorePotionBoost,
  };
}

