import { ItemDataByReference } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { getAndMergeItemData } from "../../../data/ItemData/AllItemsData.ts";
import ToolTipHeader from "./ToolTipHeader.tsx";

type ToolTipProps = {
  item: ItemDataByReference | null;
  className?: string;
};

export function ToolTipDefaultItem({ item, className }: ToolTipProps) {
  if (item === null) return null;
  const itemData = getAndMergeItemData(item);

  return (
    <div className={`text-[12px] !z-[10000] text-orangeColor ${className}`}>
      <ToolTipHeader itemData={itemData} />
    </div>
  );
}
