import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { RunIds } from "../../../data/Runs/AllRunsData.ts";

type ResetRunSlotAction = {
  runId: RunIds;
  slot: number;
};

export function stopRun(state: PlayerData, action: ResetRunSlotAction): PlayerData {
  const { runId, slot: slotIndex } = action;
  const currentRuns = { ...state.currentLongTermProcesses };
  const runSlots = currentRuns?.[runId];

  if (runSlots?.[slotIndex]) {
    const { [slotIndex]: _, ...remainingSlots } = runSlots;

    return {
      ...state,
      currentLongTermProcesses: {
        ...currentRuns,
        [runId]: remainingSlots,
      },
    };
  }

  return state;
}
