import { ItemDataByReference, PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { InventoryItemsData } from "../../../data/AllTypes/SkillsSpecificTypes.ts";

interface Action {
  items: ItemDataByReference[];
}

export function useItemsOnGround(state: PlayerData, action: Action): PlayerData {
  const itemsToUse = action.items ?? [];
  // Clone containers from the existing state
  let newItemsOnGround: InventoryItemsData = [...(state.itemsOnGround || [])];

  // Helper function: remove (or decrement) the specified item from a container
  function removeItemFromContainer(
    container: InventoryItemsData,
    item: ItemDataByReference,
  ): InventoryItemsData {
    // Find the index of the item by name
    const index = container.findIndex((slot) => slot?.id === item.id);
    if (index === -1) {
      // Item not found in this container
      console.warn(`Item "${item.id}" not found in the container.`);
      return container;
    }

    // Copy the array
    const updated = [...container];
    const slot = updated[index];
    if (!slot) return updated;

    // Decrement the item's amount
    const newAmount = slot.amount - item.amount;
    if (newAmount <= 0) {
      // If the amount drops to zero or below, remove the item
      updated[index] = null;
    } else {
      // Otherwise, update the item's amount
      updated[index] = { ...slot, amount: newAmount };
    }

    return updated;
  }

  // Process each item to use
  for (const itemToUse of itemsToUse) {
    newItemsOnGround = removeItemFromContainer(newItemsOnGround, itemToUse);
  }

  // Return the updated state
  return {
    ...state,
    itemsOnGround: newItemsOnGround,
  };
}
