export enum ProcessLevelIds {
  Bronze = 1,
  Silver = 2,
  Gold = 3,
  Platinum = 4,
  Sapphire = 5,
  Emerald = 6,
  Ruby = 7,
  Diamond = 8,
}
export const processLevelsArray: ProcessLevelIds[] = [
  ProcessLevelIds.Bronze,
  ProcessLevelIds.Silver,
  ProcessLevelIds.Gold,
  ProcessLevelIds.Platinum,
  ProcessLevelIds.Sapphire,
  ProcessLevelIds.Emerald,
  ProcessLevelIds.Ruby,
  ProcessLevelIds.Diamond,
];

export const getProcessInfoFromId = (
  id: ProcessLevelIds | undefined,
): ProcessCompletedAttributes | undefined => {
  if (!id) return undefined;
  return sharedAttributesMap[id];
};
export const getProcessLevelIndex = (levelName: ProcessLevelIds | undefined): number | null => {
  if (!levelName) return null;
  return processLevelsArray.indexOf(levelName);
};

export type ProcessCompletedAttributes = {
  img: string;
  name: string;
  id: ProcessLevelIds;
  color: string;
  points: number;
  lootMultiplier?: number;
  xpMultiplier?: number;
  speedMultiplier?: number;
  equipmentMultiplier?: number;
  dropRolls?: number;
};

export type ProcessCompletedMapType = {
  [key in ProcessLevelIds]: ProcessCompletedAttributes;
};

export type SlotMultiplierMapType = ProcessCompletedAttributes[];

export type RunCompletedMapType = {
  [key in ProcessLevelIds]: ProcessCompletedAttributes;
};

