import { levelBoostsTypes, PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { ProcessLevelIds, totalPointsFromOneMax } from "../../../data/ProcessLevelData/ProcessLevelData.tsx";
import {
  calculatePointsFromLevel,
  getTotalStaticResourceCount,
  totalMonstersAmount,
} from "../../../Components/util/LevelUtils/LevelData.tsx";

export type UpdateLevelBoostsAction = {
  levelType: levelBoostsTypes;
  levelsRank: ProcessLevelIds[];
};

export function updateLevelBoosts(state: PlayerData, action: UpdateLevelBoostsAction): PlayerData {
  const { levelType, levelsRank } = action;

  const MAX_COMBAT_POINTS = totalMonstersAmount() * totalPointsFromOneMax;
  const MAX_SKILLING_POINTS = getTotalStaticResourceCount() * totalPointsFromOneMax;

  let skillingPoints = state.levelBoosts?.skillingLevelBoostsPoints || 0;
  let combatPoints = state.levelBoosts?.combatLevelBoostsPoints || 0;
  // Calculate the new total points
  const updatedLevelBoosts = { ...(state.levelBoosts?.[levelType] || {}) };

  for (const level of levelsRank) {
    const points = calculatePointsFromLevel(level);
    updatedLevelBoosts[level] = (updatedLevelBoosts[level] || 0) + 1;

    if (levelType === "skillingLevelBoosts") skillingPoints += points;
    if (levelType === "combatLevelBoosts") combatPoints += points;
  }

  let skillingLevelBoostsPointsMaxedTimestamp = state.levelBoosts?.skillingLevelBoostsPointsMaxedTimestamp;
  let combatLevelBoostsPointsMaxedTimestamp = state.levelBoosts?.combatLevelBoostsPointsMaxedTimestamp;

  // Check if skilling/combat points maxed out and set the timestamp
  if (skillingPoints >= MAX_SKILLING_POINTS) skillingLevelBoostsPointsMaxedTimestamp = new Date().getTime();
  if (combatPoints >= MAX_COMBAT_POINTS) combatLevelBoostsPointsMaxedTimestamp = new Date().getTime();

  return {
    ...state,
    levelBoosts: {
      ...(state.levelBoosts || {}),
      [levelType]: updatedLevelBoosts,
      skillingLevelBoostsPoints: skillingPoints,
      combatLevelBoostsPoints: combatPoints,
      skillingLevelBoostsPointsMaxedTimestamp,
      combatLevelBoostsPointsMaxedTimestamp,
    },
  };
}
