import { PlayerData } from "../../data/AllTypes/PlayerDataTypes.ts";
import { SlayerCategoriesIds } from "../../data/MonsterData/MonsterTypes.ts";

type ToggleExtendedAction = {
  SlayerCategoriesIds: SlayerCategoriesIds;
};

export function toggleIsExtended(state: PlayerData, action: ToggleExtendedAction): PlayerData {
  const { SlayerCategoriesIds } = action;
  const currentExtended =
    state.slayerInfo.slayerExtendList && state.slayerInfo.slayerExtendList[SlayerCategoriesIds]?.isExtended;

  return {
    ...state,
    slayerInfo: {
      ...state.slayerInfo,
      slayerExtendList: {
        ...state.slayerInfo.slayerExtendList,
        [SlayerCategoriesIds]: {
          ...(state.slayerInfo.slayerExtendList && state.slayerInfo.slayerExtendList[SlayerCategoriesIds]),
          isExtended: !currentExtended,
        },
      },
    },
  };
}
