import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { SlayerCategoriesIds } from "../../../data/MonsterData/MonsterTypes.ts";

type RemoveMonsterFromBlockListAction = {
  slayerCategoryId: SlayerCategoriesIds;
};

export function removeMonsterFromBlockList(
  state: PlayerData,
  action: RemoveMonsterFromBlockListAction,
): PlayerData {
  const { slayerCategoryId } = action;
  const { slayerInfo } = state;
  const oldBlockList = slayerInfo.slayerBlockList ?? {};

  const updatedBlockList = Object.fromEntries(
    Object.entries(oldBlockList).filter(([_, value]) => value !== slayerCategoryId),
  );

  return {
    ...state,
    slayerInfo: {
      ...slayerInfo,
      slayerBlockList: updatedBlockList,
    },
  };
}
