import { PlayerData } from "../../data/AllTypes/PlayerDataTypes.ts";
import { Difficulty, ValidDiaryStatus } from "../../data/AllTypes/DiaryTypes.ts";
import { getDiaryObject } from "../../Components/util/DiaryUtils.tsx";
import { ValidDiaryIds } from "../../data/AchievementDiaries/DiaryTypes.ts";

type DiaryAction = {
  diaryId: ValidDiaryIds;
  difficulty: Difficulty;
};
export function diaryRewardGiven(state: PlayerData, action: DiaryAction): PlayerData {
  const { diaryId, difficulty } = action;

  // Check if the diary entry exists and has an entry for the specified difficulty
  const diaryObject = getDiaryObject(state.completedAchievementDiary, diaryId);

  if (diaryObject && diaryObject[difficulty]) {
    return {
      ...state,
      completedAchievementDiary: {
        ...state.completedAchievementDiary,
        [diaryId]: {
          ...diaryObject,
          [difficulty]: ValidDiaryStatus.Completed,
        },
      },
    };
  }

  return state;
}
