import { ItemIds } from "../../../data/ItemData/AllItemsIds.ts";
import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";

type AddItemToLockedListAction = {
  itemId: ItemIds;
};

export function addItemToLockedList(state: PlayerData, action: AddItemToLockedListAction): PlayerData {
  const { itemId } = action;
  const currentLocked = state.lockedInventoryItems || [];
  if (currentLocked.includes(itemId)) {
    // Already locked
    return state;
  }
  return {
    ...state,
    lockedInventoryItems: [...currentLocked, itemId],
  };
}
