import React from "react";
import ReactDOM from "react-dom/client";
import App from "./App.tsx";
import "./../tailwind.css";
import { GoogleOAuthProvider } from "@react-oauth/google";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import ErrorBoundary from "./ErrorBoundary.tsx";
import FallBackUI from "./FallBackUI.tsx";
import * as Sentry from "@sentry/react";

if (import.meta.env.VITE_APP_MODE === "production") {
  Sentry.init({
    dsn: "https://2c10dca689fb26ee20e4fbe600352763@o4509054751408128.ingest.de.sentry.io/4509054987272272",
    tracesSampleRate: 0.1,
    // tracesSampleRate: 1,
  });
}

const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      retry: (failureCount, error: any) => {
        // Only retry on 5xx errors, max 2 times
        if (failureCount >= 2) return false;

        const status = error?.response?.status || error?.status;

        return status >= 500 && status < 600;
      },
    },
  },
});

ReactDOM.createRoot(document.getElementById("root")!).render(
  <React.StrictMode>
    <QueryClientProvider client={queryClient}>
      <GoogleOAuthProvider clientId="915877110880-et848n91el48sg6a2l8rh9j66mib58i1.apps.googleusercontent.com">
        <ErrorBoundary fallback={<FallBackUI />}>
          <App />
        </ErrorBoundary>
      </GoogleOAuthProvider>
    </QueryClientProvider>
  </React.StrictMode>,
);
