import { PlayerData } from "../../data/AllTypes/PlayerDataTypes.ts";
import { recalculateMultipliersForSkill } from "./ReducerUtils/recalculateMultipliersForSkill.ts";

import { SkillsId } from "../../data/skillsData/SkillsEnum.ts";
import { ToolIds } from "../../data/skillsData/Tools.ts";

type BuyToolAction = {
  skillId: SkillsId;
  toolId: ToolIds;
};

export function buyTool(state: PlayerData, action: BuyToolAction): PlayerData {
  const { skillId, toolId } = action;
  const skillData = state.skills[skillId];
  if (skillData.toolIds?.includes(toolId)) return state;
  const newToolIds = [...(skillData.toolIds ?? []), toolId];

  const updatedMultipliers = recalculateMultipliersForSkill({
    ...skillData,
    toolIds: newToolIds,
  });

  return {
    ...state,
    skills: {
      ...state.skills,
      [skillId]: {
        ...skillData,
        toolIds: newToolIds,
        ...updatedMultipliers,
      },
    },
  };
}
