type Seed = { amount: number; img: string };

function getImageForSeedType(seedsData: Record<number, Seed>, seedNumber: number): string {
  let seedImage = Object.values(seedsData)[0].img;

  for (const seed of Object.values(seedsData)) {
    if (seedNumber >= seed.amount) {
      seedImage = seed.img;
    } else {
      break;
    }
  }

  return seedImage;
}

import { seeds } from "./SeedImages.ts";

export const getSeedImage = (seedNumber: number) => getImageForSeedType(seeds, seedNumber);
