import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";

// Assuming your action type definitions are set up similarly
type ChangeNextHealthRestoreTimeAction = {
  nextHealthRestoreTime: number; // Timestamp for the next health restore in milliseconds
};

export function changeNextHealthRestoreTime(
  state: PlayerData,
  action: ChangeNextHealthRestoreTimeAction,
): PlayerData {
  // Destructure the nextHealthRestoreTime from the action
  const { nextHealthRestoreTime } = action;

  return {
    ...state,
    healthInfo: {
      ...state.healthInfo,
      nextHealthRestoreTime: nextHealthRestoreTime,
    },
  };
}
