import { currentAttackProcessType, PlayerData, processType } from "../../data/AllTypes/PlayerDataTypes.ts";
import { MonsterIdDictionary } from "../../data/AllTypes/AttackStyleAndWeaponTypes.ts";
import { AccountImageId } from "../../data/AllTypes/AccountImageTypes.ts";

export enum AccountType {
  Countryside = 1001,
  Wilderness = 1002,
  City = 1003,
}

export type GamePreview = {
  slotId: number;
  totalXP: number;
  totalLevel: number;
  name: string;
  lastSavedLocal: number;
  lastSavedCloud?: number | null;
  accountType: AccountType;
  accountImgId: AccountImageId;
  inGameTime: number;
  accountId: string | null;
  currentProcess: processType | null;
  currentAttackProcess: currentAttackProcessType;
  collectionLogSlot: number;
  id?: string;
};

export type StoredGameState = {
  state: PlayerData;
  lastSavedLocal: number;
  lastSavedCloud?: number;
};

export type LeaderboardSnapshots = {
  slotId: string;
  snapshot: LeaderboardSnapshot;
  _id?: string;
}[];
export type SlotDataResponse = {
  saves: Record<string, string>;
  leaderboardSnapshots: LeaderboardSnapshots;
};

export type LeaderboardSnapshot = {
  inGameName: string;
  accountType: AccountType;
  accountStart?: number;
  total: {
    level: number;
    xp: number;
    maxedTimestamp?: Date;
  };
  skills: Record<
    string,
    {
      level: number;
      xp: number;
      maxedTimestamp?: Date;
    }
  >;
  pets: {
    total: number;
    maxedTimestamp?: Date | null | undefined;
  };
  levelBoosts: {
    skillingLevelBoostsPoints: number;
    skillingLevelBoostsPointsMaxedTimestamp?: Date | undefined;
    combatLevelBoostsPoints: number;
    combatLevelBoostsPointsMaxedTimestamp?: Date | undefined;
  };
  collectionLogSlot: number;
  collectionLogMaxedTimestamp?: Date | undefined;
  monsterKillStats: MonsterIdDictionary | null;
};
