import { PlayerData } from "../../data/AllTypes/PlayerDataTypes.ts";
import { SlayerCategoriesIds } from "../../data/MonsterData/MonsterTypes.ts";

type ExtendSlayerMonsterAction = {
  SlayerCategoriesIds: SlayerCategoriesIds;
};

export function extendSlayerMonster(state: PlayerData, action: ExtendSlayerMonsterAction): PlayerData {
  const { SlayerCategoriesIds } = action;
  return {
    ...state,
    slayerInfo: {
      ...state.slayerInfo,
      slayerExtendList: {
        ...state.slayerInfo.slayerExtendList,
        [SlayerCategoriesIds]: {
          isExtended: true,
          unlocked: true,
        },
      },
    },
  };
}
