import { IconName } from "../../../icons.ts";
import IconComponent from "../../AccountOverview/IconComponent.tsx";

type ButtonSmallProps = {
  text: string;
  onClick: (e: React.MouseEvent) => void;
  className?: string;
  disabled?: boolean;
  selected?: boolean;
  children?: React.ReactNode;
  icon?: IconName;
  iconSize?: number;
  iconColor?: string;
  isPrimary?: boolean;
  isLoading?: boolean;
  small?: boolean;
};

const Button = ({
  text,
  onClick,
  className = "",
  disabled,
  selected,
  children,
  icon,
  iconSize = 16,
  iconColor,
  isPrimary,
  isLoading,
  small = false,
}: ButtonSmallProps) => {
  const bgColor = isPrimary ? "bg-green-700" : selected ? "bg-selectColor" : "bg-bgColorSecondary";

  return (
    <button
      onClick={(e) => onClick && onClick(e)}
      disabled={isLoading || disabled}
      className={`
        ${bgColor}
        border-2 border-borderColor
        text-orangeColor
        relative duration-100
        flex items-center justify-center gap-1
        leading-none whitespace-nowrap rounded
        ${small ? "text-xs px-2 py-1 " : "text-sm px-3 py-1.5 "}
        ${className}
        ${
          isLoading || disabled
            ? "opacity-40 cursor-not-allowed text-disabledTextColor"
            : "opacity-100 cursor-pointer hover:brightness-110 active:brightness-100"
        }
      `}
    >
      {/*{isLoading && (*/}
      {/*  <span className="animate-spin border-2 border-t-transparent border-orangeColor rounded-full w-3 h-3 mr-1" />*/}
      {/*)}*/}

      {icon && <IconComponent iconName={icon} size={iconSize} iconColor={iconColor} className={""} />}
      {children}
      {text && <p>{text}</p>}
    </button>
  );
};

export default Button;
