import { CurrentPotionType, PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";

type SetCurrentPotionAction = {
  potionState: CurrentPotionType;
};

export function setCurrentPotions(state: PlayerData, action: SetCurrentPotionAction): PlayerData {
  return {
    ...state,
    currentPotions: action.potionState,
  };
}
