import { ItemDataByReference } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { numberFormatter } from "../../util/Formatter/NumberFormatter2Decimal.tsx";

export const isPetOwned = (
  petId: number | undefined,
  PetsMap: Record<"Combat" | "Skilling", ItemDataByReference[]> | undefined,
): boolean => {
  if (!PetsMap || !petId) return false; // If PetsMap is undefined, return false

  return Object.values(PetsMap)
    .flat()
    .some((ownedPet) => ownedPet.id === petId); // Corrected comparison
};

export const getOwnedPet = (
  petId: number,
  PetsMap: Record<"Combat" | "Skilling", ItemDataByReference[]> | undefined,
): ItemDataByReference | undefined => {
  if (!PetsMap) return undefined;
  return Object.values(PetsMap)
    .flat()
    .find((ownedPet) => ownedPet.id === petId);
};

export const formatProbability = (probability: number) => {
  const result = 1 / probability;
  return `1/${numberFormatter(Number.isInteger(result) ? result : parseFloat(result.toFixed(2)))}`;
};
