import { ItemDataByReference } from "../../AllTypes/PlayerDataTypes.ts";
import { getSeedImage } from "./SeedsImagesGetterFunctions.ts";
import { getItemInfoFromId } from "../../ItemData/AllItemsData.ts";
import { memoize } from "lodash";
import { ItemIds } from "../../ItemData/AllItemsIds.ts";
import { getCoinsImage } from "../../../Components/util/Formatter/CoinImagesDisplay.ts";
import { ImageMap } from "../../ImageMap.ts";
import { DynamicItemIdStartValue } from "../CreateXPLamp.ts";
import {
  getBoneArrowImage,
  getBronzeArrowImage,
  getDiamondArrowImage,
  getJadeArrowImage,
  getPlatinumArrowImage,
  getSunstoneArrowImage,
} from "./ArrowsImagesGetterFunctions.ts";
import { PLACEHOLDER_NAME } from "../../Constants.ts";

type ImageFunctionMap = {
  [key in number]?: (amount: number) => string;
};

const imageFunctions: ImageFunctionMap = {
  [ItemIds.COINS]: getCoinsImage,
  [ItemIds.BRONZE_ARROWS]: getBronzeArrowImage,
  [ItemIds.JADE_ARROWS]: getJadeArrowImage,
  [ItemIds.PLATINUM_ARROWS]: getPlatinumArrowImage,
  [ItemIds.DIAMOND_ARROWS]: getDiamondArrowImage,
  [ItemIds.SUNSTONE_ARROWS]: getSunstoneArrowImage,
  [ItemIds.BONE_ARROWS]: getBoneArrowImage,
};

const seedItemIds = [30000, 300001];

// Define the memoized function
export const getImageSource = memoize(
  (item: ItemDataByReference, updatedAmount: number): string => {
    if (!item || !item.id) return "";
    const itemInfo = getItemInfoFromId(item.id);

    if (item.id >= DynamicItemIdStartValue) {
      return ImageMap.xpLamp;
    }

    const imageFunction = imageFunctions[item.id];

    if (imageFunction && itemInfo?.name !== PLACEHOLDER_NAME) {
      return imageFunction(updatedAmount);
    }

    if (seedItemIds.includes(item.id)) {
      return getSeedImage(updatedAmount);
    }

    const itemImg = itemInfo?.img;
    return itemImg ? itemImg : "";
  },
  (item, updatedAmount) => `${item.id}-${updatedAmount}`,
);
