import { ItemDataByReference, PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { ExtendedDropTableIds } from "../../../data/AllTypes/DropTables.ts";
import { MonsterIds } from "../../../data/MonsterData/MonsterInfoUtil.ts";

export function updateMonsterKillStats(
  state: PlayerData,
  action: {
    monsterId: MonsterIds;
    dropsReceived?: ItemDataByReference[];
    killCount: number;
  },
): PlayerData {
  const { monsterId, dropsReceived, killCount } = action;

  // Ensure there's a valid monsterName
  if (!monsterId) {
    return state; // No updates if no valid monster name is provided
  }

  // Safely get current stats, defaulting to initial values if not present
  const currentStats = (state.monsterKillStats && state.monsterKillStats[monsterId]) || {
    killCount: 0,
    drops: [],
  };

  // Always increment kill count regardless of drops
  const newKillCount = currentStats.killCount + killCount;

  // Only update drops if dropsReceived is an array and not empty
  const updatedDrops = [...currentStats.drops];
  if (Array.isArray(dropsReceived) && dropsReceived.length > 0) {
    dropsReceived.forEach((dropReceived) => {
      // Should not add the always drops or the droptable drops to the list
      if (dropReceived.source !== ExtendedDropTableIds["Regular Drops"]) return;
      const existingDropIndex = updatedDrops.findIndex((drop) => drop.id === dropReceived.id);
      if (existingDropIndex !== -1) {
        // Increment the amount for the existing drop
        updatedDrops[existingDropIndex] = {
          ...updatedDrops[existingDropIndex],
          amount: updatedDrops[existingDropIndex].amount + dropReceived.amount,
        };
      } else {
        // Add the new drop to the updated drops array
        updatedDrops.push({ id: dropReceived.id, amount: dropReceived.amount });
      }
    });
  }

  // Update the player's monster kill stats
  const updatedMonsterKillStats = {
    ...state.monsterKillStats,
    [monsterId]: {
      killCount: newKillCount,
      drops: updatedDrops,
    },
  };

  return {
    ...state,
    monsterKillStats: updatedMonsterKillStats,
  };
}
