import { useNavigate } from "react-router-dom";
import { ResourceIds } from "../../data/skillsData/ResourceIds";
import { getSkillAndTabFromResourceId } from "../../Components/Diaries/Diaryutils.ts";
import { getMonsterInfo, MonsterIds } from "../../data/MonsterData/MonsterInfoUtil.ts";
import { CombatSkillIdList, SkillsId } from "../../data/skillsData/SkillsEnum.ts";
import { Difficulty } from "../../data/AllTypes/DiaryTypes.ts";
import { DiaryIds } from "../../data/AchievementDiaries/DiaryTypes.ts";
import { DIARY, DIARY_DIFFICULTY, QUEST, RESOURCE, TAB } from "../../data/Constants.ts";
import {
  createSearchMonsterUrl,
  createSlayerBuyUrl,
  createSlayerMonsterUrl,
  createSlayerOfflineUrl,
} from "../../Components/util/urlCreator.ts";
import { SlayerBuyIds } from "../../data/Slayer/SlayerBuys.ts";
import { SlayerCategoriesIds } from "../../data/MonsterData/MonsterTypes.ts";
import { ValidShopNames } from "../../data/AllTypes/ShopTypes.ts";
import { ItemIds } from "../../data/ItemData/AllItemsIds.ts";

type ProcessNavigationInput = {
  resourceId?: ResourceIds;
  monsterId?: MonsterIds;
};

export const useNavigation = () => {
  const navigate = useNavigate();

  const goToSkill = (skillId: SkillsId | "Combat") => {
    if (CombatSkillIdList.includes(skillId as SkillsId) || skillId === "Combat") {
      navigate(`/${encodeURIComponent("combat")}`);
    } else {
      navigate(`/skills/${encodeURIComponent(skillId)}`);
    }
  };

  const goToShop = (shopName: ValidShopNames) => {
    navigate(`/shops?tab=${encodeURIComponent(shopName)}`);
  };

  const goToItemDb = (itemId: ItemIds) => {
    navigate(`/items/${encodeURIComponent(itemId)}`);
  };

  const goToProcess = ({ resourceId, monsterId }: ProcessNavigationInput) => {
    if (monsterId) {
      const monsterInfo = getMonsterInfo(monsterId);
      if (!monsterInfo) return;
      navigate(`/combat?page=1&${TAB}=All&search=${monsterInfo.name}`);
      return;
    }

    if (resourceId) {
      const tabInfo = getSkillAndTabFromResourceId(resourceId);
      navigate(`/skills/${tabInfo?.skillId}?tab=${tabInfo?.tabName}&${RESOURCE}=${resourceId}`);
      return;
    }

    navigate(`/combat`);
  };

  const goToDiary = (diaryId: DiaryIds, difficulty: Difficulty) => {
    navigate(`/Achievements?${DIARY}=${diaryId}&${DIARY_DIFFICULTY}=${difficulty}`);
  };
  const goToQuest = (questName: string | null) => {
    if (!questName) return;
    navigate(`/quests?tab=${QUEST}&page=1&search=${encodeURIComponent(questName)}`);
  };

  const goToSlayerMonster = (monsterId: SlayerCategoriesIds | null | undefined) => {
    navigate(createSlayerMonsterUrl(monsterId));
  };

  const goToSearchMonster = (search: string) => {
    navigate(createSearchMonsterUrl(search));
  };

  const goToSlayerBuy = (upgradeId: SlayerBuyIds) => {
    navigate(createSlayerBuyUrl(upgradeId));
  };
  const goToSlayerOffline = (monsterId: MonsterIds) => {
    navigate(createSlayerOfflineUrl(monsterId));
  };

  return {
    goToProcess,
    goToSkill,
    goToDiary,
    goToQuest,
    goToShop,
    goToItemDb,
    goToSlayerMonster,
    goToSearchMonster,
    goToSlayerBuy,
    goToSlayerOffline,
  };
};
