import React, { JSX, memo } from "react";

type ToastType = {
  key: number;
  toastComponent: JSX.Element;
  active: boolean;
};

type ToastDisplayProps = {
  toasts: ToastType[];
  handleToastClick: (key: number) => void;
};

const ToastDisplay: React.FC<ToastDisplayProps> = memo(({ toasts, handleToastClick }: ToastDisplayProps) => {
  return (
    <div className="toaster-container fixed left-0 top-0 z-[100000] select-none w-full">
      {toasts.map((toast) => (
        <div
          key={toast.key}
          className={`toaster ${
            toast.active ? "cursor-pointer" : "animateSlideUpToaster !bg-green-500 !pointer-events-none"
          }`}
          onClick={() => {
            handleToastClick(toast.key);
          }}
        >
          {toast.toastComponent}
        </div>
      ))}
    </div>
  );
});

export default ToastDisplay;
