import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { getAvailableSlayerBlockSlotIndex } from "../../../Components/util/SlayerUtil.tsx";
import { SlayerCategoriesIds } from "../../../data/MonsterData/MonsterTypes.ts";

type AddMonsterToBlockListAction = {
  slayerCategoryId: SlayerCategoriesIds;
};

export function addMonsterToBlockList(state: PlayerData, action: AddMonsterToBlockListAction): PlayerData {
  const { slayerCategoryId } = action;
  const { slayerInfo, completedQuests, completedAchievementDiary } = state;

  // Find an index of the first available slot
  const availableSlotIndex = getAvailableSlayerBlockSlotIndex(
    slayerInfo,
    completedQuests,
    completedAchievementDiary,
  );

  // Check if there is an available slot
  if (availableSlotIndex !== -1) {
    const updatedSlayerBlockList = {
      ...(slayerInfo.slayerBlockList ?? {}),
      [availableSlotIndex]: slayerCategoryId,
    };

    return {
      ...state,
      slayerInfo: {
        ...slayerInfo,
        slayerBlockList: updatedSlayerBlockList,
      },
    };
  } else {
    console.error("No available slot meets the quest point requirement or all slots are filled");
    return state;
  }
}
