import { ResourceIds } from "../../skillsData/ResourceIds.ts";
import { ItemDataByReference, MinMaxNumbers } from "../../AllTypes/PlayerDataTypes.ts";
import { MonsterIds } from "../../MonsterData/MonsterInfoUtil.ts";
import { Difficulty } from "../../AllTypes/DiaryTypes.ts";
import { createItemRef } from "../CreateItemRef.ts";
import { ItemIds } from "../../ItemData/AllItemsIds.ts";

export type MonsterTaskMap = Partial<Record<MonsterIds, MinMaxNumbers>>;
export type ResourceTaskMap = Partial<Record<ResourceIds, MinMaxNumbers>>;

export enum ContractDifficultyIds {
  STARTER = 1000,
  EASY = 1001,
  MEDIUM = 1002,
  HARD = 1003,
  EXPERT = 1004,
}
export const DifficultyMap: Record<ContractDifficultyIds, Difficulty | undefined> = {
  [ContractDifficultyIds.STARTER]: undefined, // Handle cases with no equivalent
  [ContractDifficultyIds.EASY]: Difficulty.EASY,
  [ContractDifficultyIds.MEDIUM]: Difficulty.MEDIUM,
  [ContractDifficultyIds.HARD]: Difficulty.HARD,
  [ContractDifficultyIds.EXPERT]: Difficulty.EXPERT,
};

export const ClueDiffToItemMap: Record<ContractDifficultyIds, ItemDataByReference | undefined> = {
  [ContractDifficultyIds.STARTER]: undefined, // Handle cases with no equivalent
  [ContractDifficultyIds.EASY]: createItemRef(ItemIds.EASY_CONTRACT),
  [ContractDifficultyIds.MEDIUM]: createItemRef(ItemIds.MEDIUM_CONTRACT),
  [ContractDifficultyIds.HARD]: createItemRef(ItemIds.HARD_CONTRACT),
  [ContractDifficultyIds.EXPERT]: createItemRef(ItemIds.EXPERT_CONTRACT),
};

export type ClueScrollInfoMapType = {
  [K in ContractDifficultyIds]: ClueDataType;
};
export type ClueDataType = {
  name: string;
  color: string;
  taskRolls: number;
  rewards: ItemDataByReference[];
  monsterTasks: MonsterTaskMap;
  resourceTasks: ResourceTaskMap;
};
