export const getSkillImgMobileFromSkill = (skillId: SkillsId | null | undefined): string => {
  if (!skillId) return defaultBgMobile;
  return skillImgMapMobile[skillId];
};
export const getSkillImgDesktopFromSkill = (skillId: SkillsId | null | undefined): string => {
  if (!skillId) return defaultBg;
  return skillImgMapDesktop[skillId];
};
