import { useState } from "react";
import { Navigate, Outlet } from "react-router-dom";
import PlayerStateInitializer from "../Components/PlayerStateInitializer";
import { useAuthStore } from "../hooks/Auth/useAuthToken.ts";
import { ACCOUNT_OVERVIEW_URL, LOGIN_URL } from "../data/Constants.ts";

function SetupProtectedRoute() {
  const [initialized, setInitialized] = useState(false);
  const { currentSlotId, userId } = useAuthStore();
  // const isWeb = useIsWeb();

  // if (isDemo && isWeb) {
  //   return <Navigate to={LOGIN_URL} replace />;
  // }

  if (!currentSlotId) {
    if (userId) return <Navigate to={ACCOUNT_OVERVIEW_URL} replace />;
    else return <Navigate to={LOGIN_URL} replace />;
  }

  if (!initialized) {
    return (
      <PlayerStateInitializer slotId={parseInt(currentSlotId)} onInitialized={() => setInitialized(true)} />
    );
  }

  return <Outlet />;
}
export default SetupProtectedRoute;
