import { create } from "zustand";
import { createJSONStorage, persist } from "zustand/middleware";

interface AuthState {
  accessToken: string | null;
  refreshToken: string | null;
  userId: string | null;
  currentSlotId: string | null;
  isTokenValid: boolean;
  isLoggedIn: boolean;
  platform: "WEB" | "STEAM" | "ITCH" | null;

  // actions
  saveAuth: (data: { accessToken: string; refreshToken: string; userId: string }) => void;
  saveTokens: (data: { accessToken: string; refreshToken: string }) => void;
  clearAuth: () => void;
  setCurrentSlotId: (slotId: number | null) => void;
  initializePlatform: () => Promise<void>;
}

export const getPlatform = async () => {
  if (typeof window === "undefined" || !window.electronAPI) return "WEB";
  const isSteamActive = await window.electronAPI.getIsSteam();
  return isSteamActive ? "STEAM" : "ITCH";
};

export const useAuthStore = create<AuthState>()(
  persist(
    (set) => ({
      accessToken: null,
      refreshToken: null,
      userId: null,
      currentSlotId: null,
      isLoggedIn: false,
      isTokenValid: false,
      platform: null, // Starter som null
      initializePlatform: async () => {
        const p = await getPlatform();
        set({ platform: p });
      },
      saveAuth: ({ accessToken, refreshToken, userId }) =>
        set({
          accessToken,
          refreshToken,
          userId,
          isLoggedIn: !!userId,
          isTokenValid: !!accessToken,
        }),

      saveTokens: ({ accessToken, refreshToken }) =>
        set((state) => ({
          accessToken,
          refreshToken,
          isLoggedIn: !!state.userId,
          isTokenValid: !!accessToken,
        })),

      setCurrentSlotId: (slotId) => set({ currentSlotId: slotId ? slotId.toString() : null }),

      clearAuth: () =>
        set({
          accessToken: null,
          refreshToken: null,
          userId: null,
          currentSlotId: null,
          isTokenValid: false,
          isLoggedIn: false,
        }),
    }),
    {
      name: "auth-store",
      storage: createJSONStorage(() => localStorage),
      partialize: (state) => {
        const { platform, ...rest } = state;
        return rest;
      },
    },
  ),
);

useAuthStore.getState().initializePlatform();
// I bunden af din authStore.ts
export const useIsSteam = () => useAuthStore((state) => state.platform === "STEAM");
export const useIsItch = () => useAuthStore((state) => state.platform === "ITCH");
export const useIsWeb = () => useAuthStore((state) => state.platform === "WEB");
