import { useState } from "react";
import { CredentialResponse, GoogleLogin } from "@react-oauth/google";
import { useLocation, useNavigate } from "react-router-dom";
import { useLinkGoogleAccount } from "../hooks/DatabaseSearch/useLinkGoogleAccount.tsx";
import { useHandleApiError } from "../hooks/Auth/useHandleApiError.tsx";
import LoginLayout from "../Layout/LoginLayout.tsx";
import { useSharedToasts } from "../hooks/Auth/useSharedToasts.tsx";
import RockyIdle from "./LandingPage/RockyIdle.tsx";
import Button from "../Components/UtilityComponents/Buttons/Button.tsx";
import { LOGIN_URL } from "../data/Constants.ts";
import { useAuthStore } from "../hooks/Auth/useAuthToken.ts";

export const LinkAccountPage = () => {
  const [isLinked, setIsLinked] = useState(false); // Track success state

  const location = useLocation();
  const searchParams = new URLSearchParams(location.search || location.hash.split("?")[1] || "");
  const code = searchParams.get("code");
  const navigate = useNavigate();
  const { clearAuth } = useAuthStore();

  const { handleApiError } = useHandleApiError();
  const { showSuccess } = useSharedToasts();
  const { mutateAsync: linkAccount } = useLinkGoogleAccount();

  const handleGoogleSignIn = async (credentialRes: CredentialResponse) => {
    const token = credentialRes.credential;
    if (!token) return handleApiError(new Error("Google login failed"), "Google login failed");

    try {
      await linkAccount({ linkCode: code!, googleToken: token });
      showSuccess("Google account linked successfully");
      clearAuth();
      setIsLinked(true); // Switch to the success view
    } catch (err) {
      handleApiError(err, "Failed to link Google account");
    }
  };

  return (
    <LoginLayout>
      <div className="flex relative flex-col items-center justify-center h-full text-center py-3">
        <RockyIdle isSmall={true} />

        <div className="flex-grow flex flex-col items-center justify-center rounded-lg p-6 w-full max-w-md relative">
          <h1 className="lg:text-5xl text-3xl text-center z-10 py-3 ">
            {isLinked ? "Account Linked!" : "Link Your Account"}
          </h1>

          <div className="flex flex-col items-center space-y-6 text-shadow-none">
            {!isLinked ? (
              <>
                <p className="text-gray-300">
                  Sign in with Google to connect your steam account to your google account.
                </p>
                <GoogleLogin
                  onSuccess={handleGoogleSignIn}
                  onError={() => handleApiError(new Error("Google login failed"), "Linking account")}
                />
              </>
            ) : (
              <div className="space-y-4 animate-in fade-in zoom-in duration-300">
                <p className="text-lg text-green-500 leading-tight">
                  You can now play on the web by logging in, or return to the Steam client to continue
                  playing.
                </p>

                <div className="flex flex-col gap-3 w-full">
                  <Button
                    text="Play on Web"
                    onClick={() => navigate(LOGIN_URL)}
                    className="w-full py-2"
                    isPrimary={true}
                  />
                  <p className="text-xs text-gray-400 italic">
                    Or you can now safely close this browser window and return to Steam.
                  </p>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </LoginLayout>
  );
};
