import { usePlayerStore } from "../usePlayerStore";
import { ItemDataByReference, playerItemsType } from "../../data/AllTypes/PlayerDataTypes";
import { DropTableDrops } from "../../data/AllTypes/DropTables.ts";
import { checkInventorySpace, removeContainersFromInv } from "../../Components/util/ResourceUtils.tsx";

export const checkInventorySpaceNow = (
  itemGain: ItemDataByReference[] | null | undefined,
  alwaysDrops?: ItemDataByReference[] | null,
  dropRolls?: number,
  dropTableDrops?: DropTableDrops[] | null,
  ignoreContainer?: boolean,
): boolean => {
  const state = usePlayerStore.getState();
  const items: playerItemsType = state.state.items;
  const playerItemsWithoutContainers = ignoreContainer ? removeContainersFromInv(items) : items;

  return checkInventorySpace(
    itemGain,
    playerItemsWithoutContainers,
    alwaysDrops,
    dropRolls,
    dropTableDrops,
    ignoreContainer,
  );
};

export const useCheckInventorySpace = (
  itemGain: ItemDataByReference[] | null | undefined,
  alwaysDrops?: ItemDataByReference[] | null,
  dropRolls?: number,
  dropTableDrops?: DropTableDrops[] | null,
  ignoreContainer?: boolean,
): boolean => {
  return usePlayerStore((state) => {
    const items: playerItemsType = state.state.items;
    return checkInventorySpace(itemGain, items, alwaysDrops, dropRolls, dropTableDrops, ignoreContainer);
  });
};
