import { SkillIdNumberDictionary } from "./SkillsSpecificTypes.ts";
import { ItemDataByReference } from "./PlayerDataTypes.ts";
import { SlayerCategoriesIds } from "../MonsterData/MonsterTypes.ts";
import { Difficulty } from "./DiaryTypes.ts";
import { QuestIds } from "../Quest/QuestIds.ts";

export type ValidSlayerMasterIds = SlayerMasterIds;
export enum SlayerMasterIds {
  Easy = 1001,
  Medium = 1002,
  Hard = 1003,
  Expert = 1004,
}

export type allSlayerMastersType = {
  [key in SlayerMasterIds]: slayerMasterInfoType;
};

export type slayerMasterInfoType = {
  id: SlayerMasterIds;
  name: string;
  difficulty: Difficulty;
  combatReq: number | null;
  questReq: QuestIds[] | null;
  skillReq: SkillIdNumberDictionary | null;
  img: string;
  icon: string;
  pointsReward: PointRewardMapType;
  monsters: slayerMonsterTypeDictionary;
};
export type PointRewardMapType = {
  base: number;
  per10: number;
  per50: number;
  per100: number;
  per250: number;
  per1000: number;
};

export type slayerMonsterTypeDictionary = Partial<Record<SlayerCategoriesIds, slayerMonsterType>>;

export type slayerMonsterType = {
  id: SlayerCategoriesIds;
  combatLevel?: number;
  questReq?: number[];
  skillReq?: SkillIdNumberDictionary;
  taskAmountMin: number;
  taskAmountMax: number;
  taskAmountMinExtended?: number;
  taskAmountMaxExtended?: number;
  taskWeight: number;
};

export type AllSlayerExtendsType = Record<SlayerCategoriesIds, SlayerExtendsType>;

export type SlayerExtendsType = {
  extendName: string;
  img: string;
  pointsCost: number;
  note: string;
};
export type ValidSlayerItemsToBuy = "";

export type SlayerBuyTypes = Partial<Record<ValidSlayerItemsToBuy, SlayerBuyType>>;

export type SlayerBuyType = {
  name: ValidSlayerItemsToBuy;
  img: string;
  itemCost: ItemDataByReference[] | null;
  itemGain: ItemDataByReference[];
  slayerPointsCost: number;
};

export type SlayerBlockList = SlayerSlot[];

export type SlayerSlot = {
  questPointsRequirements: number;
  description: string;
  diaryRequirement?: boolean;
};

export type SlayerExtendList = Partial<Record<SlayerCategoriesIds, SlayerExtend>>;

export type SlayerExtend = {
  isExtended: boolean;
  unlocked: boolean;
};
