import { create } from "zustand/react";
import { JSX } from "react";

type ToastType = {
  key: number;
  toastComponent: JSX.Element;
  active: boolean;
  alternate?: boolean;
};

type ToastStore = {
  toasts: ToastType[];
  alternateToasts: ToastType[];
  addToast: (toastComponent: JSX.Element, timeout: number, alternate?: boolean) => void;
  removeToast: (key: number) => void;
  deactivateToast: (key: number) => void;
  clearAllAlternateToasts: () => void;
};

export const useToastStore = create<ToastStore>((set) => ({
  toasts: [],
  alternateToasts: [],
  addToast: (toastComponent, timeout, alternate = false) => {
    const key = Math.random();
    const newToast = { key, toastComponent, active: true, alternate };

    set((state) => ({
      ...(alternate
        ? { alternateToasts: [...state.alternateToasts, newToast] }
        : { toasts: [...state.toasts, newToast] }),
    }));

    setTimeout(() => {
      set((state) => ({
        ...(alternate
          ? { alternateToasts: state.alternateToasts.filter((toast) => toast.key !== key) }
          : { toasts: state.toasts.filter((toast) => toast.key !== key) }),
      }));
    }, timeout);
  },
  removeToast: (key) => {
    set((state) => ({
      toasts: state.toasts.filter((toast) => toast.key !== key),
      alternateToasts: state.alternateToasts.filter((toast) => toast.key !== key),
    }));
  },
  deactivateToast: (key) => {
    set((state) => ({
      toasts: state.toasts.map((toast) => (toast.key === key ? { ...toast, active: false } : toast)),
    }));

    // remove after fade-out animation
    setTimeout(() => {
      set((state) => ({
        toasts: state.toasts.filter((toast) => toast.key !== key),
      }));
    }, 500); // match your CSS animation duration
  },

  clearAllAlternateToasts: () => {
    set((state) => ({
      toasts: state.toasts,
      alternateToasts: [],
    }));
  },
}));
