import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { SlayerBuyIds } from "../../../data/Slayer/SlayerBuys.ts";

type Action = {
  upgradeId: SlayerBuyIds;
};

export function buySlayerUpgrade(state: PlayerData, action: Action): PlayerData {
  const { upgradeId } = action;
  if (!state.slayerInfo) return state;

  const currentUnlocks = state.slayerInfo.slayerUnlocks ?? {};

  const newUnlocks = {
    ...currentUnlocks,
    [upgradeId]: true,
  };

  return {
    ...state,
    slayerInfo: {
      ...state.slayerInfo,
      slayerUnlocks: newUnlocks,
    },
  };
}
