import { unequipItem } from "../UnequipItem.ts";
import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { Slots } from "../../../data/AllTypes/EquipmentTypes.ts";

type Action = {
  slot: Slots;
  setIndex: number;
  amount: number;
};

export function useAmmunition(state: PlayerData, action: Action): PlayerData {
  const { slot, setIndex, amount } = action;

  // Get the specific set from equippedItems
  const equippedSet = state.equippedItems.sets[setIndex];
  const equippedItem = equippedSet[slot];

  // If no item is equipped or it doesn't have an amount, return the unchanged state
  if (!equippedItem || equippedItem?.amount === undefined) {
    return state;
  }

  const newAmount = equippedItem.amount - amount;

  if (newAmount <= 0) {
    // Unequip the item if the amount reaches 0
    return unequipItem(state, { slot, setIndex }); // Pass the setIndex to unequipItem
  } else {
    // Otherwise, update the item's amount
    return {
      ...state,
      equippedItems: {
        ...state.equippedItems,
        sets: {
          ...state.equippedItems.sets,
          [setIndex]: {
            ...equippedSet,
            [slot]: {
              ...equippedItem,
              amount: newAmount,
            },
          },
        },
      },
    };
  }
}
