import {
  AutoCombatIds,
  AutoCombatValues,
  ItemDataByReference,
  PlayerData,
} from "../../../data/AllTypes/PlayerDataTypes.ts";

export function useAutoCombatItem(
  state: PlayerData,
  action: { item: ItemDataByReference; autoCombatId: AutoCombatIds; trackCooldown?: boolean },
): PlayerData {
  const { item, autoCombatId, trackCooldown } = action;
  if (!item) return state;

  const existingSlot = state.autoCombat?.[autoCombatId] ?? {
    items: [],
    interval: 0,
    cooldownTimestamp: null,
  };

  const currentItems = [...existingSlot.items];
  const itemIndex = currentItems.findIndex((i) => i?.id === item.id);

  if (itemIndex !== -1 && currentItems[itemIndex] !== undefined) {
    if (currentItems[itemIndex]!.amount > item.amount) {
      currentItems[itemIndex] = {
        ...currentItems[itemIndex]!,
        amount: currentItems[itemIndex]!.amount - item.amount,
      };
    } else {
      currentItems.splice(itemIndex, 1);
    }
  }

  const updatedSlot: AutoCombatValues = {
    ...existingSlot,
    items: currentItems,
    cooldownTimestamp: trackCooldown ? Date.now() : existingSlot.cooldownTimestamp,
  };

  return {
    ...state,
    autoCombat: {
      ...state.autoCombat,
      [autoCombatId]: updatedSlot,
    },
  };
}
