import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { PrayerIds } from "../../../data/utilData/AllPrayers.ts";

type actionType = {
  prayerId: PrayerIds;
};

export const changePrayerReducer = (state: PlayerData, action: actionType): PlayerData => {
  const { prayerId } = action;
  const currentSetIndex = state.equippedItems.currentSet;
  const prevSet = state.equippedItems.sets[currentSetIndex];
  if (prevSet.currentPrayer === prayerId) return state;

  return {
    ...state,
    equippedItems: {
      ...state.equippedItems,
      sets: {
        ...state.equippedItems.sets,
        [currentSetIndex]: {
          ...prevSet,
          currentPrayer: prayerId,
        },
      },
    },
  };
};
