import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { TabNamesType } from "../../../data/skillsData/skillsChooser.ts";
import { ResourceIds } from "../../../data/skillsData/ResourceIds.ts";
import { SkillsId } from "../../../data/skillsData/SkillsEnum.ts";

export type StartProcessAction = {
  resourceId: ResourceIds;
  skillId: SkillsId;
  duration: number; // duration in milliseconds
  tabName?: TabNamesType;
};
export function startProcess(state: PlayerData, action: StartProcessAction): PlayerData {
  const { resourceId, skillId, tabName, duration } = action;

  return {
    ...state,
    currentProcess: {
      resourceId,
      skillId,
      tabName,
      duration,
      startTimestamp: Date.now(),
    },
  };
}
