import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";

// Reducer to change the uiVisibility map on PlayerData in an immutable way.
export const changeUIVisibility = (
  state: PlayerData,
  params: { key: string; isOpen: boolean },
): PlayerData => {
  const { key, isOpen } = params;

  // Use the existing uiVisibility map, or an empty object if it doesn't exist yet,
  // to ensure immutability and handle edge cases where the property might be missing.
  const existingUIVisibility = state.uiVisibility ?? {};

  // Check if the state is already the desired value to prevent unnecessary object copying
  if (existingUIVisibility[key] === isOpen) {
    return state;
  }

  return {
    ...state,
    // Immutable update of the uiVisibility map
    uiVisibility: {
      ...existingUIVisibility,
      [key]: isOpen,
    },
  };
};
