import { ItemDataByReference, PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { InventoryItemsData } from "../../../data/AllTypes/SkillsSpecificTypes.ts";

type Action = {
  item: ItemDataByReference;
};
export function useOneItem(state: PlayerData, action: Action): PlayerData {
  const itemToUse: ItemDataByReference = action.item;
  const inventory: InventoryItemsData = [...state.items.inventory];

  const existingItemIndexToUse = inventory.findIndex((inventoryItem) => inventoryItem?.id === itemToUse.id);

  if (existingItemIndexToUse !== -1) {
    const existingItem = inventory[existingItemIndexToUse];
    if (existingItem) {
      const updatedItem = {
        ...existingItem,
        amount: Math.max(existingItem.amount - 1, 0),
      };
      inventory[existingItemIndexToUse] = updatedItem.amount > 0 ? updatedItem : null;
    }
  }

  return {
    ...state,
    items: {
      ...state.items,
      inventory,
    },
  };
}
