import { placeItemInContainer } from "../../../Components/util/ExtraStorageUtils/ExtraStorageUtils.tsx";
import { ItemDataByReference, PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { ITEM_ON_GROUND_MAX } from "../../../data/Constants.ts";

export function getItemsOnGround(
  state: PlayerData,
  action: { items: ItemDataByReference[] | null },
): PlayerData {
  const { items } = action;
  if (!items || items.length === 0) return state;
  // Clone or initialize
  let updatedGroundItems = [...(state.itemsOnGround || [])];
  const nonNullItems = updatedGroundItems.filter((i) => i !== null);
  //If the amount of items on the ground is increased
  if (updatedGroundItems.length !== ITEM_ON_GROUND_MAX && nonNullItems.length <= ITEM_ON_GROUND_MAX) {
    updatedGroundItems = [...nonNullItems.slice(0, ITEM_ON_GROUND_MAX)];
    while (updatedGroundItems.length < ITEM_ON_GROUND_MAX) {
      updatedGroundItems.push(null);
    }
  }
  // Add new items to container
  for (const item of items) {
    const roundedAmount = Math.round(item.amount);
    if (roundedAmount > 0) {
      updatedGroundItems = placeItemInContainer(updatedGroundItems, item, roundedAmount);
    }
  }

  return {
    ...state,
    itemsOnGround: updatedGroundItems,
  };
}
