import { ItemData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import { createItemRef } from "../../../data/utilData/CreateItemRef.ts";
import { ItemIds } from "../../../data/ItemData/AllItemsIds.ts";
import ItemsGainDisplay from "../UIDisplays/ItemsGainDisplay.tsx";
import { useUIVisibility } from "../../../hooks/useUIVisibility.tsx";
import { SHOW_SELL_ALL_PRICE_TOOLTIP, SHOW_SELL_PRICE_ON_TOOLTIP } from "../../../data/Constants.ts";
import { getSellPrice } from "../CalculateSellPrice.tsx";

type ToolTipHeaderProps = {
  itemData: ItemData | null | undefined;
};
const ToolTipHeader = ({ itemData }: ToolTipHeaderProps) => {
  const [showSellPrice] = useUIVisibility(SHOW_SELL_PRICE_ON_TOOLTIP, true);
  const [showSellAllPrice] = useUIVisibility(SHOW_SELL_ALL_PRICE_TOOLTIP, true);
  if (!itemData) return null;
  const itemPrice = getSellPrice(itemData.id);
  const coin = createItemRef(ItemIds.COINS, itemPrice);
  const isSellable = itemData.sellable !== false && itemPrice > 0;
  const itemAmount = itemData.amount ?? 1;
  const totalSellPrice = itemPrice * itemAmount;
  const totalCoins = createItemRef(ItemIds.COINS, totalSellPrice);

  return (
    <div className="flex gap-1 justify-between relative">
      <span className={"leading-none"}>{itemData.name}</span>
      {showSellPrice && isSellable && (
        <ItemsGainDisplay
          itemsGain={[coin]}
          className={"!static -mt-[3px] -mb-[5px] h-fit !text-xs  rounded-md px-[1px] "}
        />
      )}
      {showSellAllPrice && isSellable && itemAmount > 1 && (
        <ItemsGainDisplay
          itemsGain={[totalCoins]}
          className={"!static -mt-[3px] -mb-[5px] h-fit !text-xs  rounded-md px-[1px] "}
        />
      )}
    </div>
  );
};

export default ToolTipHeader;
