import { SkillsId } from "../../../data/skillsData/SkillsEnum.ts";
import { SkillIdNumberDictionary } from "../../../data/AllTypes/SkillsSpecificTypes.ts";
import XpGainDisplay from "./XpGainDisplay.tsx";

type XpGainDisplayProps = {
  xp: SkillIdNumberDictionary | null | undefined;
};

const XpGainDisplays = ({ xp }: XpGainDisplayProps) => {
  return (
    <>
      {xp &&
        Object.entries(xp).map(([skillId, xpValue]) => {
          const skillIdTyped = Number(skillId) as SkillsId;
          return <XpGainDisplay key={skillId} skillId={skillIdTyped} xpValue={xpValue} />;
        })}
    </>
  );
};

export default XpGainDisplays;
