import { PlayerData, ValidQuestStatus } from "../../../data/AllTypes/PlayerDataTypes.ts";

type Action = {
  questId: number;
  questDuration: number;
};

export function startQuest(state: PlayerData, action: Action): PlayerData {
  const { questId, questDuration } = action;
  const currentQuestDurationInMs = questDuration * 1000;
  const now = Date.now();
  const finishTime = now + currentQuestDurationInMs;

  return {
    ...state,
    currentQuest: {
      questId: questId,
      questStartTime: now,
      questFinishTime: finishTime,
      questDuration: currentQuestDurationInMs,
    },
    completedQuests: {
      ...state.completedQuests,
      [questId]: ValidQuestStatus.InProgress,
    },
  };
}
