type AllAchievementDiariesType = Record<ValidDiaryIds, AchievementDiaryObject>;

export const getDiaryInfoFromId = (diaryId: ValidDiaryIds): AchievementDiaryObject => {
  return AllAchievementDiaries[diaryId];
};

