export const getSackItem = (itemGain?: ItemDataByReference[]) => {
  const sackItem = itemGain?.filter((item) => {
    const itemInfo = getItemInfoFromId(item.id);
    if (!itemInfo) return false;
    return itemInfo.type === ItemType.EXTRA_CONTAINER;
  });

  return sackItem;
};
