import { PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";

type RemoveShortcutAction = {
  shortcutId: string;
};

export function removeShortcut(state: PlayerData, action: RemoveShortcutAction): PlayerData {
  const shortcuts = state.shortcuts ?? [];
  const filteredShortcuts = shortcuts.filter((shortcut) => shortcut.id !== action.shortcutId);

  // Reorder shortcuts to maintain consecutive order numbers
  const reorderedShortcuts = filteredShortcuts.map((shortcut, index) => ({
    ...shortcut,
    order: index,
  }));

  return {
    ...state,
    shortcuts: reorderedShortcuts,
  };
}



