import { SkillIdNumberDictionary } from "../../../data/AllTypes/SkillsSpecificTypes.ts";
import { SkillsId } from "../../../data/skillsData/SkillsEnum.ts";
import { getSkillNameFromId } from "../../util/SkillsUtil/SkillUtil.tsx";

type SkillReqEquitmentToolTipProps = {
  skillsReq: SkillIdNumberDictionary | null;
};

const SkillReqEquitmentToolTip = ({ skillsReq }: SkillReqEquitmentToolTipProps) => {
  const skillsReqArray = skillsReq && Object.entries(skillsReq);
  const skillsReqLength = skillsReqArray?.length;
  if (!skillsReq || skillsReqLength === 0) return null;
  const skillsReqSplice = skillsReqArray?.slice(0, 2);
  return (
    <>
      {skillsReqSplice?.map(([skill, level], index) => {
        const skillId = Number(skill) as SkillsId;
        const skillName = getSkillNameFromId(skillId);

        return (
          <div key={index} className="flex">
            <p>{skillName}:</p>
            <p>{level}</p>
          </div>
        );
      })}
      {skillsReqLength && skillsReqLength > 2 && <p> + {skillsReqLength - 2} More...</p>}
    </>
  );
};

export default SkillReqEquitmentToolTip;
