import { ItemDataByReference } from "../../../data/AllTypes/PlayerDataTypes.ts";
import {
  getAndMergeItemData,
  getEquipmentInfo,
  getEquipmentStats,
} from "../../../data/ItemData/AllItemsData.ts";
import EquipmentLevelIcon from "../../LevelBoostsComponents/EquipmentLevelIcon.tsx";
import { bonusCategories } from "../../../data/utilData/GearAndDmgCalculations/BonusCatagories.ts";
import SkillReqEquipmentToolTip from "./SkillReqEquitmentToolTip.tsx";
import QuestReqEquipmentToolTip from "./QuestReqEquipmentToolTip.tsx";
import AmmoDescriptionToolTip from "./AmmoDescriptionToolTip.tsx";
import { ProcessCompletedAttributes } from "../../../data/ProcessLevelData/ProcessLevelData.tsx";
import ToolTipHeader from "./ToolTipHeader.tsx";
import AttackSpeedTooltip from "./AttackSpeedTooltip.tsx";

export const getDropShadowFilter = (color: string | undefined, blurRadius = 10) =>
  `drop-shadow(0 0 ${blurRadius}px ${color ?? "#43341D"})`;

export const shouldShowPercentage = (category: string) => {
  return [
    "Slayer",
    "Forest",
    "Sea",
    "Mine",
    "Temple",
    "Field",
    "Market",
    "seaDmg",
    "forestDmg",
    "mineDmg",
    "templeDmg",
    "fieldDmg",
    "slayerDmg",
    "marketDmg",
    "slayer",
  ].includes(category);
};
type ToolTipEquipmentProps = {
  item: ItemDataByReference;
  combatPoints: number;
  level: ProcessCompletedAttributes | null;
};

const ToolTipEquipmentStatShowcase = ({ item, combatPoints, level }: ToolTipEquipmentProps) => {
  const equipmentInfo = getEquipmentInfo(item);
  const itemData = getAndMergeItemData(item);

  const equipmentStats = getEquipmentStats(item, combatPoints);
  if (!equipmentInfo || !equipmentStats) return null;

  const displayStat = (value: number | undefined, category: string) => {
    if (!value) return null;
    const shouldShowPercent = shouldShowPercentage(category);
    const deltaRounded = value % 1 !== 0 ? (shouldShowPercent ? value.toFixed(2) : value.toFixed(0)) : value;
    return (
      <div className="flex" key={category}>
        <p>{category}:</p>
        <p className={value > 0 ? "text-green-500" : value < 0 ? "text-red-500" : ""}>
          {value > 0 ? "+" : ""}
          {deltaRounded}
          {shouldShowPercent && "%"}
        </p>
      </div>
    );
  };

  return (
    <div key={item.id} className={`text-[11.5px]`} style={{ filter: getDropShadowFilter(level?.color) }}>
      <div className="absolute -right-[8px] -top-[8px] ">
        {level && <EquipmentLevelIcon level={level} small />}
      </div>
      <ToolTipHeader itemData={itemData} />
      {Object.entries(bonusCategories).map(([categoryName, categoryStats]) => {
        const shouldDisplay = categoryStats.some(({ stat }) => (equipmentStats[stat] ?? 0) > 0);
        if (!shouldDisplay) return null;
        return (
          <div key={categoryName}>
            <h2 className="text-orangeColorSecondary">{categoryName}:</h2>
            {categoryStats.map(({ label, stat }) => displayStat(equipmentStats[stat], label))}
          </div>
        );
      })}
      <AttackSpeedTooltip attackSpeed={equipmentInfo.weaponStats?.baseAttackSpeed} />
      {equipmentInfo.weaponStats?.twoHanded && <h2 className="text-blue-500 ">*Two Handed</h2>}
      {Object.entries(equipmentInfo.skillReq ?? {}).length > 0 && (
        <h2 className="text-red-500 ">Level Req:</h2>
      )}
      <SkillReqEquipmentToolTip skillsReq={equipmentInfo.skillReq} />
      <QuestReqEquipmentToolTip questReq={equipmentInfo.questReq} />
      <AmmoDescriptionToolTip ammunitionAllowed={equipmentInfo?.weaponStats?.ammunitionAllowed} />
    </div>
  );
};

export default ToolTipEquipmentStatShowcase;
