import ItemAmountDisplay from "../../util/Formatter/ItemAmountDisplay.tsx";
import { ItemDataByReference } from "../../../data/AllTypes/PlayerDataTypes.ts";
import ImgGetImageSourceWithSkeletonLoading from "./ImgGetImageSourceWithSkeletonLoading.tsx";
import { memo } from "react";
import { getImageSource } from "../../../data/utilData/ImagesUtils/GetImageUtil.ts";
import { getItemInfoFromId } from "../../../data/ItemData/AllItemsData.ts";
import { getItemsSmallText } from "../../util/ExtraStorageUtils/ItemsUtils.tsx";
import ItemDbLinkButton from "./ItemDbLinkButton.tsx";

type ItemWithAmountProps = {
  item: ItemDataByReference;
  multiplier?: number;
  clickable?: boolean;
  withoutSkeleton?: boolean;
  itemSmallText?: number | string | null | undefined;
  className?: string;
  removePaddingX?: boolean;
  isLowOpacity?: boolean;
  imageClassName?: string | 0;
  showHelpLink?: boolean;
};
export const ItemWithAmount = memo(
  ({
    item,
    multiplier,
    clickable,
    withoutSkeleton,
    itemSmallText,
    className,
    removePaddingX,
    isLowOpacity = false,
    imageClassName,
    showHelpLink = true,
  }: ItemWithAmountProps) => {
    let amount = Math.round(item.amount);
    if (multiplier) {
      amount *= multiplier;
    }
    const itemInfo = getItemInfoFromId(item.id);
    const imgSrc = getImageSource(item, amount);
    const paddingX = removePaddingX ? "" : "px-2";
    const scale = removePaddingX ? "w-[32px] h-[35px]" : "w-[48px] h-[37px]";
    // const scale = removePaddingX ? "w-[32px] h-[35px]" : "w-[47px] h-[36px]";
    const smallText = itemSmallText ? itemSmallText : getItemsSmallText(item);

    return (
      <div
        className={`relative group/itemRef transition duration-150 flex items-center justify-center 
        ${scale} 
        ${className}
        ${isLowOpacity && "bg-red-600/20 rounded"}
         ${clickable ? "active:opacity-60 " : ""}
    `}
      >
        {showHelpLink && <ItemDbLinkButton itemId={item.id} />}
        <div className={`${isLowOpacity && "!brightness-[30%]"} ${imageClassName} `}>
          {!withoutSkeleton ? (
            <ImgGetImageSourceWithSkeletonLoading
              item={item}
              amount={amount}
              imageClassName={"aspect-auto w-fit h-fit max-w-6 max-h-7 z-0 object-contain"}
              containerClassName={`relative group max-w-6 max-h-7 w-full h-full grid place-items-center ${paddingX}`}
            />
          ) : (
            <img src={imgSrc} alt={itemInfo?.name} />
          )}
        </div>
        <div className={` absolute bottom-0 right-0 text-xs text-orangeColor  leading-none ${paddingX}`}>
          {smallText}
        </div>
        <div
          className={`absolute top-0 left-0 text-xs leading-none ${isLowOpacity && "brightness-[60%]"}  ${paddingX}`}
        >
          {amount >= 2 && <ItemAmountDisplay amount={amount} />}
        </div>
      </div>
    );
  },
);
