import { ItemDataByReference, PlayerData } from "../../data/AllTypes/PlayerDataTypes.ts";
import { InventoryItemsData } from "../../data/AllTypes/SkillsSpecificTypes.ts";

type withdrawFromBankAction = {
  item: ItemDataByReference;
};
export function withdrawFromBank(state: PlayerData, action: withdrawFromBankAction): PlayerData {
  const { item } = action;

  // Return early if the bank is null or the item is null or has no name
  if (state.items.bank === null || item === null || item.id === null) return state;

  const updatedBank: InventoryItemsData = [...state.items.bank];

  // Find the index of the item in the bank
  const existingItemIndex = updatedBank.findIndex((bankItem) => bankItem && bankItem.id === item.id);

  if (existingItemIndex !== -1) {
    const existingItem = updatedBank[existingItemIndex];
    if (!existingItem) return state; // Return early if the existing item is somehow null

    // Calculate the withdrawal amount, ensuring it doesn't exceed the existing amount

    const withdrawalAmount = Math.min(existingItem.amount, item.amount);

    // Update the amount of the existing item
    updatedBank[existingItemIndex] = {
      ...existingItem,
      amount: existingItem.amount - withdrawalAmount,
    };

    // If all the item is withdrawn, remove it from the bank
    if (existingItem.amount === withdrawalAmount) {
      updatedBank[existingItemIndex] = null;
    }

    if (isNaN(item.amount) || !item.amount) {
      updatedBank[existingItemIndex] = null;
    }
  }

  return {
    ...state,
    items: {
      ...state.items,
      bank: updatedBank,
    },
  };
}
