import { useToastStore } from "../../Context/ToastStore.ts";
import ServerErrorToaster from "../../Components/UtilityComponents/Toasts/ServerErrorToaster.tsx";
import ServerSuccessToaster from "../../Components/UtilityComponents/Toasts/ServerSuccessToaster.tsx";

export const useSharedToasts = () => {
  const addToast = useToastStore((state) => state.addToast);

  const showError = (message: string, duration = 5000) => {
    addToast(<ServerErrorToaster error={message} />, duration);
  };

  const showSuccess = (message: string, duration = 5000) => {
    addToast(<ServerSuccessToaster message={message} />, duration);
  };

  return { showError, showSuccess };
};
