import React, { JSX } from "react";
import ToastsDisplay from "./ToastDisplay";
import { useToastStore } from "./ToastStore";

type ToastManagerProviderProps = {
  children: React.ReactNode;
};
export type AddToastFunctionType = (toastComponent: JSX.Element, timeout: number) => void;

const ToastManagerProvider = ({ children }: ToastManagerProviderProps) => {
  const toasts = useToastStore((state) => state.toasts);
  const handleToastClick = useToastStore((state) => state.deactivateToast);

  return (
    <>
      {children}
      <ToastsDisplay toasts={toasts} handleToastClick={handleToastClick} />
    </>
  );
};

export default ToastManagerProvider;
