import { ItemDataByReference } from "../../../data/AllTypes/PlayerDataTypes.ts";
import IconComponent from "../../AccountOverview/IconComponent.tsx";
import TooltipWrapper from "../ToolTip/TooltipWrapper.tsx";
import ItemWithToolTip from "../../Items/ItemWithToolTip.tsx";
import { getShiningClassBasedOnProbability } from "../../util/VisualUtils.tsx";

type ToasterItemGainAndCostProps = {
  itemGain: ItemDataByReference[] | null | undefined;
  itemCost: ItemDataByReference[] | null | [] | undefined;
  itemsToGet?: ItemDataByReference[] | null | undefined;
  hideTooltip?: boolean;
  className?: string;
  shiningDrops?: boolean;
};
const ToasterItemGainAndCost = ({
  itemGain,
  itemCost,
  itemsToGet,
  hideTooltip,
  className = "",
  shiningDrops = false,
}: ToasterItemGainAndCostProps) => {
  return (
    <div className={`flex items-center gap-x-2 text-lg  ${className}`}>
      {itemGain && itemGain[0] && itemGain[0].amount >= 1 && (
        <div className="flex  gap-1 items-center">
          <p className="inline-block text-xl text-green-500">+</p>
          <div
            className={`flex flex-wrap items-center gap-0.5  ${itemGain.length > 6 && "!grid grid-cols-5"}`}
          >
            {itemGain.map((item, index) => {
              const itemsToGetIds = itemsToGet?.map((item) => item.id);
              const probability = item.probability ? item.probability : 1;
              const shiningClass = shiningDrops ? getShiningClassBasedOnProbability(probability ?? 1) : "";
              return (
                <div key={index} className="relative">
                  {itemsToGet && !itemsToGetIds?.includes(item.id) && (
                    <TooltipWrapper
                      content={"Not enough inventory space"}
                      className="top-0 right-0 w-full h-full grid place-items-center !absolute z-10"
                    >
                      <IconComponent iconName={"PiWarningCircleFill"} size={20} iconColor={"red"} />
                    </TooltipWrapper>
                  )}
                  <ItemWithToolTip
                    item={item}
                    removePaddingX={true}
                    hideTooltip={hideTooltip}
                    showHelpLink={!hideTooltip}
                    imageClassName={shiningClass}
                  />
                </div>
              );
            })}
          </div>
        </div>
      )}
      {itemCost && itemCost[0] && itemCost[0].amount >= 1 && (
        <div className="text-red-500 flex gap-1 justify-center">
          <p className="inline-block self-center text-xl">-</p>
          <div className="flex items-center">
            {itemCost.map((item, index) => (
              <ItemWithToolTip item={item} key={index} removePaddingX={true} hideTooltip={hideTooltip} />
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default ToasterItemGainAndCost;
