import { MouseEvent } from "react";
import { DragEndEvent } from "@dnd-kit/core";
import FloatingToast from "./FloatingToast.tsx";

type ErrorToasterProps = {
  message: string;
  mouseEvent: MouseEvent | undefined | DragEndEvent;
};

export default function ErrorToasterWithEvent({ message, mouseEvent }: ErrorToasterProps) {
  return (
    <div className="toaster text-red-500 ">
      <FloatingToast mouseEvent={mouseEvent}>{message}</FloatingToast>
    </div>
  );
}
