import { InventoryStates, ItemDataByReference, PlayerData } from "../../../data/AllTypes/PlayerDataTypes.ts";
import {
  CONTAINERS_CONFIG,
  hasExtraStorageInInventory,
} from "../../../Components/util/ExtraStorageUtils/ExtraStorageUtils.tsx";
import { InventoryItemsData } from "../../../data/AllTypes/SkillsSpecificTypes.ts";

interface Action {
  items: ItemDataByReference[];
  inventoryState?: InventoryStates;
}

export function useItems(state: PlayerData, action: Action): PlayerData {
  const { inventoryState } = action;
  const itemsToUse = action.items ?? [];

  const newItems = state.items;

  for (const itemToUse of itemsToUse) {
    if (inventoryState) {
      const config = CONTAINERS_CONFIG[inventoryState];
      if (!config) continue;
      const playerContainer = newItems[config.id];
      if (!playerContainer) continue;
      const leftoverAmount = removeFromContainerInPortions(
        playerContainer,
        itemToUse.id,
        itemToUse.amount,
        (updated) => {
          newItems[config.id] = updated;
        },
      );
      if (leftoverAmount > 0)
        console.warn("error removing item:", itemToUse.id, "leftover amount:", leftoverAmount);
    } else {
      // No specific inventoryState: remove in default priority order
      let leftoverAmount = itemToUse.amount;
      // Loop through storage containers in config
      for (const config of Object.values(CONTAINERS_CONFIG)) {
        const isUnlocked = hasExtraStorageInInventory(newItems.inventory!, config?.unlockItemId);
        if (!isUnlocked) continue;
        if (leftoverAmount <= 0) break;
        const container = newItems[config.id];
        if (!container) continue;
        leftoverAmount = removeFromContainerInPortions(container, itemToUse.id, leftoverAmount, (updated) => {
          newItems[config.id] = updated;
        });
      }

      if (leftoverAmount > 0) {
        console.warn(
          `Tried to use ${itemToUse.amount} of "${itemToUse.id}", but only found ${
            itemToUse.amount - leftoverAmount
          } total.`,
        );
      }
    }
  }

  return {
    ...state,
    items: {
      ...newItems,
    },
  };
}

function removeFromContainerInPortions(
  container: InventoryItemsData,
  itemId: number,
  amountToRemove: number,
  onUpdate: (updatedContainer: InventoryItemsData) => void,
): number {
  const updated = [...container];
  const index = updated.findIndex((slot) => slot?.id === itemId);

  if (index === -1) {
    onUpdate(updated);
    return amountToRemove; // Item not found, nothing removed
  }

  const slot = updated[index];
  if (!slot) {
    onUpdate(updated);
    return amountToRemove; // Shouldn't happen, but defensive
  }

  if (slot.amount <= amountToRemove) {
    updated[index] = null; // Remove the item completely
    amountToRemove -= slot.amount;
  } else {
    updated[index] = { ...slot, amount: slot.amount - amountToRemove };
    amountToRemove = 0;
  }

  onUpdate(updated);
  return amountToRemove;
}
